import React, { useState, useRef } from 'react';
import { generateSpeech, transcribeAudio } from '../services/gemini';
import { Loader2, Mic, Volume2, FileAudio, PlayCircle, Upload, FileText, X, Music, Download, Check, Sparkles, AudioLines } from 'lucide-react';

const VOICES = [
  { id: 'Kore', label: 'Kore', desc: 'Warm & Professional (Female)' },
  { id: 'Puck', label: 'Puck', desc: 'Energetic & Youthful (Male)' },
  { id: 'Charon', label: 'Charon', desc: 'Deep & Authoritative (Male)' },
  { id: 'Fenrir', label: 'Fenrir', desc: 'Steady & Neutral (Male)' },
  { id: 'Zephyr', label: 'Zephyr', desc: 'Friendly & Conversational (Female)' }
];

export const AudioStudio: React.FC = () => {
  const [tab, setTab] = useState<'tts' | 'stt'>('tts');
  const [text, setText] = useState('');
  const [voice, setVoice] = useState('Kore');
  const [audioResult, setAudioResult] = useState<'playing' | 'ready' | null>(null);
  const [transcription, setTranscription] = useState('');
  const [loading, setLoading] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [downloadBlob, setDownloadBlob] = useState<Blob | null>(null);

  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // WAV encoding helper
  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i));
      }
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      let s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return new Blob([view], { type: 'audio/wav' });
  };

  // TTS Handler
  const handleTTS = async () => {
    if (!text) return;
    setLoading(true);
    setDownloadBlob(null);
    try {
      const base64 = await generateSpeech(text, voice);
      if (base64) {
        await playAndPrepareAudio(base64);
      }
    } catch (e) {
      console.error(e);
      alert("TTS generation failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const playAndPrepareAudio = async (base64: string) => {
    try {
      const binaryString = atob(base64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

      const audioContext = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);

      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }

      // Create download blob
      const wavBlob = encodeWAV(channelData, 24000);
      setDownloadBlob(wavBlob);

      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
      setAudioResult("playing"); 
      setTimeout(() => setAudioResult("ready"), buffer.duration * 1000);

    } catch (e) {
      console.error("Audio decode error", e);
    }
  };

  const handleDownload = () => {
    if (!downloadBlob) return;
    const url = URL.createObjectURL(downloadBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `narration_${voice}_${Date.now()}.wav`;
    a.click();
    URL.revokeObjectURL(url);
  };

  // STT Handlers
  const startRecording = async () => {
    setTranscription('');
    setUploadedFile(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
        setLoading(true);
        try {
          const text = await transcribeAudio(audioBlob);
          setTranscription(text);
        } catch (e) {
          console.error(e);
        } finally {
          setLoading(false);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Microphone access denied", err);
      alert("Microphone access is required for recording.");
    }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setUploadedFile(file);
      setTranscription('');
    }
  };

  const handleTranscribeFile = async () => {
    if (!uploadedFile) return;
    setLoading(true);
    try {
      const text = await transcribeAudio(uploadedFile);
      setTranscription(text);
    } catch (e) {
      console.error(e);
      alert("Failed to transcribe file.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-12 animate-fade-in pb-20">
      <div className="text-center space-y-4 py-8">
        <div className="inline-flex items-center justify-center p-4 rounded-[2rem] bg-purple-500/10 text-purple-500 mb-2 border border-purple-500/20 shadow-2xl">
           <Volume2 size={40} strokeWidth={2.5} />
        </div>
        <h2 className="text-5xl font-black bg-gradient-to-br from-white to-zinc-600 bg-clip-text text-transparent tracking-tighter">
          Acoustic Intelligence
        </h2>
        <p className="text-zinc-400 text-lg font-medium max-w-2xl mx-auto">
          Deploy neural voice synthesis or convert complex audio streams into accurate narrative transcripts.
        </p>

        <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800 w-fit mx-auto mt-8">
          <button 
            onClick={() => { setTab('tts'); setTranscription(''); }}
            className={`px-10 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all active-press ${tab === 'tts' ? 'bg-zinc-800 text-white shadow-xl' : 'text-zinc-500 hover:text-white'}`}
          >
            Voice Lab
          </button>
          <button 
            onClick={() => { setTab('stt'); setAudioResult(null); }}
            className={`px-10 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all active-press ${tab === 'stt' ? 'bg-zinc-800 text-white shadow-xl' : 'text-zinc-500 hover:text-white'}`}
          >
            Transcription
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* Main Workspace */}
        <div className="lg:col-span-8 bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
          {tab === 'tts' ? (
            <div className="space-y-8 animate-fade-in">
               <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
                       <AudioLines size={24} />
                    </div>
                    <h3 className="text-xl font-black text-white uppercase tracking-tighter">Synthesizer Manifest</h3>
                  </div>
                  {downloadBlob && (
                    <button 
