      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
        {/* Left: Input & Results */}
        <div className="lg:col-span-2 space-y-8">
          <div className="space-y-6">
            <form onSubmit={handleSubmit} className="relative group">
              <div className="absolute inset-0 bg-red-600 blur-2xl opacity-0 group-focus-within:opacity-10 transition-opacity"></div>
              <div className="relative flex gap-3 p-2 bg-zinc-900 border border-zinc-800 rounded-[2.5rem] shadow-2xl focus-within:border-red-500/50 transition-all">
                <div className="flex items-center pl-4 text-zinc-600">
                   <Search size={20} />
                </div>
                <input
                  type="text"
                  value={niche}
                  onChange={(e) => setNiche(e.target.value)}
                  placeholder="Enter your niche or target topic..."
                  className="flex-1 bg-transparent border-none py-4 outline-none text-white font-medium placeholder:text-zinc-700"
                />
                <button
