import { GoogleGenAI, Type, Modality } from "@google/genai";
import { MODEL_NAMES, SYSTEM_INSTRUCTIONS } from '../constants';
import { VideoIdea, SeoResult, SocialPost, ThumbnailRating, CompetitorAnalysis, VideoAudit, RepurposedContent, KeywordMetrics, TrendResult, TitlePrediction, OutreachResult, CustomerPersona, NicheGap, TrendForecast } from '../types';

const getAiClient = (forceNew: boolean = false) => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

// --- Shorts Architect ---
export const generateShortsScript = async (
  topic: string, 
  style: string, 
  pacing: 'Fast' | 'Standard',
  onChunk: (text: string) => void
) => {
  const ai = getAiClient();
  const prompt = `Write a high-retention YouTube Shorts script for the topic: "${topic}". 

  STYLE: ${style}.
  PACING: ${pacing}.

  MANDATORY FORMATTING:
  1. Spoken lines MUST be bold.
  2. Visual cues MUST be in [brackets].
  3. Ensure it is exactly between 45 and 58 seconds (approx 135-150 words).
  4. Follow the Hook -> Value -> Subscribe CTA -> Loop structure.
  5. MANDATORY: You MUST include a punchy verbal call to action to subscribe to the channel before the final transition.`;

  const result = await ai.models.generateContentStream({
    model: MODEL_NAMES.TEXT_FAST, 
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.SHORTS
    }
  });

  for await (const chunk of result) {
    if (chunk.text) onChunk(chunk.text);
  }
};

// --- Title Logic ---
export const generateViralTitles = async (context: string, preferredTriggers: string[] = []): Promise<TitlePrediction[]> => {
  const ai = getAiClient();
  const triggersText = preferredTriggers.length > 0 
    ? `HEAVILY PRIORITIZE these triggers: ${preferredTriggers.join(', ')}.`
    : "Use a balanced mix of psychological triggers.";

  const prompt = `Generate 10 viral YouTube title variations for: "${context}". 
  ${triggersText}
  For each title, predict a Click-Through Rate (CTR) score (0-100) based on power word density and structure.`;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_FAST,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.TITLE_GENERATOR,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            type: { type: Type.STRING },
            predictedCtr: { type: Type.NUMBER },
            logic: { type: Type.STRING }
          },
          required: ["title", "type", "predictedCtr", "logic"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) return [];
  try {
    const res = JSON.parse(text) as TitlePrediction[];
    return Array.isArray(res) ? res : [];
  } catch (e) {
    console.error(e);
    return [];
  }
};

