};

import React, { useState, useRef, useEffect } from 'react';
import { generateVideo } from '../services/gemini';
import { 
  Loader2, 
  Video as VideoIcon, 
  Upload, 
  PlayCircle, 
  Download, 
  Scissors, 
  Plus, 
  Trash2, 
  PauseCircle, 
  SkipBack, 
  SkipForward, 
  Film, 
  Zap, 
  Check,
  AudioLines,
  Sparkles,
  Key,
  RotateCcw,
  Gauge,
  Clock,
  Camera,
  Sun,
  Wind,
  ChevronRight,
  Info,
  Layers,
  Wand2,
  ArrowRight
} from 'lucide-react';

const LOADING_MESSAGES = [
  "Initializing Veo creative engine...",
  "Analyzing visual descriptors and style cues...",
  "Synthesizing high-fidelity frames...",
  "Applying temporal coherence and physics...",
  "Processing optical flow algorithms...",
  "Finalizing cinematic render...",
  "Optimizing for your target aspect ratio...",
  "Hang tight, artistic perfection takes a moment..."
];

const CAMERA_MOTIONS = [
  'Static (Stationary)', 'Slow Pan Right', 'Slow Pan Left', 
  'Cinematic Tilt Up', 'Dramatic Tilt Down', 'Dolly Zoom In', 
  'Slow Zoom Out', 'Tracking Shot', 'Handheld (Organic)', 'Crane Shot (High)'
];

const VIDEO_STYLES = [
  'Cinematic Movie', '3D Octane Render', 'Drone Aerial View', 
  'GoPro POV Wide', '16mm Vintage Film', 'Cyberpunk Neon', 
  'Hyper-realistic RAW', 'Dreamy Ethereal'
];

const VIDEO_LIGHTING = [
  'Golden Hour (Low Sun)', 'Dramatic Rim Lighting', 'Soft Studio 3-Point', 
  'Volumetric Foggy Rays', 'Neon Night Ambient', 'Subsurface Scattering'
];

const SPEED_OPTIONS = [0.5, 0.75, 1, 1.25, 1.5, 2];

interface TimelineClip {
  id: string;
  type: 'video' | 'audio';
  url: string;
  name: string;
  duration: number;
  trimStart: number;
  trimEnd: number;
  timelineOffset: number;
  playbackSpeed: number;
}

export const VideoStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'create' | 'edit'>('create');
  const [hasApiKey, setHasApiKey] = useState(true);

  // --- GENERATOR STATE ---
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('1080p');
  const [startImage, setStartImage] = useState<string | null>(null);

  // Modifiers
  const [cameraMotion, setCameraMotion] = useState('');
  const [videoStyle, setVideoStyle] = useState('Cinematic Movie');
  const [lighting, setLighting] = useState('');

  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const [justAdded, setJustAdded] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);

  const previewVideoRef = useRef<HTMLVideoElement>(null);
  const editorFileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
    };
    checkKey();
  }, []);

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 6000);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Assume success as per guidelines to avoid race condition
      setHasApiKey(true);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey && window.aistudio) {
       await handleOpenKeyPicker();
       // Proceed immediately
    }

    setIsGenerating(true);
    setGeneratedVideoUrl(null);

    // Construct technical prompt
    const technicalPrompt = `A ${videoStyle.toLowerCase()} of ${prompt}. ${cameraMotion ? `Camera motion: ${cameraMotion}.` : ''} ${lighting ? `Lighting: ${lighting}.` : ''} High fidelity, detailed textures, consistent physics, cinematic quality.`;

    try {
      const url = await generateVideo(technicalPrompt, aspectRatio, startImage || undefined, resolution);
      if (url) {
        setGeneratedVideoUrl(url);
      }
    } catch (error: any) {
      console.error(error);
      if (error.message?.includes("Requested entity was not found")) {
         setHasApiKey(false);
         alert("Project mismatch or missing API key. Please select your paid GCP API key again.");
      } else {
         alert("Video generation failed. Please try a more descriptive prompt.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const sendToEditor = () => {
    if (generatedVideoUrl) {
      addVideoToTimeline(generatedVideoUrl, `AI Clip ${timeline.length + 1}`);
      setJustAdded(true);
      setTimeout(() => {
        setJustAdded(false);
        setActiveTab('edit');
      }, 800);
    }
  };

  const addVideoToTimeline = (url: string, name: string) => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const duration = tempVid.duration || 10;
      setTimeline(prev => {
        const nextOffset = prev.reduce((max, clip) => {
          const end = clip.timelineOffset + (clip.trimEnd - clip.trimStart) / clip.playbackSpeed;
          return Math.max(max, end);
        }, 0);

        const newClip: TimelineClip = {
          id: Math.random().toString(36).substring(2, 11),
          type: 'video',
          url,
          name,
          duration,
          trimStart: 0,
          trimEnd: duration,
          timelineOffset: nextOffset,
          playbackSpeed: 1
        };
        const newTimeline = [...prev, newClip];
        recalculateTotalDuration(newTimeline);
        return newTimeline;
      });
    };
  };

  const recalculateTotalDuration = (clips: TimelineClip[]) => {
    let max = 0;
    clips.forEach(c => {
      const end = c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed;
      if (end > max) max = end;
    });
    setTotalDuration(max);
  };

  const togglePlay = () => setIsPlaying(!isPlaying);
  const seek = (time: number) => setCurrentTime(Math.max(0, Math.min(time, totalDuration)));

  useEffect(() => {
    let animationFrameId: number;
    if (isPlaying) {
      const startTime = performance.now();
      const initialCurrentTime = currentTime;
      const animate = (now: number) => {
        const delta = (now - startTime) / 1000;
        const next = initialCurrentTime + delta;
        if (next >= totalDuration) {
          setIsPlaying(false);
          setCurrentTime(totalDuration);
        } else {
          setCurrentTime(next);
          animationFrameId = requestAnimationFrame(animate);
        }
      };
      animationFrameId = requestAnimationFrame(animate);
    }
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  useEffect(() => {
    if (previewVideoRef.current) {
       const activeClip = timeline.find(c => 
         c.type === 'video' && 
         currentTime >= c.timelineOffset && 
         currentTime <= (c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed)
       );
       if (activeClip) {
          if (previewVideoRef.current.src !== activeClip.url) {
            previewVideoRef.current.src = activeClip.url;
          }
          previewVideoRef.current.playbackRate = activeClip.playbackSpeed;
          const internalTime = activeClip.trimStart + (currentTime - activeClip.timelineOffset) * activeClip.playbackSpeed;
          if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.2) {
             previewVideoRef.current.currentTime = internalTime;
          }
       }
    }
  }, [currentTime, timeline]);

  const ModifierGroup = ({ label, icon: Icon, options, current, setter, color }: any) => (
    <div className="space-y-3">
      <label className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${color}`}>
         <Icon size={12} /> {label}
      </label>
      <div className="flex flex-wrap gap-2">
         {options.map((opt: string) => (
           <button
             key={opt}
             type="button"
             onClick={() => setter(current === opt ? '' : opt)}
             className={`px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase transition-all border ${current === opt ? 'bg-zinc-100 border-white text-black shadow-lg scale-105' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
           >
             {opt}
           </button>
         ))}
      </div>
    </div>
  );

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6 gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
             <VideoIcon className="text-red-500" /> Veo Visual Engine
          </h2>
          <p className="text-zinc-400 text-sm font-medium">Next-Generation Cinematic Synthesis</p>
        </div>

        <div className="flex gap-4 items-center">
          {!hasApiKey && (
             <button 
               onClick={handleOpenKeyPicker}
               className="flex items-center gap-2 bg-yellow-500/10 border border-yellow-500/30 text-yellow-500 px-5 py-2 rounded-xl text-xs font-black uppercase tracking-widest animate-pulse transition-all hover:bg-yellow-500/20"
             >
                <Key size={14} /> Connect Paid API Key
             </button>
          )}
          <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800">
            <button 
              onClick={() => setActiveTab('create')}
              className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'create' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
            >
              Creative Studio
            </button>
            <button 
              onClick={() => setActiveTab('edit')}
              className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'edit' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
            >
              Timeline Sequencer
            </button>
          </div>
        </div>
      </header>

      {activeTab === 'create' ? (
        <div className="flex-1 flex flex-col md:flex-row gap-8 min-h-0">
          {/* LEFT: CONFIG PANEL */}
          <div className="w-full md:w-[450px] flex flex-col gap-6 overflow-y-auto pr-3 custom-scrollbar pb-10">
            <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 space-y-8 shadow-2xl relative overflow-hidden">
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Input Framework</label>
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full h-44 border-2 border-dashed border-zinc-800 hover:border-red-500/50 rounded-3xl flex flex-col items-center justify-center cursor-pointer bg-zinc-950/50 transition-all relative group overflow-hidden"
                  >
                    {startImage ? (
                      <img src={startImage} alt="Reference" className="h-full w-full object-cover group-hover:scale-105 transition-transform" />
                    ) : (
                      <div className="text-zinc-600 flex flex-col items-center gap-3">
                        <Upload size={32} />
                        <span className="text-[10px] font-black uppercase tracking-widest">Base Frame (Optional)</span>
                      </div>
                    )}
                  </div>
                  <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
               </div>

               <div className="space-y-4">
                 <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Action Descriptor</label>
                 <textarea
                   value={prompt}
                   onChange={(e) => setPrompt(e.target.value)}
                   placeholder="Describe movement, subject, and environment (e.g. A robotic hummingbird sipping from a liquid crystal flower)..."
                   className="w-full h-36 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 focus:ring-2 focus:ring-red-500/50 outline-none transition-all resize-none text-white text-sm leading-relaxed"
                 />
               </div>

               <div className="space-y-8 pt-2">
                  <ModifierGroup 
                    label="Camera Dynamics" 
                    icon={Camera} 
                    options={CAMERA_MOTIONS} 
                    current={cameraMotion} 
                    setter={setCameraMotion} 
                    color="text-blue-500" 
                  />

                  <ModifierGroup 
                    label="Visual Archetype" 
                    icon={Film} 
                    options={VIDEO_STYLES} 
                    current={videoStyle} 
                    setter={setVideoStyle} 
                    color="text-purple-500" 
                  />

                  <ModifierGroup 
                    label="Spectral Lighting" 
                    icon={Sun} 
                    options={VIDEO_LIGHTING} 
                    current={lighting} 
                    setter={setLighting} 
                    color="text-orange-500" 
                  />
               </div>

               <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Temporal Ratio</label>
                  <select 
                    value={aspectRatio}
                    onChange={(e) => setAspectRatio(e.target.value as any)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs text-white appearance-none cursor-pointer"
                  >
                    <option value="16:9">16:9 Horizontal</option>
                    <option value="9:16">9:16 Portrait</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Pixel Density</label>
                  <select 
                    value={resolution}
                    onChange={(e) => setResolution(e.target.value as any)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs text-white appearance-none cursor-pointer"
                  >
                    <option value="1080p">1080p HD</option>
                    <option value="720p">720p SD</option>
                  </select>
                </div>
              </div>

              <button
                onClick={handleGenerate}
                disabled={isGenerating || (!prompt && !startImage)}
                className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white py-6 rounded-[2rem] font-black uppercase text-xs tracking-[0.3em] transition-all shadow-xl shadow-red-600/20 flex items-center justify-center gap-3 active-press border-2 border-red-500"
              >
                {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <><Sparkles size={18} /> Synthesize Sequence</>}
              </button>
            </div>

            <div className="p-6 bg-zinc-900/50 border border-zinc-800 rounded-[2rem] flex items-start gap-4">
               <div className="p-3 bg-blue-500/10 rounded-2xl text-blue-400">
                  <Info size={20} />
               </div>
               <div>
                  <h4 className="text-[10px] font-bold text-white uppercase tracking-widest mb-1">Billing Protocol</h4>
                  <p className="text-[11px] text-zinc-500 leading-relaxed">
                    Veo generation requires a paid GCP project. View <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-blue-400 underline">billing documentation</a> for details.
                  </p>
               </div>
            </div>
          </div>

          {/* RIGHT: PREVIEW PANEL */}
          <div className="flex-1 bg-zinc-950 rounded-[3rem] border border-zinc-800/50 flex items-center justify-center relative overflow-hidden group shadow-inner">
            {isGenerating ? (
              <div className="flex flex-col items-center gap-8 text-red-500 animate-fade-in">
                  <div className="relative">
                     <Loader2 className="animate-spin w-20 h-20" strokeWidth={1} />
                     <div className="absolute inset-0 bg-red-500 blur-3xl opacity-10 animate-pulse"></div>
                  </div>
                  <div className="text-center space-y-3">
                     <p className="text-xl font-black text-white tracking-tight animate-pulse uppercase">Dreaming your Vision</p>
                     <p className="text-xs text-zinc-500 font-medium max-w-[280px] mx-auto leading-relaxed">
                        {LOADING_MESSAGES[loadingMsgIndex]}
                     </p>
                  </div>
              </div>
            ) : generatedVideoUrl ? (
              <div className="w-full h-full flex flex-col animate-scale-in relative group">
                <video src={generatedVideoUrl} controls autoPlay loop className="w-full h-full object-contain bg-black shadow-2xl" />
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex gap-4 opacity-0 group-hover:opacity-100 transition-all duration-500 transform group-hover:translate-y-0 translate-y-4">
                    <button 
                      onClick={sendToEditor}
                      disabled={justAdded}
                      className={`px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 backdrop-blur-xl shadow-2xl transition-all active-press ${justAdded ? 'bg-green-600 text-white' : 'bg-white hover:bg-zinc-200 text-black'}`}
                    >
                       {justAdded ? <><Check size={18} /> Added to Tracks</> : <><Scissors size={18} /> Export to Timeline</>}
                    </button>
                    <a 
                      href={generatedVideoUrl} 
                      download={`ranktica_clip_${Date.now()}.mp4`}
                      className="bg-zinc-900/80 hover:bg-zinc-800 text-white px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 border border-zinc-700 shadow-2xl transition-all active-press"
                    >
                      <Download size={18} /> Download Master
                    </a>
                </div>
              </div>
            ) : (
              <div className="text-zinc-800 flex flex-col items-center gap-8 opacity-30 animate-pulse">
                  <div className="w-56 h-56 rounded-[3.5rem] border-4 border-dashed border-zinc-800 flex items-center justify-center">
                     <VideoIcon size={96} strokeWidth={1} />
                  </div>
                  <div className="text-center space-y-3">
                    <p className="font-black uppercase text-lg tracking-[0.4em]">Visualizer Ready</p>
                    <p className="text-[10px] font-bold tracking-widest uppercase opacity-60 flex items-center justify-center gap-2">
                        Configure dynamics <ArrowRight size={10} /> Synthesize sequence
                    </p>
                  </div>
              </div>
            )}
          </div>
        </div>
      ) : (
        <div className="flex-1 flex flex-col gap-6 overflow-hidden animate-fade-in">
           {/* TIMELINE VIEW (Previous implementation preserved and refined) */}
           <div className="flex-1 bg-black rounded-[3rem] relative flex items-center justify-center overflow-hidden border border-zinc-800 shadow-2xl">
              <video ref={previewVideoRef} className="max-h-full max-w-full" onEnded={() => setIsPlaying(false)} />

              {timeline.length === 0 && (
                <div className="text-zinc-900 flex flex-col items-center gap-4">
                   <RotateCcw size={80} className="opacity-20" />
                   <p className="font-black uppercase tracking-[0.4em] text-xs opacity-40">Timeline Empty</p>
                </div>
              )}

              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-md border border-zinc-800/50 rounded-2xl px-6 py-3 flex items-center gap-6 shadow-2xl">
                 <div className="flex items-center gap-4">
                    <button onClick={() => seek(0)} className="p-2 text-zinc-500 hover:text-white transition-colors active-press"><SkipBack size={20} /></button>
                    <button onClick={togglePlay} className="p-3 bg-red-600 hover:bg-red-500 rounded-full text-white transition-all shadow-lg shadow-red-600/20 active-press">
                       {isPlaying ? <PauseCircle size={32} /> : <PlayCircle size={32} />}
                    </button>
                    <button onClick={() => seek(totalDuration)} className="p-2 text-zinc-500 hover:text-white transition-colors active-press"><SkipForward size={20} /></button>
                 </div>
                 <div className="w-px h-8 bg-zinc-800"></div>
                 <span className="text-sm font-mono text-zinc-300 min-w-[120px] text-center">
                    {currentTime.toFixed(2)}s / {totalDuration.toFixed(2)}s
                 </span>
              </div>
           </div>

           <div className="h-[45%] bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex flex-col overflow-hidden shadow-2xl">
              <div className="h-16 border-b border-zinc-800 flex items-center justify-between px-8 bg-zinc-950/50">
                 <h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Master Sequence Manifest</h3>
                 <div className="flex items-center gap-4">
                    <button 
                      onClick={() => editorFileInputRef.current?.click()}
                      className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2 bg-zinc-800 hover:bg-zinc-700 text-white px-5 py-2.5 rounded-xl border border-zinc-700 transition-all active-press"
                    >
                      <Plus size={14} /> Import Media
                    </button>
                    <input type="file" ref={editorFileInputRef} onChange={(e) => {
                       const file = e.target.files?.[0];
                       if (file) addVideoToTimeline(URL.createObjectURL(file), file.name);
                    }} className="hidden" accept="video/*" />
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-black/20 custom-scrollbar">
                 {timeline.length === 0 ? (
                   <div className="h-full flex flex-col items-center justify-center text-zinc-800">
                      <p className="text-sm font-bold uppercase tracking-widest opacity-30 italic">No tracks detected in current workspace</p>
                   </div>
                 ) : (
                   timeline.map((clip) => (
                     <div key={clip.id} className="group relative bg-zinc-900 border border-zinc-800/60 rounded-[2rem] p-5 flex gap-6 items-center hover:border-zinc-700 transition-all">
                        <div className={`p-5 rounded-2xl shrink-0 transition-transform duration-500 group-hover:rotate-6 ${clip.type === 'video' ? 'bg-blue-600/10 text-blue-500' : 'bg-purple-600/10 text-purple-500'}`}>
                           {clip.type === 'video' ? <Film size={28} /> : <AudioLines size={28} />}
                        </div>
                        <div className="flex-1 min-w-0">
                           <div className="flex justify-between items-start mb-4">
                              <div>
                                 <h4 className="text-base font-extrabold text-white truncate">{clip.name}</h4>
                                 <p className="text-[9px] text-zinc-500 uppercase font-black tracking-[0.2em] mt-1">{clip.duration.toFixed(1)}s source</p>
                              </div>
                              <button 
                                onClick={() => {
                                   const updated = timeline.filter(c => c.id !== clip.id);
                                   setTimeline(updated);
                                   recalculateTotalDuration(updated);
                                }} 
                                className="p-2.5 text-zinc-600 hover:text-red-500 transition-all bg-zinc-950 rounded-xl border border-zinc-800"
                              >
                                 <Trash2 size={16} />
                              </button>
                           </div>
                           <div className="grid grid-cols-4 gap-4 items-end">
                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1">Timeline Offset</span>
                                 <input type="number" value={clip.timelineOffset} step={0.1} onChange={(e) => {
                                    const val = parseFloat(e.target.value) || 0;
                                    setTimeline(prev => {
                                       const next = prev.map(c => c.id === clip.id ? { ...c, timelineOffset: val } : c);
                                       recalculateTotalDuration(next);
                                       return next;
                                    });
                                 }} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs font-bold text-white" />
                              </div>
                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1">Trim Start</span>
                                 <input type="number" value={clip.trimStart} step={0.1} onChange={(e) => {
                                    const val = parseFloat(e.target.value) || 0;
                                    setTimeline(prev => {
                                       const next = prev.map(c => c.id === clip.id ? { ...c, trimStart: val } : c);
                                       recalculateTotalDuration(next);
                                       return next;
                                    });
                                 }} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs font-bold text-white" />
                              </div>
                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1">Trim End</span>
                                 <input type="number" value={clip.trimEnd} step={0.1} onChange={(e) => {
                                    const val = parseFloat(e.target.value) || 0;
                                    setTimeline(prev => {
                                       const next = prev.map(c => c.id === clip.id ? { ...c, trimEnd: val } : c);
                                       recalculateTotalDuration(next);
                                       return next;
                                    });
                                 }} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs font-bold text-white" />
                              </div>
                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1">Playback Speed</span>
                                 <select value={clip.playbackSpeed} onChange={(e) => {
                                    const val = parseFloat(e.target.value) || 1;
                                    setTimeline(prev => {
                                       const next = prev.map(c => c.id === clip.id ? { ...c, playbackSpeed: val } : c);
                                       recalculateTotalDuration(next);
                                       return next;
                                    });
                                 }} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs font-bold text-white">
                                    {SPEED_OPTIONS.map(s => <option key={s} value={s}>{s}x</option>)}
                                 </select>
                              </div>
                           </div>
                        </div>
                     </div>
                   ))
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

