const LinkEditor = ({ 
  title, 
  items, 
  setItems,
  limit,
  icon: Icon
}: { 
  title: string, 
  items: LinkItem[], 
  setItems: React.Dispatch<React.SetStateAction<LinkItem[]>>,
  limit?: number,
  icon: any
}) => (
  <div className="space-y-4 bg-zinc-950/50 p-6 rounded-2xl border border-zinc-800">
