        <Icon size={14} className="text-zinc-600" />
        {title} {limit && <span className="text-zinc-700">({items.length}/{limit})</span>}
      </h4>
      <button 
        onClick={() => {
          if (limit && items.length >= limit) return;
          setItems([...items, { id: Date.now().toString(), label: '', url: '' }])
