            onChange={(e) => {
              const newItems = [...items];
              newItems[idx].url = e.target.value;
              setItems(newItems);
            }}
            className="flex-1 bg-zinc-900 border border-zinc-800 rounded-xl px-3 py-2 text-xs text-white focus:border-blue-500 outline-none transition-all"
