);

export const SeoOptimizer: React.FC<SeoOptimizerProps> = ({ prefill }) => {
  const [topic, setTopic] = useState('');
  const [result, setResult] = useState<SeoResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [copiedAll, setCopiedAll] = useState(false);
  const { incrementStat } = useAuth();

  // Settings State
  const [socialHandles, setSocialHandles] = useState<LinkItem[]>([]);
  const [playlists, setPlaylists] = useState<LinkItem[]>([]);

  // Options
  const [includeSocials, setIncludeSocials] = useState(true);
  const [includePlaylists, setIncludePlaylists] = useState(true);

  // Prefill Handling
  useEffect(() => {
    if (prefill) {
      const context = prefill.title || prefill.text?.substring(0, 100) || prefill.context || '';
      if (context) {
        setTopic(context);
        handleOptimize(context);
      }
    }
  }, [prefill]);

  // Load/Save settings
  useEffect(() => {
    const savedSocials = localStorage.getItem('rt_socials');
    const savedPlaylists = localStorage.getItem('rt_playlists');
    if (savedSocials) setSocialHandles(JSON.parse(savedSocials));
    if (savedPlaylists) setPlaylists(JSON.parse(savedPlaylists));
  }, []);

  useEffect(() => {
    localStorage.setItem('rt_socials', JSON.stringify(socialHandles));
    localStorage.setItem('rt_playlists', JSON.stringify(playlists));
  }, [socialHandles, playlists]);

  const handleOptimize = async (manualTopic?: string) => {
    const topicToUse = manualTopic || topic;
    if (!topicToUse.trim()) return;

    setLoading(true);
    setResult(null);
    try {
      const data = await generateSeo(topicToUse);

      // Build final description with links
      let finalDescription = data.description;

      const socialsPart = includeSocials && socialHandles.filter(s => s.label && s.url).length > 0
        ? "\n\n🔗 CONNECT WITH US\n" + socialHandles.map(s => `${s.label}: ${s.url}`).join('\n')
        : "";

      const playlistsPart = includePlaylists && playlists.filter(p => p.label && p.url).length > 0
        ? "\n\n📺 RECOMMENDED PLAYLISTS\n" + playlists.map(p => `${p.label}: ${p.url}`).join('\n')
        : "";

      finalDescription += socialsPart + playlistsPart;

      setResult({ ...data, description: finalDescription });
      incrementStat('seoOptimized');
    } catch (e) {
      console.error(e);
      alert("SEO generation failed. Please try a different topic.");
    } finally {
      setLoading(false);
    }
  };

  const handleQuickSelect = (t: string) => {
    setTopic(t);
    handleOptimize(t);
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const copyAll = () => {
    if (!result) return;
    const text = `--- VIDEO METADATA MANIFEST ---

TITLES:
${result.titles.map((t, i) => `${i+1}. ${t}`).join('\n')}

DESCRIPTION:
${result.description}

TAGS:
${result.tags.join(', ')}

HASHTAGS:
${result.hashtags.join(' ')}

SEMANTIC CLUSTERS (LSI):
${result.semanticClusters.join(' | ')}
`;
    copyToClipboard(text);
    setCopiedAll(true);
    setTimeout(() => setCopiedAll(false), 2000);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-12 animate-fade-in pb-20 relative">
      <div className="text-center space-y-4 py-8">
        <div className="inline-flex items-center justify-center p-4 rounded-[2rem] bg-blue-500/10 text-blue-500 mb-2 border border-blue-500/20 shadow-2xl">
           <Zap size={40} strokeWidth={2.5} fill="currentColor" />
        </div>
        <h2 className="text-5xl font-black bg-gradient-to-br from-white to-zinc-600 bg-clip-text text-transparent tracking-tighter">
          SEO Vision Studio
        </h2>
        <p className="text-zinc-400 text-lg font-medium max-w-2xl mx-auto">
          Deploy Gemini to map your content to Google's Knowledge Graph with high-retention semantic metadata.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Left Col: Settings/Management */}
        <div className="lg:col-span-1 space-y-6">
           <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 shadow-2xl space-y-8 h-fit">
              <div className="flex items-center justify-between border-b border-zinc-800 pb-4">
                 <h3 className="text-xs font-black uppercase tracking-[0.2em] text-white">Description Architecture</h3>
                 <Settings size={16} className="text-zinc-600" />
              </div>

              <LinkEditor 
                title="Social Profiles" 
                icon={Share2}
                items={socialHandles} 
                setItems={setSocialHandles} 
                limit={5} 
              />

              <LinkEditor 
                title="Smart Playlists" 
                icon={Youtube}
                items={playlists} 
                setItems={setPlaylists} 
                limit={5} 
              />

              <div className="space-y-3 pt-2">
                 <label className="flex items-center gap-3 cursor-pointer group">
                    <div 
                      onClick={() => setIncludeSocials(!includeSocials)}
                      className={`w-10 h-5 rounded-full transition-all relative ${includeSocials ? 'bg-blue-600' : 'bg-zinc-800'}`}
                    >
                       <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${includeSocials ? 'right-1' : 'left-1'}`}></div>
                    </div>
                    <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest group-hover:text-zinc-300 transition-colors">Append Socials</span>
                 </label>
                 <label className="flex items-center gap-3 cursor-pointer group">
