                                <pre className="whitespace-pre-wrap font-sans text-sm leading-relaxed text-zinc-400 font-medium">
                                   {result.description}
                                </pre>
                                <button 
                                  onClick={() => {copyToClipboard(result.description); alert('Description copied!')}}
                                  className="absolute top-4 right-4 p-3 bg-zinc-900 border border-zinc-800 rounded-xl text-zinc-500 hover:text-white opacity-0 group-hover/desc:opacity-100 transition-all shadow-xl"
                                >
                                   <Copy size={16} />
                                </button>
                             </div>
                          </div>
                       </div>
                    </div>
                 </div>

                 {/* Tags & Hashtags */}
                 <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 shadow-xl">
                    <div className="flex justify-between items-center mb-6">
                       <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                          <Layout size={16} className="text-zinc-500" /> Discovery Index (Tags)
                       </h3>
                       <button onClick={() => {copyToClipboard(result.tags.join(', ')); alert('Tags copied!')}} className="text-[10px] font-bold text-zinc-500 hover:text-white">Copy All</button>
                    </div>
                    <div className="flex flex-wrap gap-2">
                       {result.tags.map((tag, i) => (
                          <span key={i} className="bg-zinc-950 border border-zinc-800 px-3 py-1 rounded-lg text-[11px] text-zinc-400 hover:text-white transition-colors cursor-default">
                             {tag}
                          </span>
                       ))}
                    </div>
                 </div>

                 <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 shadow-xl">
                    <div className="flex justify-between items-center mb-6">
                       <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                          <Hash size={16} className="text-zinc-500" /> Viral Anchors (Hashtags)
                       </h3>
                       <button onClick={() => {copyToClipboard(result.hashtags.join(' ')); alert('Hashtags copied!')}} className="text-[10px] font-bold text-zinc-500 hover:text-white">Copy All</button>
                    </div>
                    <div className="flex flex-wrap gap-3">
                       {result.hashtags.map((h, i) => (
                          <span key={i} className="text-lg font-black text-blue-500 hover:scale-105 transition-transform cursor-pointer">
                             #{h.replace(/^#/, '')}
                          </span>
                       ))}
                    </div>
                 </div>
              </div>
           )}

           {!result && !loading && (
              <div className="flex flex-col items-center justify-center py-32 text-zinc-800 gap-8 opacity-40">
                 <div className="w-48 h-48 rounded-[3.5rem] border-4 border-dashed border-zinc-900 flex items-center justify-center">
                    <Search size={80} strokeWidth={1} />
                 </div>
                 <div className="text-center space-y-2">
                    <p className="font-black uppercase tracking-[0.4em] text-sm">Vision Engine Dormant</p>
                    <p className="text-[10px] font-bold tracking-widest uppercase opacity-60">Define topic to generate semantic manifest</p>
                 </div>
