        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { generateScriptStream } from '../services/gemini';
import { ToolType } from '../types';
import { 
  Loader2, 
  Play, 
  Download, 
  LayoutTemplate, 
  Bold, 
  Italic, 
  List, 
  ListOrdered, 
  Heading1, 
  Heading2,
  Sparkles,
  Zap,
  BookOpen,
  ChevronDown,
  History,
  FileText,
  Copy,
  Clock,
  Search,
  ChevronRight
} from 'lucide-react';
import { useAuth } from '../auth/AuthContext';

const SCRIPT_PRESETS = [
  {
    id: 'ranktica-tutorial',
    label: 'Ranktica AI Walkthrough',
    title: 'How to use Ranktica AI for YouTube Automation',
    tone: 'Engaging & Fun',
    type: 'tutorial',
    instructions: `Write a high-retention tutorial script. 
1. The Hook (0-15s): Focus on scaling a YouTube empire without burnout.
2. Step 1: Idea Generator & Viral Potential Score.
3. Step 2: Script Writer & Retention Logic.
4. Step 3: SEO Optimizer & Semantic Clusters.
5. Step 4: Thumbnail Studio & CTR Rater.
6. Step 5: Repurpose Engine & Multi-platform strategy.
7. Outro: CTA for trial.`
  },
  {
    id: 'case-study',
    label: 'AI Case Study',
    title: 'How I built a Faceless Channel to 100k Subs',
    tone: 'Deep Dive & Analytical',
    type: 'storytelling',
    instructions: 'Focus on data, specific AI tools used, revenue breakdown, and "hard truths" about the algorithm.'
  }
];

interface ScriptWriterProps {
  prefill?: { title?: string; instructions?: string };
  onNavigate?: (tool: ToolType, payload?: any) => void;
}

export const ScriptWriter: React.FC<ScriptWriterProps> = ({ prefill, onNavigate }) => {
  const [title, setTitle] = useState('');
  const [instructions, setInstructions] = useState('');
  const [tone, setTone] = useState('Engaging & Fun');
  const [scriptType, setScriptType] = useState('standard');
  const [script, setScript] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showPresets, setShowPresets] = useState(false);
  const [library, setLibrary] = useState<Array<{title: string, content: string, date: number}>>([
    {
      title: 'How to use Ranktica AI for YouTube Automation',
      date: Date.now(),
      content: `# How to use Ranktica AI for YouTube Automation\n\n**[0:00 - 0:15] THE HOOK**\n**"Ever feel like the YouTube algorithm is a puzzle you just can't solve? You've got the passion, but the research, the scripting, and the editing are eating up all your time. What if I told you that you could automate the entire process with one single dashboard? Welcome to Ranktica AI."**\n\n**[0:15 - 0:45] THE IDEA GENERATOR**\n**"It all starts with a spark. In the Viral Idea Lab, you don't just guess what's going to work. You enter your niche, and our Gemini 3 Pro model analyzes current trends to give you ideas with a calculated 'Viral Potential Score'. It even writes the hook for you."**\n\n**[0:45 - 1:15] THE SCRIPT WRITER**\n**"Once you have your winner, head over to the Script Writer. This isn't just generic AI text. It uses high-retention logic to structure your video. Whether it's a deep-dive documentary or a fast-paced tutorial, Ranktica formats it for maximum watch time."**\n\n**[1:15 - 1:45] SEO & CTR OPTIMIZATION**\n**"But a great video is useless if no one clicks. Our SEO Vision Studio maps your content to Google’s Knowledge Graph, finding the exact semantic clusters that trigger the algorithm. Pair that with our Thumbnail Studio to generate high-CTR visuals and use the CTR Rater to verify your design before you publish."**\n\n**[1:45 - 2:15] AUTOMATION SUITE**\n**"Need to scale across platforms? The Repurpose Engine takes your long-form script and turns it into a Twitter thread, a newsletter, and a 60-second Short instantly. You can even generate cinematic B-roll using our Veo-powered Video Studio."**\n\n**[2:15 - 2:30] OUTRO**\n**"YouTube Automation isn't about being lazy—it's about being strategic. Scale your channel, reclaim your time, and start your viral journey at Ranktica.ai today."**`
    }
  ]);

  const scriptEndRef = useRef<HTMLDivElement>(null);
  const instructionsRef = useRef<HTMLTextAreaElement>(null);
  const { incrementStat } = useAuth();
  const hasIncrementedRef = useRef(false);

  useEffect(() => {
    if (prefill) {
      if (prefill.title) setTitle(prefill.title);
      if (prefill.instructions) setInstructions(prefill.instructions);
    }
  }, [prefill]);

  const applyPreset = (p: typeof SCRIPT_PRESETS[0]) => {
    setTitle(p.title);
    setTone(p.tone);
    setScriptType(p.type);
    setInstructions(p.instructions);
    setShowPresets(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    setIsGenerating(true);
    setScript('');
    hasIncrementedRef.current = false;

    try {
      let fullContent = '';
      await generateScriptStream(title, tone, scriptType, instructions, (chunk) => {
        setScript(prev => {
            if (!hasIncrementedRef.current && prev.length > 50) {
                incrementStat('scriptsWritten');
                hasIncrementedRef.current = true;
            }
            fullContent += chunk;
            return prev + chunk;
        });
      });
      setLibrary(prev => [{title, content: fullContent, date: Date.now()}, ...prev].slice(0, 10));
    } catch (err) {
      console.error(err);
      setScript(prev => prev + "\n\n[Error generating script. Please try again.]");
    } finally {
      setIsGenerating(false);
    }
  };

  useEffect(() => {
    if (scriptEndRef.current) {
      scriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [script]);

  const handleDownload = () => {
    const blob = new Blob([script], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_script.md`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const insertFormat = (startTag: string, endTag: string = '') => {
    const textarea = instructionsRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = before + startTag + selection + endTag + after;
    setInstructions(newText);

    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start + startTag.length, end + startTag.length);
    }, 0);
  };

  const handleOptimizeSeo = () => {
     if (onNavigate) {
        onNavigate(ToolType.SEO, { title, text: script });
     }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col md:flex-row gap-6 animate-fade-in pb-10">
      {/* Configuration Panel */}
      <div className="w-full md:w-[380px] space-y-6 flex flex-col shrink-0">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-black text-white mb-1">Script Writer</h2>
            <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest">Architectural Studio</p>
          </div>
          <div className="relative">
            <button 
              onClick={() => setShowPresets(!showPresets)}
              className="flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all border border-zinc-800 active-press"
            >
              <BookOpen size={14} /> Presets <ChevronDown size={14} className={showPresets ? 'rotate-180' : ''} />
            </button>
            {showPresets && (
              <div className="absolute top-full right-0 mt-2 w-64 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-2xl z-50 overflow-hidden animate-scale-in glass-morphism">
                <div className="p-3 border-b border-zinc-800 text-[10px] font-black uppercase text-zinc-500 tracking-widest">Select Template</div>
                {SCRIPT_PRESETS.map(p => (
                  <button
                    key={p.id}
                    onClick={() => applyPreset(p)}
                    className="w-full text-left px-4 py-3 hover:bg-red-500/10 hover:text-white text-zinc-400 text-sm font-medium border-b border-zinc-800 last:border-0 transition-colors"
                  >
                    {p.label}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4 p-6 bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex-1 flex flex-col shadow-2xl">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Video Headline</label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="e.g. YouTube Automation Walkthrough"
              className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-red-500/50 outline-none transition-all text-white font-medium placeholder:text-zinc-800"
            />
          </div>

          <div className="space-y-2 flex-1 flex flex-col">
            <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Logic Constraints</label>
            <div className="flex-1 flex flex-col bg-zinc-950 border border-zinc-800 rounded-2xl overflow-hidden focus-within:ring-2 focus-within:ring-red-500/50 transition-all shadow-inner">
              <div className="flex items-center gap-1 p-2 border-b border-zinc-800 bg-zinc-900/40">
                <button type="button" onClick={() => insertFormat('**', '**')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <Bold size={14} />
                </button>
                <button type="button" onClick={() => insertFormat('*', '*')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <Italic size={14} />
                </button>
                <div className="w-px h-4 bg-zinc-800 mx-1"></div>
                <button type="button" onClick={() => insertFormat('# ')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <Heading1 size={14} />
                </button>
                <button type="button" onClick={() => insertFormat('- ')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <List size={14} />
                </button>
              </div>

              <textarea
                ref={instructionsRef}
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
                placeholder="Describe narrative flow, visual cues, and key takeaways..."
                className="w-full h-full min-h-[120px] bg-transparent p-5 outline-none resize-none text-white text-sm leading-relaxed placeholder:text-zinc-800"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Structural Tier</label>
              <select
                value={scriptType}
                onChange={(e) => setScriptType(e.target.value)}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-500/50 outline-none text-white appearance-none text-[10px] font-black uppercase tracking-widest cursor-pointer"
              >
                <option value="standard">Standard YouTube</option>
                <option value="storytelling">Storytelling / Docu</option>
                <option value="tutorial">How-To Tutorial</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Acoustic Tone</label>
              <select
                value={tone}
                onChange={(e) => setTone(e.target.value)}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-500/50 outline-none text-white appearance-none text-[10px] font-black uppercase tracking-widest cursor-pointer"
              >
                <option>Engaging & Fun</option>
                <option>Professional</option>
                <option>Fast-paced & Hype</option>
                <option>Deep Dive</option>
              </select>
            </div>
          </div>

          <button
            type="submit"
            disabled={isGenerating || !title}
            className={`w-full py-5 rounded-[1.5rem] font-black uppercase text-xs tracking-widest flex items-center justify-center gap-3 transition-all active-press ${
              isGenerating 
                ? 'bg-zinc-800 text-zinc-600' 
                : 'bg-red-600 hover:bg-red-500 text-white shadow-xl shadow-red-600/20'
            }`}
          >
            {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <><Zap size={18} fill="currentColor" /> Synthesize Script</>}
          </button>
        </form>

        {/* Script Library Panel */}
        <div className="bg-zinc-900 border border-zinc-800 p-6 rounded-[2.5rem] shadow-xl overflow-hidden flex flex-col max-h-[300px]">
           <div className="flex items-center justify-between mb-4 shrink-0">
              <h3 className="text-[10px] font-black text-zinc-600 uppercase tracking-widest flex items-center gap-2">
                <History size={14} /> Script Library
              </h3>
              <span className="text-[9px] font-bold text-zinc-700 bg-zinc-950 px-2 py-0.5 rounded-full border border-zinc-800">{library.length} SAVED</span>
           </div>
           <div className="space-y-2 overflow-y-auto pr-2 custom-scrollbar">
              {library.map((item, i) => (
                <button 
                  key={i}
                  onClick={() => { setTitle(item.title); setScript(item.content); }}
                  className="w-full text-left p-3 rounded-xl bg-zinc-950 border border-zinc-800 hover:border-red-500/30 transition-all group"
                >
                   <div className="flex justify-between items-start gap-2 mb-1">
                      <p className="text-xs font-bold text-zinc-300 truncate group-hover:text-white transition-colors">{item.title}</p>
                      <Clock size={10} className="text-zinc-700 shrink-0 mt-0.5" />
                   </div>
                   <p className="text-[9px] text-zinc-600 font-medium uppercase tracking-tighter">Cached Archive</p>
                </button>
              ))}
           </div>
        </div>
      </div>

      {/* Editor/Preview Panel */}
