export const IdeaCard: React.FC<IdeaCardProps> = ({ idea, onAction, isSaved, onToggleSave }) => {
  const [copied, setCopied] = useState(false);
  const [showLogic, setShowLogic] = useState(false);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(`${idea.title}\n${idea.hook}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="group relative bg-zinc-900 border border-zinc-800 p-6 rounded-[2rem] transition-all duration-300 hover:border-red-500/40 hover:shadow-2xl hover:shadow-red-500/5 animate-scale-in hover-lift flex flex-col">
