                  <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Niche Authority</span>
                    <span className="text-xl font-black text-white flex items-center gap-2">
                       <Target size={20} className="text-red-500" /> {niche}
