    if (!script) return { pacing: 0, density: 0, cues: 0 };
    const cueCount = (script.match(/\[Visual:.*?\]/g) || []).length;
    const words = script.replace(/\[.*?\]/g, '').split(/\s+/).filter(w => w.length > 0).length;

    // Calculated stats
    const visualDensity = Math.min((cueCount / (words / 20)) * 100, 100); // Target 1 cue per 20 words
    const pacingVelocity = Math.min((words / 150) * 100, 100); // Score based on word count/time ratio

    return {
      pacing: Math.round(pacingVelocity),
      density: Math.round(visualDensity),
      cues: cueCount
    };
