interface LibraryAsset {
  id: string;
  url: string;
  name: string;
  type: 'ai' | 'upload';
  thumbnail?: string;
  duration: number;
}

interface TimelineClip {
  id: string;
  type: 'video' | 'audio';
  url: string;
  name: string;
  duration: number;
  trimStart: number;
  trimEnd: number;
  timelineOffset: number;
  playbackSpeed: number;
}

export const VideoStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'create' | 'edit'>('create');
  const [hasApiKey, setHasApiKey] = useState(true);

  // --- LIBRARY STATE ---
  const [library, setLibrary] = useState<LibraryAsset[]>([]);

  // --- GENERATOR STATE ---
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('1080p');
  const [startImage, setStartImage] = useState<string | null>(null);

  const [cameraMotion, setCameraMotion] = useState('');
  const [videoStyle, setVideoStyle] = useState('Cinematic Movie');
  const [lighting, setLighting] = useState('');

  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const assetUploadRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);

  const previewVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
    };
    checkKey();
  }, []);

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 6000);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const applyBlueprint = (bp: typeof VIDEO_BLUEPRINTS[0]) => {
    setPrompt(bp.prompt);
    setVideoStyle(bp.style);
    setCameraMotion(bp.motion);
    setLighting(bp.lighting);
    setAspectRatio(bp.aspect as any);
  };

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const addAssetToLibrary = (url: string, name: string, type: 'ai' | 'upload') => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const newAsset: LibraryAsset = {
        id: Math.random().toString(36).substring(2, 11),
        url,
        name,
        type,
        duration: tempVid.duration || 5
      };
      setLibrary(prev => [newAsset, ...prev]);
    };
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey && window.aistudio) await handleOpenKeyPicker();

    setIsGenerating(true);
    setGeneratedVideoUrl(null);

    const technicalPrompt = `A ${videoStyle.toLowerCase()} of ${prompt}. ${cameraMotion ? `Camera motion: ${cameraMotion}.` : ''} ${lighting ? `Lighting: ${lighting}.` : ''} High fidelity, cinematic quality.`;

    try {
      const url = await generateVideo(technicalPrompt, aspectRatio, startImage || undefined, resolution);
      if (url) {
        setGeneratedVideoUrl(url);
        addAssetToLibrary(url, `AI Sequence ${library.length + 1}`, 'ai');
      }
    } catch (error: any) {
      console.error(error);
      if (error.message?.includes("Requested entity was not found")) {
         setHasApiKey(false);
         alert("API Key mismatch. Please re-select.");
      } else {
         alert("Generation failed.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAssetUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      addAssetToLibrary(url, file.name, 'upload');
    }
  };

  const handleRefUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const addVideoToTimeline = (url: string, name: string, duration: number) => {
    setTimeline(prev => {
      const nextOffset = prev.reduce((max, clip) => {
        const end = clip.timelineOffset + (clip.trimEnd - clip.trimStart) / clip.playbackSpeed;
        return Math.max(max, end);
      }, 0);

      const newClip: TimelineClip = {
        id: Math.random().toString(36).substring(2, 11),
        type: 'video',
        url,
        name,
        duration,
        trimStart: 0,
        trimEnd: duration,
        timelineOffset: nextOffset,
        playbackSpeed: 1
      };
      const newTimeline = [...prev, newClip];
      recalculateTotalDuration(newTimeline);
      return newTimeline;
    });
  };

  const recalculateTotalDuration = (clips: TimelineClip[]) => {
    let max = 0;
    clips.forEach(c => {
      const end = c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed;
      if (end > max) max = end;
    });
    setTotalDuration(max);
  };

  const togglePlay = () => setIsPlaying(!isPlaying);
  const seek = (time: number) => setCurrentTime(Math.max(0, Math.min(time, totalDuration)));

  useEffect(() => {
    let animationFrameId: number;
    if (isPlaying) {
      const startTime = performance.now();
      const initialCurrentTime = currentTime;
      const animate = (now: number) => {
        const delta = (now - startTime) / 1000;
        const next = initialCurrentTime + delta;
        if (next >= totalDuration) {
          setIsPlaying(false);
          setCurrentTime(totalDuration);
        } else {
          setCurrentTime(next);
          animationFrameId = requestAnimationFrame(animate);
        }
      };
      animationFrameId = requestAnimationFrame(animate);
    }
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  useEffect(() => {
    if (previewVideoRef.current) {
       const activeClip = timeline.find(c => 
         c.type === 'video' && 
         currentTime >= c.timelineOffset && 
         currentTime <= (c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed)
       );
       if (activeClip) {
          if (previewVideoRef.current.src !== activeClip.url) previewVideoRef.current.src = activeClip.url;
          previewVideoRef.current.playbackRate = activeClip.playbackSpeed;
          const internalTime = activeClip.trimStart + (currentTime - activeClip.timelineOffset) * activeClip.playbackSpeed;
          if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.2) previewVideoRef.current.currentTime = internalTime;
       }
    }
  }, [currentTime, timeline]);

  const ModifierGroup = ({ label, icon: Icon, options, current, setter, color }: any) => (
    <div className="space-y-3">
      <label className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${color}`}>
         <Icon size={12} /> {label}
      </label>
      <div className="flex flex-wrap gap-2">
         {options.map((opt: string) => (
           <button key={opt} type="button" onClick={() => setter(current === opt ? '' : opt)} className={`px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase transition-all border ${current === opt ? 'bg-zinc-100 border-white text-black shadow-lg scale-105' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}>
             {opt}
           </button>
         ))}
      </div>
    </div>
  );

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6 gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
             <VideoIcon className="text-red-500" /> Veo Studio
          </h2>
          <p className="text-zinc-400 text-sm font-medium">Visual Synthesis & Timeline Orchestration</p>
        </div>

        <div className="flex gap-4 items-center">
          <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800">
            <button onClick={() => setActiveTab('create')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'create' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}>Creative Hub</button>
            <button onClick={() => setActiveTab('edit')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'edit' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}>Sequencer</button>
          </div>
        </div>
      </header>

      <div className="flex-1 flex flex-col md:flex-row gap-8 min-h-0">
        {/* SIDEBAR: ASSET VAULT (Visible in Create Tab) */}
        {activeTab === 'create' && (
          <div className="w-full md:w-[420px] flex flex-col gap-6 overflow-y-auto pr-3 custom-scrollbar pb-10">

            <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 space-y-8 shadow-2xl relative overflow-hidden">
               <div className="flex items-center justify-between">
                  <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] flex items-center gap-2">
                    <Archive size={12} className="text-blue-500" /> Neural Media Vault
                  </h3>
                  <button onClick={() => assetUploadRef.current?.click()} className="p-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 hover:text-white rounded-xl transition-all"><Plus size={16}/></button>
                  <input type="file" ref={assetUploadRef} className="hidden" accept="video/*" onChange={handleAssetUpload} />
               </div>

               <div className="grid grid-cols-2 gap-3">
                  {library.length === 0 ? (
                    <div className="col-span-2 py-10 flex flex-col items-center justify-center border-2 border-dashed border-zinc-800 rounded-3xl text-zinc-700">
                       <Film size={24} className="mb-2 opacity-20" />
                       <span className="text-[9px] font-black uppercase tracking-widest opacity-40">Vault Empty</span>
                    </div>
                  ) : (
                    library.map(asset => (
                      <div key={asset.id} className="group relative bg-zinc-950 border border-zinc-800 rounded-2xl p-2 transition-all hover:border-blue-500/50">
                         <div className="aspect-video bg-zinc-900 rounded-xl mb-2 flex items-center justify-center relative overflow-hidden">
                            {asset.type === 'ai' ? <Sparkles size={16} className="text-red-500 opacity-20" /> : <Upload size={16} className="text-blue-500 opacity-20" />}
                            <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                               <button onClick={() => addVideoToTimeline(asset.url, asset.name, asset.duration)} className="p-2 bg-white text-black rounded-full hover:scale-110 transition-transform"><Plus size={14} /></button>
                               <a href={asset.url} download className="p-2 bg-zinc-800 text-white rounded-full hover:scale-110 transition-transform"><Download size={14} /></a>
                            </div>
                         </div>
                         <p className="text-[10px] font-bold text-zinc-400 truncate px-1">{asset.name}</p>
                         <span className="absolute top-3 right-3 text-[8px] font-black px-1.5 py-0.5 bg-black/80 text-zinc-500 rounded uppercase">{asset.duration.toFixed(1)}s</span>
                      </div>
                    ))
                  )}
               </div>

               <div className="w-full h-px bg-zinc-800"></div>

               <div className="space-y-4">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Input Framework</label>
                  <div onClick={() => fileInputRef.current?.click()} className="w-full h-32 border-2 border-dashed border-zinc-800 hover:border-red-500/50 rounded-3xl flex flex-col items-center justify-center cursor-pointer bg-zinc-950/50 transition-all relative group overflow-hidden">
                    {startImage ? <img src={startImage} alt="Ref" className="h-full w-full object-cover" /> : <div className="text-zinc-600 flex flex-col items-center gap-2"><Camera size={24} /><span className="text-[9px] font-black uppercase">Base Frame</span></div>}
                  </div>
                  <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleRefUpload} />
               </div>

               <div className="space-y-4">
                 <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="Action descriptor..." className="w-full h-28 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 outline-none text-white text-sm" />
               </div>

               <div className="space-y-6 pt-2">
                  <ModifierGroup label="Dynamics" icon={Camera} options={CAMERA_MOTIONS.slice(0, 5)} current={cameraMotion} setter={setCameraMotion} color="text-blue-500" />
                  <ModifierGroup label="Archetype" icon={Film} options={VIDEO_STYLES.slice(0, 4)} current={videoStyle} setter={setVideoStyle} color="text-purple-500" />
               </div>

               <button onClick={handleGenerate} disabled={isGenerating || (!prompt && !startImage)} className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white py-5 rounded-[2rem] font-black uppercase text-xs tracking-[0.3em] transition-all shadow-xl flex items-center justify-center gap-3 border-2 border-red-500">
                {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <><Sparkles size={18} /> Synthesize</>}
              </button>
            </div>
          </div>
        )}

        {/* MAIN STAGE */}
        <div className="flex-1 bg-zinc-950 rounded-[3rem] border border-zinc-800/50 flex flex-col items-center justify-center relative overflow-hidden group shadow-inner">
          {activeTab === 'create' ? (
            isGenerating ? (
              <div className="flex flex-col items-center gap-8 text-red-500 animate-fade-in">
                  <Loader2 className="animate-spin w-20 h-20" strokeWidth={1} />
                  <div className="text-center space-y-2">
                     <p className="text-xl font-black text-white tracking-tight animate-pulse uppercase">Dreaming Vision</p>
                     <p className="text-[10px] text-zinc-500 font-medium">{LOADING_MESSAGES[loadingMsgIndex]}</p>
                  </div>
              </div>
