            <div className="w-full h-full flex flex-col overflow-hidden">
               <div className="flex-1 relative flex items-center justify-center bg-black">
                  <video ref={previewVideoRef} className="max-h-full max-w-full" onEnded={() => setIsPlaying(false)} />
                  <div className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-md border border-zinc-800/50 rounded-2xl px-6 py-3 flex items-center gap-6 shadow-2xl">
                     <button onClick={() => seek(0)} className="p-2 text-zinc-500 hover:text-white transition-colors"><SkipBack size={20} /></button>
                     <button onClick={togglePlay} className="p-3 bg-red-600 hover:bg-red-500 rounded-full text-white transition-all shadow-lg active-press">
                        {isPlaying ? <PauseCircle size={32} /> : <PlayCircle size={32} />}
                     </button>
                     <button onClick={() => seek(totalDuration)} className="p-2 text-zinc-500 hover:text-white transition-colors"><SkipForward size={20} /></button>
                     <div className="w-px h-8 bg-zinc-800"></div>
                     <span className="text-sm font-mono text-zinc-300 min-w-[100px] text-center">{currentTime.toFixed(2)}s</span>
                  </div>
