               <div className="h-[40%] bg-zinc-900 border-t border-zinc-800 p-6 overflow-y-auto custom-scrollbar">
                  <div className="flex items-center justify-between mb-6">
                     <h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Timeline Workspace</h3>
                     <div className="flex items-center gap-4">
                        <button onClick={() => assetUploadRef.current?.click()} className="text-[10px] font-black uppercase bg-zinc-800 hover:bg-zinc-700 text-white px-4 py-2 rounded-xl transition-all"><Plus size={14} className="inline mr-2"/> Add Clip</button>
                     </div>
                  </div>
                  <div className="space-y-3">
                     {timeline.map(clip => (
                       <div key={clip.id} className="bg-zinc-950 border border-zinc-800 rounded-2xl p-4 flex items-center gap-4 group">
                          <div className="w-12 h-12 bg-zinc-900 rounded-xl flex items-center justify-center text-zinc-700 group-hover:text-blue-500 transition-colors"><Film size={20}/></div>
                          <div className="flex-1 min-w-0">
                             <p className="text-xs font-bold text-zinc-200 truncate">{clip.name}</p>
                             <div className="flex gap-4 mt-1">
                                <span className="text-[9px] text-zinc-600 font-black uppercase tracking-tighter">Offset: {clip.timelineOffset.toFixed(1)}s</span>
                                <span className="text-[9px] text-zinc-600 font-black uppercase tracking-tighter">Speed: {clip.playbackSpeed}x</span>
                             </div>
                          </div>
                          <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                             <button onClick={() => setTimeline(prev => prev.filter(c => c.id !== clip.id))} className="p-2 hover:bg-red-500/10 text-zinc-600 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                          </div>
                       </div>
                     ))}
                  </div>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

