                <div className="p-3 border-b border-zinc-800 text-[10px] font-black uppercase text-zinc-500 tracking-widest">Select Template</div>
                {SCRIPT_PRESETS.map(p => (
                  <button key={p.id} onClick={() => applyPreset(p)} className="w-full text-left px-4 py-3 hover:bg-red-500/10 hover:text-white text-zinc-400 text-sm font-medium border-b border-zinc-800 last:border-0 transition-colors">
                    {p.label}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        <form onSubmit={handleGenerate} className="space-y-4 p-6 bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex-1 flex flex-col shadow-2xl">
