  Loader2, 
  Mic, 
  Volume2, 
  FileAudio, 
  PlayCircle, 
  Upload, 
  FileText, 
  X, 
  Music, 
  Download, 
  Check, 
  Sparkles, 
  AudioLines, 
  Zap, 
  Copy,
  Activity,
  Waves,
  Ear,
  Radio,
  ChevronRight
} from 'lucide-react';

