        </div>
        <h2 className="text-5xl font-black bg-gradient-to-br from-white to-zinc-600 bg-clip-text text-transparent tracking-tighter">
          Acoustic Intelligence Studio
        </h2>
        <p className="text-zinc-400 text-lg font-medium max-w-2xl mx-auto">
          Orchestrate neural voice synthesis and temporal audio mapping for high-retention cinematic narratives.
        </p>

        <div className="flex bg-zinc-900/50 rounded-3xl p-1.5 border border-zinc-800 w-fit mx-auto mt-10 shadow-2xl">
          <button 
            onClick={() => { setTab('tts'); setTranscription(''); }}
            className={`px-12 py-3.5 rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] transition-all active-press ${tab === 'tts' ? 'bg-zinc-800 text-white shadow-xl' : 'text-zinc-500 hover:text-white'}`}
          >
            Synthesis Lab
          </button>
          <button 
            onClick={() => { setTab('stt'); setAudioResult(null); }}
            className={`px-12 py-3.5 rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] transition-all active-press ${tab === 'stt' ? 'bg-zinc-800 text-white shadow-xl' : 'text-zinc-500 hover:text-white'}`}
          >
            Transcription
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* Main Stage */}
        <div className="lg:col-span-8 space-y-8">
          <div className="bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:opacity-10 transition-opacity">
               <AudioLines size={120} />
            </div>

            {tab === 'tts' ? (
              <div className="space-y-10 animate-fade-in relative z-10">
                 <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
                         <Radio size={24} />
                      </div>
                      <div>
                        <h3 className="text-2xl font-black text-white uppercase tracking-tighter">Narration Blueprint</h3>
                        <p className="text-[10px] font-black uppercase text-zinc-600 tracking-widest">Optimizing for Vocal Texture</p>
                      </div>
                    </div>
                    {downloadBlob && (
                      <button 
                        onClick={handleDownload}
                        className="flex items-center gap-2 bg-white hover:bg-zinc-200 text-black px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl transition-all active-press border-2 border-white"
                      >
                        <Download size={16} /> Export Master
                      </button>
