                <div className="pt-4">
                   <div className="bg-zinc-950 rounded-2xl border border-zinc-800 p-5 space-y-4">
                      <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest text-zinc-600">
                         <span>Synthetic Fidelity</span>
