           )}

           <div className="bg-zinc-900 border border-zinc-800 p-10 rounded-[3rem] shadow-2xl">
              <h3 className="text-xs font-black text-white uppercase tracking-[0.2em] mb-8 flex items-center gap-3">
                 <Activity size={16} className="text-blue-500" /> Latency Telemetry
              </h3>
              <div className="space-y-8">
                 <div className="space-y-3">
                    <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest">
                       <span className="text-zinc-600">Inference Speed</span>
                       <span className="text-green-500">Fast (0.8s)</span>
                    </div>
                    <div className="w-full h-1.5 bg-zinc-950 rounded-full overflow-hidden">
                       <div className="h-full bg-green-500 w-[92%] shadow-[0_0_10px_rgba(34,197,94,0.4)]"></div>
                    </div>
                 </div>

                 <div className="space-y-3">
                    <div className="flex items-center justify-between text-[10px] font-black uppercase tracking-widest">
                       <span className="text-zinc-600">Vocal Coherence</span>
                       <span className="text-blue-400">Maximized</span>
                    </div>
                    <div className="w-full h-1.5 bg-zinc-950 rounded-full overflow-hidden">
                       <div className="h-full bg-blue-500 w-[98%] shadow-[0_0_10px_rgba(59,130,246,0.4)]"></div>
                    </div>
                 </div>

                 <div className="pt-6 border-t border-zinc-800">
                    <div className="flex items-center gap-3 p-4 bg-zinc-950 rounded-2xl border border-zinc-800 group cursor-help">
                       <div className="p-2 bg-yellow-500/10 rounded-xl text-yellow-500 group-hover:scale-110 transition-transform">
                          <Zap size={14} fill="currentColor" />
                       </div>
                       <div>
                          <p className="text-[10px] font-black text-white uppercase tracking-widest">Studio Status</p>
                          <p className="text-[9px] font-bold text-zinc-600 uppercase mt-1">Operational • 24.0kHz Ready</p>
                       </div>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { generateVideo } from '../services/gemini';
import { 
  Loader2, 
  Video as VideoIcon, 
  Upload, 
  PlayCircle, 
  Download, 
  Scissors, 
  Plus, 
  Trash2, 
  PauseCircle, 
  SkipBack, 
  SkipForward, 
  Film, 
  Zap, 
  Check,
  AudioLines,
  Sparkles,
  RotateCcw,
  Clock,
  Camera,
  Layers,
  Wand2,
  Archive,
  Monitor,
  GripVertical,
  Play,
  Settings,
  ChevronRight,
  Maximize,
  Volume2,
  Lock,
  ExternalLink
} from 'lucide-react';

const LOADING_MESSAGES = [
  "Initializing Veo creative engine...",
  "Analyzing visual descriptors and style cues...",
  "Synthesizing high-fidelity frames...",
  "Applying temporal coherence and physics...",
  "Finalizing cinematic render...",
  "Optimizing for your target aspect ratio..."
];

const CAMERA_MOTIONS = [
  'Static', 'Slow Pan Right', 'Slow Pan Left', 
  'Cinematic Tilt Up', 'Dramatic Tilt Down', 'Dolly Zoom In'
];

const VIDEO_STYLES = [
  'Cinematic Movie', '3D Octane Render', 'Drone Aerial View', 
  'GoPro POV Wide', '16mm Vintage Film', 'Cyberpunk Neon'
];

interface LibraryAsset {
  id: string;
  url: string;
  name: string;
  type: 'ai' | 'upload';
  duration: number;
}

interface TimelineClip {
  id: string;
  assetId: string;
  url: string;
  name: string;
  duration: number;
  timelineOffset: number; // Seconds from start
}

export const VideoStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'create' | 'edit'>('create');
  const [hasApiKey, setHasApiKey] = useState(false);
  const [checkingKey, setCheckingKey] = useState(true);

  // --- LIBRARY STATE ---
  const [library, setLibrary] = useState<LibraryAsset[]>([]);

  // --- GENERATOR STATE ---
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('1080p');
  const [startImage, setStartImage] = useState<string | null>(null);
  const [cameraMotion, setCameraMotion] = useState('');
  const [videoStyle, setVideoStyle] = useState('Cinematic Movie');

  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const assetUploadRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [zoomLevel, setZoomLevel] = useState(20); // pixels per second
  const timelineRef = useRef<HTMLDivElement>(null);
  const previewVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      setCheckingKey(true);
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
      setCheckingKey(false);
    };
    checkKey();
  }, []);

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 6000);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const totalDuration = useMemo(() => {
    return timeline.reduce((max, clip) => Math.max(max, clip.timelineOffset + clip.duration), 0);
  }, [timeline]);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true); // Assume success as per instructions
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey) {
      await handleSelectKey();
      return;
    }

    setIsGenerating(true);
    setGeneratedVideoUrl(null);

    const technicalPrompt = `A ${videoStyle.toLowerCase()} of ${prompt}. ${cameraMotion ? `Camera motion: ${cameraMotion}.` : ''} High fidelity, cinematic quality.`;

    try {
      const url = await generateVideo(technicalPrompt, aspectRatio, startImage || undefined, resolution);
      if (url) {
        setGeneratedVideoUrl(url);
        addAssetToLibrary(url, `AI Sequence ${library.length + 1}`, 'ai');
      }
    } catch (error: any) {
      console.error(error);
      if (error.message?.includes("Requested entity was not found")) {
        setHasApiKey(false);
        alert("Paid API Key not found. Please select a valid key from a billed project.");
      } else {
        alert("Generation failed. Please try again.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const addAssetToLibrary = (url: string, name: string, type: 'ai' | 'upload') => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const newAsset: LibraryAsset = {
        id: Math.random().toString(36).substring(2, 11),
        url,
        name,
        type,
        duration: tempVid.duration || 5
      };
      setLibrary(prev => [newAsset, ...prev]);
    };
  };

  const handleAssetUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      addAssetToLibrary(url, file.name, 'upload');
    }
  };

  const addClipToTimeline = (asset: LibraryAsset) => {
    const newClip: TimelineClip = {
      id: Math.random().toString(36).substring(2, 11),
      assetId: asset.id,
      url: asset.url,
      name: asset.name,
      duration: asset.duration,
      timelineOffset: totalDuration
    };
    setTimeline(prev => [...prev, newClip]);
    setActiveTab('edit');
  };

  const removeClip = (id: string) => {
    setTimeline(prev => {
      const filtered = prev.filter(c => c.id !== id);
      let offset = 0;
      return filtered.map(c => {
        const item = { ...c, timelineOffset: offset };
        offset += c.duration;
        return item;
      });
    });
  };

  const togglePlay = () => setIsPlaying(!isPlaying);

  useEffect(() => {
    let animationFrameId: number;
    if (isPlaying) {
      const startTime = performance.now();
      const initialCurrentTime = currentTime;
      const animate = (now: number) => {
        const delta = (now - startTime) / 1000;
        const next = initialCurrentTime + delta;
        if (next >= totalDuration) {
          setIsPlaying(false);
          setCurrentTime(totalDuration);
        } else {
          setCurrentTime(next);
          animationFrameId = requestAnimationFrame(animate);
        }
      };
      animationFrameId = requestAnimationFrame(animate);
    }
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  useEffect(() => {
    if (previewVideoRef.current) {
      const activeClip = timeline.find(c => 
        currentTime >= c.timelineOffset && 
        currentTime < c.timelineOffset + c.duration
      );
      if (activeClip) {
        if (previewVideoRef.current.src !== activeClip.url) {
          previewVideoRef.current.src = activeClip.url;
        }
        const internalTime = currentTime - activeClip.timelineOffset;
        if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.2) {
          previewVideoRef.current.currentTime = internalTime;
        }
      } else {
        previewVideoRef.current.src = "";
      }
    }
  }, [currentTime, timeline]);

  const handleTimelineClick = (e: React.MouseEvent) => {
    if (!timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left + timelineRef.current.scrollLeft;
    setCurrentTime(Math.max(0, Math.min(x / zoomLevel, totalDuration)));
  };

  if (checkingKey) {
    return (
      <div className="h-full flex items-center justify-center">
        <Loader2 className="animate-spin text-red-500" size={48} />
      </div>
    );
  }

  if (!hasApiKey) {
    return (
      <div className="h-[calc(100vh-6rem)] flex flex-col items-center justify-center animate-fade-in space-y-8">
        <div className="w-32 h-32 bg-zinc-900 rounded-[2.5rem] flex items-center justify-center border border-zinc-800 shadow-2xl relative overflow-hidden group">
           <div className="absolute inset-0 bg-red-600/5 group-hover:bg-red-600/10 transition-colors"></div>
           <Lock size={48} className="text-red-500 relative z-10" />
        </div>
        <div className="text-center space-y-3 max-w-md">
           <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Engine Locked</h2>
           <p className="text-zinc-500 font-medium">
             Video generation via Veo requires a paid API key from a Google Cloud project with billing enabled.
           </p>
        </div>
        <div className="flex flex-col items-center gap-4 w-full">
           <button 
             onClick={handleSelectKey}
             className="bg-red-600 hover:bg-red-500 text-white px-10 py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-red-600/20 transition-all active-press flex items-center gap-2"
           >
              <Zap size={18} fill="currentColor" /> Initialize Neural Engine
           </button>
           <a 
             href="https://ai.google.dev/gemini-api/docs/billing" 
             target="_blank" 
             rel="noreferrer"
             className="text-xs font-bold text-zinc-600 hover:text-zinc-400 flex items-center gap-2 transition-colors"
           >
              Learn about paid billing <ExternalLink size={12} />
           </a>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4 overflow-hidden">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6 gap-4">
        <div>
          <h2 className="text-3xl font-black text-white tracking-tighter flex items-center gap-3">
             <VideoIcon className="text-red-500" /> Video Architect Studio
          </h2>
          <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest">Autonomous Visual Synthesis</p>
        </div>

        <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800 shadow-inner">
          <button onClick={() => setActiveTab('create')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'create' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}>Creative Hub</button>
          <button onClick={() => setActiveTab('edit')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'edit' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}>Timeline Orchestrator</button>
        </div>
      </header>

      <div className="flex-1 flex flex-col md:flex-row gap-6 min-h-0">
        {/* Sidebar: Asset Library */}
        <div className="w-full md:w-[320px] flex flex-col gap-6 shrink-0">
          <div className="flex-1 bg-zinc-900 border border-zinc-800 rounded-[2rem] p-6 flex flex-col shadow-2xl overflow-hidden">
             <div className="flex items-center justify-between mb-6">
                <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                  <Archive size={14} className="text-blue-500" /> Media Vault
                </h3>
                <button onClick={() => assetUploadRef.current?.click()} className="p-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 hover:text-white rounded-xl transition-all shadow-md active-press"><Plus size={16}/></button>
                <input type="file" ref={assetUploadRef} className="hidden" accept="video/*" onChange={handleAssetUpload} />
             </div>

             <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                {library.length === 0 ? (
                  <div className="h-40 flex flex-col items-center justify-center border-2 border-dashed border-zinc-800 rounded-3xl text-zinc-800 opacity-50">
                     <Film size={24} className="mb-2" />
                     <span className="text-[10px] font-black uppercase tracking-widest">Vault Empty</span>
                  </div>
                ) : (
                  library.map(asset => (
                    <div key={asset.id} className="group bg-zinc-950 border border-zinc-800 rounded-2xl p-2 hover:border-red-500/50 transition-all shadow-lg cursor-pointer" onClick={() => addClipToTimeline(asset)}>
                       <div className="aspect-video bg-zinc-900 rounded-xl mb-2 flex items-center justify-center relative overflow-hidden">
                          {asset.type === 'ai' ? <Sparkles size={16} className="text-red-500 opacity-20" /> : <Upload size={16} className="text-blue-500 opacity-20" />}
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                             <Plus size={24} className="text-white" />
                          </div>
                          <span className="absolute bottom-1 right-1 text-[8px] font-black px-1.5 py-0.5 bg-black/80 text-zinc-400 rounded uppercase">{asset.duration.toFixed(1)}s</span>
                       </div>
                       <p className="text-[10px] font-black text-zinc-500 truncate px-1 uppercase tracking-tighter">{asset.name}</p>
                    </div>
                  ))
                )}
             </div>

             {/* Create Form in Sidebar if in Create Tab */}
             {activeTab === 'create' && (
               <div className="mt-6 pt-6 border-t border-zinc-800 space-y-4 animate-fade-in">
                  <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="Action manifest (e.g. A robotic falcon flying over a digital city)..." className="w-full h-24 bg-zinc-950 border border-zinc-800 rounded-2xl p-4 outline-none text-white text-xs leading-relaxed focus:ring-1 focus:ring-red-500/50 transition-all resize-none" />
                  <div className="grid grid-cols-2 gap-2">
                     <select value={videoStyle} onChange={(e) => setVideoStyle(e.target.value)} className="bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-[10px] font-black uppercase text-zinc-500 appearance-none outline-none focus:border-zinc-600">
                        {VIDEO_STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                     </select>
                     <select value={cameraMotion} onChange={(e) => setCameraMotion(e.target.value)} className="bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-[10px] font-black uppercase text-zinc-500 appearance-none outline-none focus:border-zinc-600">
                        <option value="">Static Motion</option>
                        {CAMERA_MOTIONS.map(m => <option key={m} value={m}>{m}</option>)}
                     </select>
                  </div>
                  <button onClick={handleGenerate} disabled={isGenerating || !prompt} className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] transition-all shadow-xl flex items-center justify-center gap-2 active-press">
                    {isGenerating ? <Loader2 className="animate-spin" size={14} /> : <><Sparkles size={14} /> Synthesize Sequence</>}
                  </button>
               </div>
             )}
          </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col gap-6 min-w-0">
          {/* Top Panel: Preview / Generator */}
          <div className="flex-1 bg-zinc-950 rounded-[3rem] border border-zinc-800/50 flex items-center justify-center relative overflow-hidden shadow-inner group">
             {activeTab === 'create' ? (
               isGenerating ? (
                 <div className="flex flex-col items-center gap-6 text-red-500">
                    <Loader2 className="animate-spin w-16 h-16" strokeWidth={1} />
                    <div className="text-center space-y-2">
                       <p className="text-lg font-black text-white tracking-tighter uppercase animate-pulse">Encoding Latent Vision</p>
                       <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">{LOADING_MESSAGES[loadingMsgIndex]}</p>
                    </div>
                 </div>
               ) : generatedVideoUrl ? (
                 <video src={generatedVideoUrl} controls autoPlay loop className="w-full h-full object-contain" />
               ) : (
                 <div className="text-zinc-900 flex flex-col items-center gap-8 opacity-20">
                    <VideoIcon size={120} strokeWidth={1} />
                    <p className="font-black uppercase text-xl tracking-[0.5em]">Synthesis Engine Ready</p>
                 </div>
               )
             ) : (
               /* Sequencer Preview */
               <div className="w-full h-full relative bg-black flex items-center justify-center">
                  <video ref={previewVideoRef} className="max-h-full max-w-full" onEnded={() => setIsPlaying(false)} />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent pointer-events-none" />

                  {/* Transport Controls Overlay */}
                  <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-zinc-900/80 backdrop-blur-xl border border-zinc-800 rounded-[2rem] px-8 py-3 shadow-2xl opacity-0 group-hover:opacity-100 transition-opacity">
                     <button onClick={() => setCurrentTime(0)} className="text-zinc-500 hover:text-white transition-colors"><SkipBack size={20}/></button>
                     <button onClick={togglePlay} className="w-12 h-12 bg-red-600 hover:bg-red-500 rounded-full flex items-center justify-center text-white shadow-lg active-press transition-all">
                        {isPlaying ? <PauseCircle size={28} /> : <PlayCircle size={28} />}
                     </button>
                     <button onClick={() => setCurrentTime(totalDuration)} className="text-zinc-500 hover:text-white transition-colors"><SkipForward size={20}/></button>
                  </div>
               </div>
             )}
          </div>

          {/* Bottom Panel: Timeline */}
          <div className="h-[280px] bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex flex-col overflow-hidden shadow-2xl relative">
             <div className="px-8 py-4 border-b border-zinc-800 flex items-center justify-between bg-zinc-950/40 shrink-0">
                <div className="flex items-center gap-4">
                   <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Sequence Manifest</h3>
                   <div className="w-px h-4 bg-zinc-800" />
                   <span className="text-sm font-mono text-red-500 font-black">{currentTime.toFixed(2)}s <span className="text-zinc-700">/ {totalDuration.toFixed(2)}s</span></span>
                </div>
                <div className="flex items-center gap-4">
                   <div className="flex items-center gap-2">
                      <span className="text-[10px] font-bold text-zinc-600 uppercase">Zoom</span>
                      <input type="range" min="10" max="100" value={zoomLevel} onChange={(e) => setZoomLevel(parseInt(e.target.value))} className="w-24 accent-red-600" />
                   </div>
                </div>
             </div>

             {/* RULER / PLAYHEAD TRACK */}
             <div className="flex-1 relative overflow-hidden flex flex-col">
                {/* Horizontal Scroll Area */}
                <div 
                   ref={timelineRef}
                   className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar bg-zinc-950/20 relative"
                   onClick={handleTimelineClick}
                >
                   {/* Playhead Line */}
                   <div 
                      className="absolute top-0 bottom-0 w-[2px] bg-red-600 z-30 pointer-events-none shadow-[0_0_10px_rgba(239,68,68,0.5)]"
                      style={{ left: `${currentTime * zoomLevel}px` }}
                   >
                      <div className="w-4 h-4 bg-red-600 rounded-b-lg -ml-[7px] flex items-center justify-center">
                         <div className="w-[2px] h-2 bg-white/50" />
                      </div>
                   </div>

                   {/* Tracks Container */}
                   <div className="p-8 min-h-full" style={{ width: `${Math.max(1000, totalDuration * zoomLevel + 200)}px` }}>
                      <div className="space-y-4">
                         {/* Track 1: Video */}
                         <div className="h-24 bg-zinc-900/50 border border-zinc-800 rounded-2xl relative flex items-center group/track shadow-inner">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 flex items-center gap-2 opacity-20 pointer-events-none">
                               <VideoIcon size={14} />
                               <span className="text-[8px] font-black uppercase tracking-widest">Primary Visuals</span>
                            </div>

                            {timeline.map((clip) => (
                              <div 
                                 key={clip.id}
                                 className={`absolute h-16 rounded-xl border border-red-500/30 bg-red-900/10 flex flex-col justify-center px-4 overflow-hidden group/clip transition-all hover:bg-red-800/20 active:scale-[0.98] ${currentTime >= clip.timelineOffset && currentTime < clip.timelineOffset + clip.duration ? 'ring-2 ring-red-500 bg-red-800/30' : ''}`}
                                 style={{ left: `${clip.timelineOffset * zoomLevel}px`, width: `${clip.duration * zoomLevel}px` }}
                                 onClick={(e) => { e.stopPropagation(); setCurrentTime(clip.timelineOffset); }}
                              >
                                 <div className="flex items-center justify-between w-full">
                                    <span className="text-[10px] font-black text-white uppercase tracking-tighter truncate max-w-[80%]">{clip.name}</span>
                                    <button onClick={(e) => { e.stopPropagation(); removeClip(clip.id); }} className="opacity-0 group-hover/clip:opacity-100 p-1 text-zinc-500 hover:text-red-500 transition-all"><Trash2 size={12}/></button>
                                 </div>
                                 <div className="mt-1 flex items-center gap-1">
                                    <Film size={10} className="text-zinc-600" />
                                    <span className="text-[8px] text-zinc-500 font-bold uppercase">{clip.duration.toFixed(1)}s</span>
                                 </div>
                              </div>
                            ))}
                         </div>

                         {/* Track 2: Audio Placeholder */}
                         <div className="h-16 bg-zinc-900/30 border border-zinc-800/50 rounded-2xl relative flex items-center opacity-40">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 flex items-center gap-2 pointer-events-none">
                               <Volume2 size={14} />
                               <span className="text-[8px] font-black uppercase tracking-widest">Ambient Audio System</span>
                            </div>
                         </div>
                      </div>
                   </div>
                </div>
             </div>

             {/* Bottom Tool Bar */}
             <div className="px-8 py-3 bg-zinc-950 border-t border-zinc-800 shrink-0 flex items-center justify-between">
                <div className="flex items-center gap-6">
                   <div className="flex items-center gap-2 text-zinc-600">
                      <Layers size={14} />
                      <span className="text-[10px] font-bold uppercase tracking-widest">{timeline.length} Elements Linked</span>
                   </div>
                </div>
                {timeline.length > 0 && (
                   <button className="bg-white hover:bg-zinc-200 text-black px-6 py-2 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 transition-all shadow-xl active-press">
                      <Download size={14} /> Export Production
                   </button>
                )}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { generateShortsScript, generateThumbnail } from '../services/gemini';
import { 
  Loader2, 
  Smartphone, 
  Zap, 
  Clock, 
  Copy, 
  Maximize2, 
  Minimize2, 
  Sparkles, 
  Video, 
  FileText,
  Play,
  RotateCcw,
  BookOpen,
  ChevronDown,
  Check,
  History,
  Timer,
  ImageIcon,
  ChevronRight,
  Film,
  Scissors
} from 'lucide-react';
import { useAuth } from '../auth/AuthContext';
import { ToolType } from '../types';

const SHORT_STYLES = [
  { id: 'cinematic', label: 'Cinematic Story', desc: 'Dramatic lighting and high production feel.' },
  { id: 'kinetic', label: 'Kinetic Typography', desc: 'Fast text, energetic music, and bold colors.' },
  { id: 'documentary', label: 'Mini Docu', desc: 'Informative, fast facts, and clean b-roll.' },
  { id: 'sketch', label: 'POV Sketch', desc: 'Relatable characters and punchy dialogue.' },
  { id: 'educational', label: 'How-to Blast', desc: 'Rapid steps and satisfying results.' }
];

const SHORTS_PRESETS = [
  {
    id: 'ai-marketing-kinetic',
    label: 'AI Marketing (Kinetic)',
    topic: 'The Future of AI in Marketing: How agentic workflows are destroying traditional agencies.',
    style: 'kinetic',
    pacing: 'Fast' as const
  },
  {
    id: 'ranktica-tutorial',
    label: 'Ranktica Walkthrough',
    topic: 'How to use Ranktica AI for YouTube Automation (Quick Tutorial)',
    style: 'educational',
    pacing: 'Fast' as const
  },
  {
    id: 'productivity-hack',
    label: 'Productivity Hack',
    topic: 'One simple trick to double your output as a creator using AI agents.',
    style: 'kinetic',
    pacing: 'Fast' as const
  }
];

interface ShortsGeneratorProps {
  prefill?: { 
    topic?: string; 
    style?: string; 
    pacing?: 'Fast' | 'Standard';
    context?: string;
  };
}

export const ShortsGenerator: React.FC<ShortsGeneratorProps> = ({ prefill }) => {
  const [topic, setTopic] = useState(prefill?.topic || '');
  const [style, setStyle] = useState(prefill?.style || 'kinetic');
  const [pacing, setPacing] = useState<'Fast' | 'Standard'>(prefill?.pacing || 'Fast');
  const [script, setScript] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [teleprompterMode, setTeleprompterMode] = useState(false);
  const [showPresets, setShowPresets] = useState(false);
  const [prompterSpeed, setPrompterSpeed] = useState(1);
  const [visualPrompts, setVisualPrompts] = useState<Record<number, string | null>>({});
  const [loadingVisual, setLoadingVisual] = useState<number | null>(null);

  const [recentScripts, setRecentScripts] = useState<Array<{topic: string, script: string}>>([
    {
      topic: 'The Future of AI in Marketing',
      script: `[Visual: Hyper-fast montage of evolving marketing logos (Google, Meta, OpenAI)]
**The future of marketing isn't a tool you use... it's a team of agents that work for you while you sleep.**

[Visual: Dramatic transition to a 3D hologram of a neural network]
**By 2026, standard SaaS is dead. We're entering the era of "Autonomous Orchestration."**

[Visual: Screen recording of autonomous AI agents chatting and executing tasks]
**Step 1: Contextual Intelligence. AI won't just write a post; it will analyze your competitor's every move and counter-strike in real-time.**

[Visual: A "Revenue" chart skyrocketing with a robotic hand hovering over it]
**Step 2: Predictive ROI. Imagine knowing a campaign's conversion rate before you even spend a single dollar on ads.**

[Visual: Massive Pulsing red SUBSCRIBE button overlay]
**The autonomous shift is happening now. If you want the blueprint to the future, hit subscribe to join the Ranktica elite.**

[Visual: The Ranktica AI Logo glowing in a futuristic data center]
**Build your empire at Ranktica.ai today.**`
    }
  ]);

  const { incrementStat } = useAuth();
  const scriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (prefill) {
      if (prefill.topic) setTopic(prefill.topic);
      if (prefill.style) setStyle(prefill.style);
      if (prefill.pacing) setPacing(prefill.pacing);
    }
  }, [prefill]);

  const applyPreset = (p: typeof SHORTS_PRESETS[0]) => {
    setTopic(p.topic);
    setStyle(p.style);
    setPacing(p.pacing);
    setShowPresets(false);
  };

  const handleGenerate = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!topic.trim()) return;

    setIsGenerating(true);
    setScript('');
    setVisualPrompts({});

    try {
      let fullScript = '';
      await generateShortsScript(topic, style, pacing, (chunk) => {
        setScript(prev => prev + chunk);
        fullScript += chunk;
      });
      incrementStat('scriptsWritten');
      setRecentScripts(prev => [{topic, script: fullScript}, ...prev].slice(0, 5));
    } catch (err) {
      console.error(err);
      setScript("[Error generating script. Please check your connection and try again.]");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleVisualizeScene = async (index: number, visualPromptText: string) => {
    setLoadingVisual(index);
    try {
      const url = await generateThumbnail(visualPromptText, '3D Render', 'fast', '9:16', '1K');
      setVisualPrompts(prev => ({ ...prev, [index]: url }));
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingVisual(null);
    }
  };

  useEffect(() => {
    if (scriptEndRef.current && !teleprompterMode) {
      scriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [script, teleprompterMode]);

  const spokenTextOnly = script.replace(/\[.*?\]/g, '').trim();
  const wordCount = spokenTextOnly.split(/\s+/).filter(w => w.length > 0).length;
  const estSeconds = Math.round((wordCount / (pacing === 'Fast' ? 165 : 135)) * 60);
  const isOverLimit = estSeconds > 60;

  const copyScript = () => {
    navigator.clipboard.writeText(script);
    alert("Full script copied to clipboard!");
  };

  const reset = () => {
    setTopic('');
    setScript('');
    setVisualPrompts({});
  };

  return (
    <div className={`h-full flex flex-col gap-8 animate-fade-in ${teleprompterMode ? 'fixed inset-0 z-50 bg-[#09090b] p-8 md:p-20' : 'pb-10'}`}>

      {!teleprompterMode && (
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 shrink-0">
          <div>
            <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
              <Smartphone className="text-red-500" /> Shorts Architect
            </h2>
            <p className="text-zinc-400 text-sm font-medium">Design viral vertical content with high-retention logic.</p>
          </div>
          <div className="flex gap-2">
            <div className="relative">
              <button 
                onClick={() => setShowPresets(!showPresets)}
                className="flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-5 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all border border-zinc-800 active-press"
              >
                <BookOpen size={16} /> Blueprints <ChevronDown size={14} className={showPresets ? 'rotate-180 transition-transform' : 'transition-transform'} />
              </button>
              {showPresets && (
                <div className="absolute top-full right-0 mt-3 w-64 bg-[#0f0f12] border border-zinc-800 rounded-2xl shadow-2xl z-50 overflow-hidden animate-scale-in glass-morphism">
                   <div className="p-3 border-b border-zinc-800 text-[10px] font-black uppercase text-zinc-500 tracking-widest">Global Templates</div>
                   {SHORTS_PRESETS.map(p => (
                     <button
                       key={p.id}
                       onClick={() => applyPreset(p)}
                       className="w-full text-left px-4 py-3 hover:bg-red-500/10 hover:text-white text-zinc-400 text-sm font-medium border-b border-zinc-800 last:border-0 transition-colors"
                     >
                       {p.label}
                     </button>
                   ))}
                </div>
              )}
            </div>
            {script && (
              <button 
                onClick={reset}
                className="p-3 bg-zinc-900 border border-zinc-800 text-zinc-500 hover:text-white rounded-2xl transition-all active-press"
                title="Reset Canvas"
              >
                <RotateCcw size={18} />
              </button>
            )}
          </div>
        </header>
      )}

      <div className={`flex-1 flex flex-col md:flex-row gap-8 min-h-0 ${teleprompterMode ? 'w-full max-w-6xl mx-auto' : ''}`}>

        {/* Left: Input Panel */}
        {!teleprompterMode && (
          <div className="w-full md:w-[420px] flex flex-col gap-6 overflow-y-auto pr-3 custom-scrollbar pb-4">
            <form onSubmit={handleGenerate} className="bg-zinc-900 border border-zinc-800 p-8 rounded-[2.5rem] space-y-8 shadow-2xl relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
                 <Zap size={120} />
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Narrative Catalyst</label>
                <textarea
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  placeholder="Enter your hook or core concept (e.g. 5 secrets about the Roman Empire)..."
                  className="w-full h-36 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 focus:ring-2 focus:ring-red-500/50 outline-none transition-all resize-none text-white text-sm leading-relaxed shadow-inner"
                />
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Cinematic Identity</label>
                <div className="grid grid-cols-1 gap-2">
                  {SHORT_STYLES.map(s => (
                    <button
                      key={s.id}
                      type="button"
                      onClick={() => setStyle(s.id)}
                      className={`text-left p-4 rounded-2xl border transition-all ${style === s.id ? 'bg-red-500/10 border-red-500 text-red-500 shadow-lg scale-[1.02]' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                    >
                      <p className="text-xs font-black uppercase tracking-tight">{s.label}</p>
                      <p className="text-[10px] opacity-60 font-medium mt-1">{s.desc}</p>
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Temporal Flux (Pacing)</label>
                <div className="flex bg-zinc-950 border border-zinc-800 rounded-2xl p-1">
                  <button
                    type="button"
                    onClick={() => setPacing('Fast')}
                    className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${pacing === 'Fast' ? 'bg-zinc-800 text-white shadow-md' : 'text-zinc-500 hover:text-white'}`}
                  >
                    Aggressive
                  </button>
                  <button
                    type="button"
                    onClick={() => setPacing('Standard')}
                    className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${pacing === 'Standard' ? 'bg-zinc-800 text-white shadow-md' : 'text-zinc-500 hover:text-white'}`}
                  >
                    Steady
                  </button>
                </div>
              </div>

              <button
                type="submit"
                disabled={isGenerating || !topic}
                className={`w-full py-6 rounded-[2rem] font-black uppercase text-xs tracking-widest transition-all shadow-2xl flex items-center justify-center gap-3 active-press border-2 ${isGenerating ? 'bg-zinc-800 border-zinc-700 text-zinc-600' : 'bg-red-600 border-red-500 text-white shadow-red-600/30'}`}
              >
                {isGenerating ? <Loader2 className="animate-spin" size={22} /> : <><Sparkles size={20} fill="currentColor" /> Synthesize Script</>}
              </button>
            </form>

            {/* Recent History Panel */}
            {recentScripts.length > 0 && (
              <div className="bg-zinc-900 border border-zinc-800 p-6 rounded-[2.5rem] shadow-xl">
                 <h3 className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-4 flex items-center gap-2">
                    <History size={14} /> Vault of Drafts
                 </h3>
                 <div className="space-y-2">
                    {recentScripts.map((s, i) => (
                      <button 
                        key={i}
                        onClick={() => { setTopic(s.topic); setScript(s.script); }}
                        className="w-full text-left p-3 rounded-xl bg-zinc-950 border border-zinc-800 hover:border-red-500/30 transition-all group"
                      >
                         <p className="text-xs font-bold text-zinc-300 truncate group-hover:text-white">{s.topic}</p>
                         <p className="text-[9px] text-zinc-600 font-medium uppercase tracking-tighter">Latent Copy</p>
                      </button>
                    ))}
                 </div>
              </div>
            )}
          </div>
        )}

        {/* Right: Output Stage */}
        <div className={`flex-1 flex flex-col gap-6 min-w-0 transition-all duration-500`}>

          {/* Enhanced Stats Bar */}
          {script && !teleprompterMode && (
            <div className="flex items-center gap-6 bg-zinc-900 border border-zinc-800 p-5 rounded-[2rem] shadow-inner shrink-0 overflow-x-auto custom-scrollbar no-scrollbar">
               <div className="flex items-center gap-2 shrink-0">
                  <Clock size={16} className={isOverLimit ? 'text-red-500' : 'text-green-500'} />
                  <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">Est. Duration</span>
                    <span className={`text-sm font-black ${isOverLimit ? 'text-red-500' : 'text-white'}`}>{estSeconds}s {isOverLimit && '(LIMIT EXCEEDED)'}</span>
                  </div>
               </div>
               <div className="w-px h-8 bg-zinc-800 shrink-0"></div>
               <div className="flex items-center gap-2 shrink-0">
                  <FileText size={16} className="text-blue-500" />
                  <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">Linguistic Mass</span>
                    <span className="text-sm font-black text-white">{wordCount} Units</span>
                  </div>
               </div>
               <div className="ml-auto flex gap-3 shrink-0">
                  <button onClick={copyScript} className="p-3 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 hover:text-white rounded-2xl transition-all border border-zinc-700" title="Clone to Buffer"><Copy size={18} /></button>
                  <button onClick={() => setTeleprompterMode(true)} className="flex items-center gap-2 px-5 py-3 bg-zinc-800 hover:bg-zinc-700 text-white rounded-2xl transition-all border border-zinc-700 font-black uppercase text-[10px] tracking-widest" title="Open Vision Hub">
                    <Maximize2 size={14} /> Teleprompter
                  </button>
                  <button className="flex items-center gap-2 px-6 py-3 bg-white hover:bg-zinc-200 text-black rounded-2xl transition-all shadow-xl font-black uppercase text-[10px] tracking-[0.2em] active-press">
                    <Film size={14} /> Enter Studio
                  </button>
               </div>
            </div>
          )}

          <div className={`flex-1 bg-zinc-950 border border-zinc-900 rounded-[3rem] shadow-inner relative overflow-hidden group flex flex-col ${teleprompterMode ? 'border-none' : ''}`}>

             {teleprompterMode && (
               <div className="shrink-0 flex items-center justify-between mb-12 animate-fade-in">
                  <div className="flex items-center gap-5">
                     <div className="w-14 h-14 bg-red-600 rounded-full flex items-center justify-center animate-pulse shadow-[0_0_30px_rgba(239,68,68,0.3)]">
                        <Play size={28} fill="white" className="ml-1" />
                     </div>
                     <div>
                        <h3 className="text-3xl font-black uppercase tracking-[0.3em] text-white">Retinal Scan</h3>
                        <div className="flex items-center gap-4 mt-2">
                           <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1.5"><Timer size={12} /> Velocity Multiplier:</span>
                           <div className="flex gap-1.5">
                              {[1, 1.2, 1.5, 2].map(s => (
                                <button 
                                  key={s} 
                                  onClick={() => setPrompterSpeed(s)}
                                  className={`px-3 py-1 rounded-lg text-[10px] font-black transition-all border ${prompterSpeed === s ? 'bg-red-600 border-red-500 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'}`}
                                >
                                  {s}x
                                </button>
                              ))}
                           </div>
                        </div>
                     </div>
                  </div>
                  <button 
                    onClick={() => setTeleprompterMode(false)}
                    className="p-5 bg-zinc-900 border border-zinc-800 text-white rounded-3xl hover:bg-zinc-800 transition-all active-press"
                  >
                     <Minimize2 size={32} />
                  </button>
               </div>
             )}

             <div className="flex-1 overflow-y-auto p-8 md:p-14 custom-scrollbar">
                {!script && !isGenerating ? (
                   <div className="h-full flex flex-col items-center justify-center text-zinc-800 gap-8 opacity-40">
                      <div className="w-48 h-48 rounded-[3rem] border-4 border-dashed border-zinc-900 flex items-center justify-center">
                         <Smartphone size={100} strokeWidth={1} />
                      </div>
                      <div className="text-center space-y-2">
                        <p className="font-black uppercase text-base tracking-[0.5em]">Terminal Idling</p>
                        <p className="text-[10px] font-bold tracking-widest uppercase opacity-60">Initialize parameters to begin narrative synthesis</p>
                      </div>
                   </div>
                ) : isGenerating && !script ? (
                   <div className="h-full flex flex-col items-center justify-center gap-10 text-red-500">
                      <div className="relative">
                         <Loader2 className="animate-spin w-24 h-24" strokeWidth={1} />
                         <div className="absolute inset-0 bg-red-500 blur-[80px] opacity-10 animate-pulse"></div>
                      </div>
                      <div className="text-center space-y-3">
                        <p className="text-2xl font-black text-white tracking-tighter animate-pulse uppercase">Compressing Narrative</p>
                        <p className="text-[10px] text-zinc-500 font-black tracking-widest uppercase">Consulting Retention Algorithm</p>
                      </div>
                   </div>
                ) : (
                   <div className={`${teleprompterMode ? 'max-w-5xl mx-auto text-6xl md:text-8xl font-black leading-tight space-y-20 pb-80' : 'text-xl font-bold leading-relaxed space-y-8'} text-zinc-100 transition-all duration-300`}>
                      {script.split(/(\[.*?\])/g).map((part, i) => (
                        part.startsWith('[') ? (
                          <div key={i} className="flex flex-col gap-6 mb-4 animate-scale-in">
                            <div className={`flex items-center gap-4 bg-red-600/10 text-red-500 border border-red-600/20 rounded-3xl w-fit ${teleprompterMode ? 'px-12 py-6 text-3xl' : 'px-5 py-2.5 text-[11px] uppercase tracking-widest font-black'}`}>
                               <Video size={teleprompterMode ? 32 : 16} />
                               {part.slice(1, -1)}
                               {!teleprompterMode && (
                                 <button 
                                   onClick={() => handleVisualizeScene(i, part.slice(1, -1))}
                                   disabled={loadingVisual === i}
                                   className="ml-6 p-1.5 hover:bg-red-600/20 rounded-xl transition-all group/vis"
                                   title="Neural Visual Reference"
                                 >
                                   {loadingVisual === i ? <Loader2 size={14} className="animate-spin" /> : <ImageIcon size={14} className="group-hover/vis:scale-110 transition-transform" />}
                                 </button>
                               )}
                            </div>
                            {visualPrompts[i] && !teleprompterMode && (
                              <div className="w-full max-w-[200px] aspect-[9/16] rounded-[2rem] overflow-hidden border-2 border-zinc-800 bg-zinc-900 shadow-2xl animate-scale-in relative group/ref">
                                 <img src={visualPrompts[i]!} className="w-full h-full object-cover group-hover/ref:scale-110 transition-transform duration-700" alt="Scene Ref" />
                                 <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover/ref:opacity-100 transition-opacity flex items-end p-4">
                                    <span className="text-[8px] font-black text-white uppercase tracking-widest">Scene Ref Generated</span>
                                 </div>
                              </div>
                            )}
                          </div>
                        ) : (
                          <p key={i} className={`whitespace-pre-wrap ${teleprompterMode ? 'drop-shadow-[0_10px_20px_rgba(0,0,0,0.5)]' : ''}`}>{part}</p>
                        )
                      ))}
                      <div ref={scriptEndRef} />
                   </div>
                )}
             </div>

             {/* Dynamic Bottom Gradient for Teleprompter */}
             {teleprompterMode && (
                <div className="absolute bottom-0 left-0 right-0 h-80 bg-gradient-to-t from-[#09090b] via-[#09090b]/80 to-transparent pointer-events-none z-10"></div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

