const VIDEO_BLUEPRINTS = [
  {
    id: 'robotic-hummingbird',
    label: 'Cybernetic Nature',
    prompt: 'A robotic hummingbird with iridescent metallic feathers sipping glowing nectar from a liquid crystal flower.',
    style: 'Cinematic Movie',
    motion: 'Slow Pan Right',
    lighting: 'Golden Hour',
