    style: 'Cyberpunk Neon',
    motion: 'Dolly Zoom In',
    lighting: 'Bioluminescent',
    lens: 'Anamorphic 40mm'
  },
  {
    id: 'abstract-neural',
    label: 'Neural Flux',
    prompt: 'Visual representation of artificial intelligence thinking, glowing synapses and flowing data streams in 3D space.',
    style: '3D Octane Render',
    motion: 'Static',
    lighting: 'Volumetric',
    lens: 'Macro Lens Detail'
  }
];

interface LibraryAsset {
  id: string;
  url: string;
  name: string;
  type: 'ai' | 'upload';
  duration: number;
}

interface TimelineClip {
  id: string;
  assetId: string;
  url: string;
  name: string;
  duration: number;
  timelineOffset: number; // Seconds from start
}

export const VideoStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'create' | 'edit'>('create');
  const [hasApiKey, setHasApiKey] = useState(false);
  const [checkingKey, setCheckingKey] = useState(true);

  // --- LIBRARY STATE ---
  const [library, setLibrary] = useState<LibraryAsset[]>([]);

  // --- GENERATOR STATE ---
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('1080p');
  const [startImage, setStartImage] = useState<string | null>(null);
  const [cameraMotion, setCameraMotion] = useState('');
  const [videoStyle, setVideoStyle] = useState('Cinematic Movie');
  const [lightingStyle, setLightingStyle] = useState('');
  const [lensSpec, setLensSpec] = useState('');

  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const assetUploadRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [zoomLevel, setZoomLevel] = useState(20); // pixels per second
  const timelineRef = useRef<HTMLDivElement>(null);
  const previewVideoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      setCheckingKey(true);
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
      setCheckingKey(false);
    };
    checkKey();
  }, []);

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 6000);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const totalDuration = useMemo(() => {
    return timeline.reduce((max, clip) => Math.max(max, clip.timelineOffset + clip.duration), 0);
  }, [timeline]);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true); 
    }
  };

  const applyBlueprint = (bp: typeof VIDEO_BLUEPRINTS[0]) => {
    setPrompt(bp.prompt);
    setVideoStyle(bp.style);
    setCameraMotion(bp.motion);
    setLightingStyle(bp.lighting || '');
    setLensSpec(bp.lens || '');
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey) {
      await handleSelectKey();
      return;
    }

    setIsGenerating(true);
    setGeneratedVideoUrl(null);

    const technicalPrompt = `A ${videoStyle.toLowerCase()} of ${prompt}. ${cameraMotion ? `Camera motion: ${cameraMotion}.` : ''} ${lightingStyle ? `Lighting: ${lightingStyle}.` : ''} ${lensSpec ? `Captured with ${lensSpec}.` : ''} Ultra high fidelity, 5 second cinematic sequence, 8k textures.`;

    try {
      const url = await generateVideo(technicalPrompt, aspectRatio, startImage || undefined, resolution);
      if (url) {
        setGeneratedVideoUrl(url);
        addAssetToLibrary(url, `AI Sequence ${library.length + 1}`, 'ai');
      }
    } catch (error: any) {
      console.error(error);
      if (error.message?.includes("Requested entity was not found")) {
        setHasApiKey(false);
        alert("Paid API Key not found. Please select a valid key from a billed project.");
      } else {
        alert("Generation failed. Please try again.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const addAssetToLibrary = (url: string, name: string, type: 'ai' | 'upload') => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const newAsset: LibraryAsset = {
        id: Math.random().toString(36).substring(2, 11),
        url,
        name,
        type,
        duration: tempVid.duration || 5
      };
      setLibrary(prev => [newAsset, ...prev]);
    };
  };

  const handleAssetUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      addAssetToLibrary(url, file.name, 'upload');
    }
  };

  const addClipToTimeline = (asset: LibraryAsset) => {
    const newClip: TimelineClip = {
      id: Math.random().toString(36).substring(2, 11),
      assetId: asset.id,
      url: asset.url,
      name: asset.name,
      duration: asset.duration,
      timelineOffset: totalDuration
    };
    setTimeline(prev => [...prev, newClip]);
    setActiveTab('edit');
  };

  const removeClip = (id: string) => {
    setTimeline(prev => {
      const filtered = prev.filter(c => c.id !== id);
      let offset = 0;
      return filtered.map(c => {
        const item = { ...c, timelineOffset: offset };
        offset += c.duration;
        return item;
      });
    });
  };

  const togglePlay = () => setIsPlaying(!isPlaying);

  useEffect(() => {
    let animationFrameId: number;
    if (isPlaying) {
      const startTime = performance.now();
      const initialCurrentTime = currentTime;
      const animate = (now: number) => {
        const delta = (now - startTime) / 1000;
        const next = initialCurrentTime + delta;
        if (next >= totalDuration) {
          setIsPlaying(false);
          setCurrentTime(totalDuration);
        } else {
          setCurrentTime(next);
          animationFrameId = requestAnimationFrame(animate);
        }
      };
      animationFrameId = requestAnimationFrame(animate);
    }
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  useEffect(() => {
    if (previewVideoRef.current) {
      const activeClip = timeline.find(c => 
        currentTime >= c.timelineOffset && 
        currentTime < c.timelineOffset + c.duration
      );
      if (activeClip) {
        if (previewVideoRef.current.src !== activeClip.url) {
          previewVideoRef.current.src = activeClip.url;
        }
        const internalTime = currentTime - activeClip.timelineOffset;
        if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.2) {
          previewVideoRef.current.currentTime = internalTime;
        }
      } else {
        previewVideoRef.current.src = "";
      }
    }
  }, [currentTime, timeline]);

  const handleTimelineClick = (e: React.MouseEvent) => {
    if (!timelineRef.current) return;
    const rect = timelineRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left + timelineRef.current.scrollLeft;
    setCurrentTime(Math.max(0, Math.min(x / zoomLevel, totalDuration)));
  };

  if (checkingKey) {
    return (
      <div className="h-full flex items-center justify-center">
        <Loader2 className="animate-spin text-red-500" size={48} />
      </div>
    );
  }

  if (!hasApiKey) {
    return (
      <div className="h-[calc(100vh-6rem)] flex flex-col items-center justify-center animate-fade-in space-y-8">
        <div className="w-32 h-32 bg-zinc-900 rounded-[2.5rem] flex items-center justify-center border border-zinc-800 shadow-2xl relative overflow-hidden group">
           <div className="absolute inset-0 bg-red-600/5 group-hover:bg-red-600/10 transition-colors"></div>
           <Lock size={48} className="text-red-500 relative z-10" />
        </div>
        <div className="text-center space-y-3 max-w-md">
           <h2 className="text-3xl font-black text-white uppercase tracking-tighter">Engine Locked</h2>
           <p className="text-zinc-500 font-medium">
             Video generation via Veo requires a paid API key from a Google Cloud project with billing enabled.
           </p>
        </div>
        <div className="flex flex-col items-center gap-4 w-full">
           <button 
             onClick={handleSelectKey}
             className="bg-red-600 hover:bg-red-500 text-white px-10 py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-red-600/20 transition-all active-press flex items-center gap-2"
           >
              <Zap size={18} fill="currentColor" /> Initialize Neural Engine
           </button>
           <a 
             href="https://ai.google.dev/gemini-api/docs/billing" 
             target="_blank" 
             rel="noreferrer"
             className="text-xs font-bold text-zinc-600 hover:text-zinc-400 flex items-center gap-2 transition-colors"
           >
              Learn about paid billing <ExternalLink size={12} />
           </a>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4 overflow-hidden">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6 gap-4">
        <div>
          <h2 className="text-3xl font-black text-white tracking-tighter flex items-center gap-3">
             <VideoIcon className="text-red-500" /> Video Architect Studio
          </h2>
          <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest">Autonomous Visual Synthesis</p>
        </div>

        <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800 shadow-inner">
          <button onClick={() => setActiveTab('create')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'create' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}>Creative Hub</button>
          <button onClick={() => setActiveTab('edit')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'edit' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}>Timeline Orchestrator</button>
        </div>
      </header>

      <div className="flex-1 flex flex-col md:flex-row gap-6 min-h-0">
        {/* Sidebar: Asset Library & Generation */}
        <div className="w-full md:w-[320px] flex flex-col gap-6 shrink-0">
          <div className="flex-1 bg-zinc-900 border border-zinc-800 rounded-[2rem] p-6 flex flex-col shadow-2xl overflow-hidden">

             <div className="flex items-center justify-between mb-4">
                <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                  <Star size={14} className="text-yellow-500" /> Neural Blueprints
                </h3>
             </div>

             <div className="grid grid-cols-1 gap-2 mb-6">
                {VIDEO_BLUEPRINTS.map(bp => (
                  <button 
                    key={bp.id}
                    onClick={() => applyBlueprint(bp)}
                    className="w-full text-left p-3 bg-zinc-950 border border-zinc-800 rounded-xl hover:border-red-500/30 transition-all group"
                  >
                     <div className="flex justify-between items-center mb-1">
                        <span className="text-[9px] font-black text-zinc-400 uppercase tracking-tighter">{bp.label}</span>
                        <ChevronRight size={10} className="text-zinc-700 group-hover:translate-x-1 transition-transform" />
                     </div>
                     <p className="text-[10px] text-zinc-600 line-clamp-1 italic">"{bp.prompt}"</p>
                  </button>
                ))}
             </div>

             <div className="flex items-center justify-between mb-4">
                <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                  <Archive size={14} className="text-blue-500" /> Media Vault
                </h3>
                <button onClick={() => assetUploadRef.current?.click()} className="p-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 hover:text-white rounded-xl transition-all shadow-md active-press"><Plus size={16}/></button>
                <input type="file" ref={assetUploadRef} className="hidden" accept="video/*" onChange={handleAssetUpload} />
             </div>

             <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                {library.length === 0 ? (
                  <div className="h-20 flex flex-col items-center justify-center border-2 border-dashed border-zinc-800 rounded-2xl text-zinc-800 opacity-50">
                     <Film size={20} className="mb-1" />
                     <span className="text-[8px] font-black uppercase tracking-widest">Vault Empty</span>
                  </div>
                ) : (
                  library.map(asset => (
                    <div key={asset.id} className="group bg-zinc-950 border border-zinc-800 rounded-2xl p-2 hover:border-red-500/50 transition-all shadow-lg cursor-pointer" onClick={() => addClipToTimeline(asset)}>
                       <div className="aspect-video bg-zinc-900 rounded-xl mb-2 flex items-center justify-center relative overflow-hidden">
                          {asset.type === 'ai' ? <Sparkles size={16} className="text-red-500 opacity-20" /> : <Upload size={16} className="text-blue-500 opacity-20" />}
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                             <Plus size={24} className="text-white" />
                          </div>
                          <span className="absolute bottom-1 right-1 text-[8px] font-black px-1.5 py-0.5 bg-black/80 text-zinc-400 rounded uppercase">{asset.duration.toFixed(1)}s</span>
                       </div>
                       <p className="text-[10px] font-black text-zinc-500 truncate px-1 uppercase tracking-tighter">{asset.name}</p>
                    </div>
                  ))
                )}
             </div>

             {activeTab === 'create' && (
               <div className="mt-6 pt-6 border-t border-zinc-800 space-y-4 animate-fade-in">
                  <div className="space-y-2">
                     <label className="text-[9px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Action Manifest</label>
                     <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="Action manifest (e.g. A robotic falcon flying over a digital city)..." className="w-full h-24 bg-zinc-950 border border-zinc-800 rounded-2xl p-4 outline-none text-white text-xs leading-relaxed focus:ring-1 focus:ring-red-500/50 transition-all resize-none" />
                  </div>

                  <div className="grid grid-cols-2 gap-2">
                     <div className="space-y-1">
                        <label className="text-[8px] font-black text-zinc-700 uppercase block ml-1">Style</label>
                        <select value={videoStyle} onChange={(e) => setVideoStyle(e.target.value)} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-2 py-2 text-[9px] font-black uppercase text-zinc-500 appearance-none outline-none focus:border-zinc-600">
                           {VIDEO_STYLES.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                     </div>
                     <div className="space-y-1">
                        <label className="text-[8px] font-black text-zinc-700 uppercase block ml-1">Motion</label>
                        <select value={cameraMotion} onChange={(e) => setCameraMotion(e.target.value)} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-2 py-2 text-[9px] font-black uppercase text-zinc-500 appearance-none outline-none focus:border-zinc-600">
                           <option value="">Static Motion</option>
                           {CAMERA_MOTIONS.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                     </div>
                  </div>

                  <div className="grid grid-cols-2 gap-2">
                     <div className="space-y-1">
                        <label className="text-[8px] font-black text-zinc-700 uppercase block ml-1 flex items-center gap-1"><Sun size={8}/> Lighting</label>
                        <input value={lightingStyle} onChange={(e) => setLightingStyle(e.target.value)} placeholder="e.g. Golden Hour" className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-[9px] font-bold text-white outline-none focus:border-zinc-600" />
                     </div>
                     <div className="space-y-1">
                        <label className="text-[8px] font-black text-zinc-700 uppercase block ml-1 flex items-center gap-1"><Focus size={8}/> Optics</label>
                        <input value={lensSpec} onChange={(e) => setLensSpec(e.target.value)} placeholder="e.g. 35mm Prime" className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-[9px] font-bold text-white outline-none focus:border-zinc-600" />
                     </div>
                  </div>

                  <button onClick={handleGenerate} disabled={isGenerating || !prompt} className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] transition-all shadow-xl flex items-center justify-center gap-2 active-press">
                    {isGenerating ? <Loader2 className="animate-spin" size={14} /> : <><Sparkles size={14} /> Synthesize Sequence</>}
                  </button>
               </div>
             )}
          </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col gap-6 min-w-0">
          {/* Top Panel: Preview / Generator */}
          <div className="flex-1 bg-zinc-950 rounded-[3rem] border border-zinc-800/50 flex items-center justify-center relative overflow-hidden shadow-inner group">
             {activeTab === 'create' ? (
               isGenerating ? (
                 <div className="flex flex-col items-center gap-6 text-red-500">
                    <Loader2 className="animate-spin w-16 h-16" strokeWidth={1} />
                    <div className="text-center space-y-2">
                       <p className="text-lg font-black text-white tracking-tighter uppercase animate-pulse">Encoding Latent Vision</p>
                       <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest">{LOADING_MESSAGES[loadingMsgIndex]}</p>
                    </div>
                 </div>
               ) : generatedVideoUrl ? (
                 <video src={generatedVideoUrl} controls autoPlay loop className="w-full h-full object-contain" />
               ) : (
                 <div className="text-zinc-900 flex flex-col items-center gap-8 opacity-20">
                    <VideoIcon size={120} strokeWidth={1} />
                    <p className="font-black uppercase text-xl tracking-[0.5em]">Synthesis Engine Ready</p>
                 </div>
               )
             ) : (
               /* Sequencer Preview */
               <div className="w-full h-full relative bg-black flex items-center justify-center">
                  <video ref={previewVideoRef} className="max-h-full max-w-full" onEnded={() => setIsPlaying(false)} />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent pointer-events-none" />

                  {/* Transport Controls Overlay */}
