                   >
                      <div className="w-4 h-4 bg-red-600 rounded-b-lg -ml-[7px] flex items-center justify-center">
                         <div className="w-[2px] h-2 bg-white/50" />
                      </div>
                   </div>

                   {/* Tracks Container */}
                   <div className="p-8 min-h-full" style={{ width: `${Math.max(1000, totalDuration * zoomLevel + 200)}px` }}>
                      <div className="space-y-4">
                         {/* Track 1: Video */}
                         <div className="h-24 bg-zinc-900/50 border border-zinc-800 rounded-2xl relative flex items-center group/track shadow-inner">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 flex items-center gap-2 opacity-20 pointer-events-none">
                               <VideoIcon size={14} />
                               <span className="text-[8px] font-black uppercase tracking-widest">Primary Visuals</span>
