};

// --- Scripting ---
export const generateScriptStream = async (title: string, tone: string, scriptType: string, instructions: string, onChunk: (text: string) => void) => {
  const ai = getAiClient();
  const prompt = `Write a high-retention YouTube script for the video title: "${title}". 
  TONE: ${tone}. 
  STRUCTURE: ${scriptType}. 
  INSTRUCTIONS: ${instructions}`;

  const result = await ai.models.generateContentStream({
    model: MODEL_NAMES.TEXT_SMART,
    contents: prompt,
    config: { systemInstruction: SYSTEM_INSTRUCTIONS.SCRIPT }
  });
  for await (const chunk of result) { if (chunk.text) onChunk(chunk.text); }
};

// --- SEO ---
export const generateSeo = async (topic: string): Promise<SeoResult> => {
