import React, { useState, useRef, useEffect } from 'react';
import { generateSpeech, generateMultiSpeakerSpeech, transcribeAudio } from '../services/gemini';
import { 
  Loader2, 
  Mic, 
  Volume2, 
  FileAudio, 
  PlayCircle, 
  Upload, 
  FileText, 
  X, 
  Music, 
  Download, 
  Check, 
  Sparkles, 
  AudioLines, 
  Zap, 
  Copy,
  Activity,
  Waves,
  Ear,
  Radio,
  ChevronRight,
  Smile,
  Angry,
  Frown,
  Brain,
  MessageSquare,
  Users,
  VolumeX,
  History,
  Trash2
} from 'lucide-react';

const VOICES = [
  { id: 'Kore', label: 'Kore', desc: 'Warm & Professional (Female)', profile: 'Corporate/Vlog', tone: 'Balanced' },
  { id: 'Puck', label: 'Puck', desc: 'Energetic & Youthful (Male)', profile: 'Shorts/Gaming', tone: 'High-Pitch' },
  { id: 'Charon', label: 'Charon', desc: 'Deep & Authoritative (Male)', profile: 'Documentary/Tech', tone: 'Basso' },
  { id: 'Fenrir', label: 'Fenrir', desc: 'Steady & Neutral (Male)', profile: 'Tutorial/News', tone: 'Flat' },
  { id: 'Zephyr', label: 'Zephyr', desc: 'Friendly & Conversational (Female)', profile: 'Lifestyle/Chat', tone: 'Bright' }
];

const EMOTIONAL_MODES = [
  { id: 'cheerful', label: 'Cheerful', icon: <Smile size={14} />, prompt: 'Say cheerfully: ' },
  { id: 'serious', label: 'Authoritative', icon: <Brain size={14} />, prompt: 'Say with absolute authority: ' },
  { id: 'urgent', label: 'High Urgency', icon: <Zap size={14} />, prompt: 'Say urgently and rapidly: ' },
  { id: 'excited', label: 'Viral Hype', icon: <Sparkles size={14} />, prompt: 'Say with massive excitement and energy: ' },
  { id: 'whisper', label: 'ASMR / Quiet', icon: <Ear size={14} />, prompt: 'Whisper this: ' }
];

interface AudioStudioProps {
  prefill?: { text?: string; voice?: string };
}

export const AudioStudio: React.FC<AudioStudioProps> = ({ prefill }) => {
  const [tab, setTab] = useState<'tts' | 'stt' | 'dialogue'>('tts');
  const [text, setText] = useState(prefill?.text || '');
  const [voice, setVoice] = useState(prefill?.voice || 'Kore');
  const [selectedEmotion, setSelectedEmotion] = useState<string | null>(null);

  const [audioResult, setAudioResult] = useState<'playing' | 'ready' | null>(null);
  const [transcription, setTranscription] = useState('');
  const [loading, setLoading] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [downloadBlob, setDownloadBlob] = useState<Blob | null>(null);
  const [audioHistory, setAudioHistory] = useState<Array<{id: string, text: string, voice: string, date: number}>>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    if (prefill?.text) setText(prefill.text);
    if (prefill?.voice) setVoice(prefill.voice);
  }, [prefill]);

  // WAV encoding helper
  const encodeWAV = (samples: Float32Array, sampleRate: number) => {
    const buffer = new ArrayBuffer(44 + samples.length * 2);
    const view = new DataView(buffer);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) view.setUint8(offset + i, string.charCodeAt(i));
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 32 + samples.length * 2, true);
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, sampleRate, true);
    view.setUint32(28, sampleRate * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(36, 'data');
    view.setUint32(40, samples.length * 2, true);
    let offset = 44;
    for (let i = 0; i < samples.length; i++, offset += 2) {
      let s = Math.max(-1, Math.min(1, samples[i]));
      view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
    }
    return new Blob([view], { type: 'audio/wav' });
  };

  const handleTTS = async () => {
    if (!text) return;
    setLoading(true);
    setDownloadBlob(null);
    try {
      const emotionPrefix = selectedEmotion ? EMOTIONAL_MODES.find(e => e.id === selectedEmotion)?.prompt : '';
      const base64 = await generateSpeech(emotionPrefix + text, voice);
      if (base64) {
        await playAndPrepareAudio(base64);
        setAudioHistory(prev => [{ id: Date.now().toString(), text, voice, date: Date.now() }, ...prev].slice(0, 10));
      }
    } catch (e) {
      console.error(e);
      alert("Neural synthesis failed.");
    } finally {
      setLoading(false);
    }
  };

  const playAndPrepareAudio = async (base64: string) => {
    try {
      const binaryString = atob(base64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

      const audioContext = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
      const dataInt16 = new Int16Array(bytes.buffer);
      const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;

      const wavBlob = encodeWAV(channelData, 24000);
      setDownloadBlob(wavBlob);

      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
      setAudioResult("playing"); 
      setTimeout(() => setAudioResult("ready"), buffer.duration * 1000);
    } catch (e) { console.error("Audio engine error", e); }
  };

  const handleDownload = () => {
    if (!downloadBlob) return;
    const url = URL.createObjectURL(downloadBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `ranktica_narration_${Date.now()}.wav`;
    a.click();
  };

  return (
    <div className="max-w-7xl mx-auto space-y-12 animate-fade-in pb-20 relative">
      <div className="text-center space-y-4 py-8">
        <div className="inline-flex items-center justify-center p-4 rounded-[2.5rem] bg-purple-500/10 text-purple-500 mb-2 border border-purple-500/20 shadow-2xl">
           <Waves size={44} strokeWidth={2.5} />
        </div>
        <h2 className="text-5xl font-black bg-gradient-to-br from-white to-zinc-600 bg-clip-text text-transparent tracking-tighter">
          Neural Narrator Studio
        </h2>
        <p className="text-zinc-400 text-lg font-medium max-w-2xl mx-auto">
          Convert high-retention scripts into cinematic voiceovers with deep emotional mapping and authoritative vocal profiles.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left: Configuration & Voices */}
        <div className="lg:col-span-4 space-y-6">
           <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 shadow-2xl space-y-8">
              <div className="flex items-center justify-between border-b border-zinc-800 pb-4">
                 <h3 className="text-xs font-black uppercase tracking-[0.2em] text-white">Voice Architect</h3>
                 <Ear size={16} className="text-purple-500" />
              </div>

              <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                 {VOICES.map(v => (
                    <button
                      key={v.id}
                      onClick={() => setVoice(v.id)}
                      className={`w-full text-left p-4 rounded-2xl border transition-all relative overflow-hidden group ${voice === v.id ? 'bg-purple-600/10 border-purple-500 text-white' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                    >
                       <div className="flex justify-between items-center mb-1">
                          <span className="text-xs font-black uppercase tracking-widest">{v.label}</span>
                          <span className={`text-[8px] font-black px-1.5 py-0.5 rounded border ${voice === v.id ? 'bg-purple-500 border-purple-400 text-white' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}>{v.tone}</span>
                       </div>
                       <p className="text-[10px] font-bold text-zinc-600 mb-1 group-hover:text-zinc-400 transition-colors">{v.profile}</p>
                       <p className="text-[11px] opacity-60 italic group-hover:opacity-100 transition-opacity line-clamp-1">{v.desc}</p>
                       {voice === v.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-purple-500"></div>}
                    </button>
                 ))}
              </div>

              <div className="w-full h-px bg-zinc-800"></div>

              <div className="space-y-4">
                 <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Emotional Blueprint</label>
                 <div className="grid grid-cols-1 gap-2">
                    {EMOTIONAL_MODES.map(e => (
                      <button
                        key={e.id}
                        onClick={() => setSelectedEmotion(selectedEmotion === e.id ? null : e.id)}
                        className={`flex items-center gap-3 px-4 py-3 rounded-xl border transition-all text-[10px] font-black uppercase tracking-widest ${selectedEmotion === e.id ? 'bg-purple-600 border-purple-500 text-white' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                      >
                        {e.icon} {e.label}
                      </button>
                    ))}
                 </div>
              </div>
           </div>

           {/* Synthesis History */}
           {audioHistory.length > 0 && (
             <div className="bg-zinc-900 border border-zinc-800 rounded-[2rem] p-6 shadow-xl flex flex-col gap-4">
