              <div className="bg-zinc-900/50 border border-zinc-800 p-8 rounded-[2.5rem] flex items-start gap-5 group">
                 <div className="p-4 bg-purple-500/10 rounded-[1.5rem] text-purple-400 shrink-0 group-hover:scale-110 transition-transform">
                    <Brain size={24} />
                 </div>
                 <div>
                    <h4 className="text-[11px] font-black text-white uppercase tracking-[0.2em] mb-2">Neural Identity Mapping</h4>
                    <p className="text-[12px] text-zinc-500 leading-relaxed font-medium">
                      "Using 'Charon' for technical breakdowns increases viewer authority perception by 18% based on acoustic resonance studies."
                    </p>
                 </div>
              </div>
              <div className="bg-zinc-900/50 border border-zinc-800 p-8 rounded-[2.5rem] flex items-start gap-5 group">
                 <div className="p-4 bg-red-500/10 rounded-[1.5rem] text-red-500 shrink-0 group-hover:scale-110 transition-transform">
                    <Activity size={24} />
