export const ThumbnailGenerator: React.FC = () => {
  const [mode, setMode] = useState<'generate' | 'edit'>('generate');
  const [genMode, setGenMode] = useState<'fast' | 'pro' | 'artistic'>('fast');
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('Photorealistic');
  const [aspectRatio, setAspectRatio] = useState('16:9');
  const [imageSize, setImageSize] = useState('1K');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // Visual Modifiers
  const [lighting, setLighting] = useState('');
  const [optics, setOptics] = useState('');
  const [texture, setTexture] = useState('');
  const [mood, setMood] = useState('');
  const [composition, setComposition] = useState('');
  const [colorGrade, setColorGrade] = useState('');
  const [viralMagnetism, setViralMagnetism] = useState('');

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const { incrementStat } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Computed final prompt for preview
  const [builtPrompt, setBuiltPrompt] = useState('');

  useEffect(() => {
    if (!prompt) {
      setBuiltPrompt('');
      return;
    }

    const parts = [];
    parts.push(`A high-impact ${style.toLowerCase()} YouTube thumbnail masterpiece of ${prompt}`);

    if (viralMagnetism) parts.push(`with ${viralMagnetism.toLowerCase()}`);
    if (composition) parts.push(`utilizing a ${composition.toLowerCase()}`);
    if (optics) parts.push(`captured via ${optics.toLowerCase()}`);
    if (lighting) parts.push(`illuminated by ${lighting.toLowerCase()}`);
    if (texture) parts.push(`featuring ${texture.toLowerCase()}`);
    if (colorGrade) parts.push(`color graded with ${colorGrade.toLowerCase()}`);
    if (mood) parts.push(`designed for a ${mood.toLowerCase()} vibe`);

    parts.push(`Ultra-high resolution, extreme sharp focus, cinematic lighting, 8k resolution, photorealistic textures, high-CTR appeal, pattern interrupt.`);

    const final = parts.join('. ') + '.';
    setBuiltPrompt(final);
  }, [prompt, style, lighting, optics, texture, mood, composition, colorGrade, viralMagnetism]);

  const applyBlueprint = (bp: typeof THUMBNAIL_BLUEPRINTS[0]) => {
    setPrompt(bp.prompt);
    setStyle(bp.style);
    setLighting(bp.lighting);
    setOptics(bp.optics);
    setMood(bp.mood);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && mode === 'generate') return;

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(builtPrompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
        }
        url = await editImage(uploadedImage, prompt);
      }
      setResultImage(url);
      incrementStat('thumbnailsCreated');
    } catch (err: any) {
      console.error(err);
