export const optimizeScriptPacing = async (currentScript: string, onChunk: (text: string) => void) => {
  const ai = getAiClient();
  const result = await ai.models.generateContentStream({
    model: MODEL_NAMES.TEXT_FAST,
    contents: `RE-PACE AND OPTIMIZE FOR RETENTION: \n\n${currentScript}`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.PACING_OPTIMIZER
    }
  });

  for await (const chunk of result) {
    if (chunk.text) onChunk(chunk.text);
  }
};

