      await handleSelectKey();
      return;
    }

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(prompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
        }
        url = await editImage(uploadedImage, prompt);
      }
      setResultImage(url);
      incrementStat('thumbnailsCreated');
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        setHasApiKey(false);
        alert("API Key not found or project missing billing. Resetting key selection.");
      } else {
