                        <p className="text-[11px] opacity-60 italic group-hover:opacity-100 transition-opacity line-clamp-1">{v.desc}</p>
                        {voice === v.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-purple-500 shadow-[2px_0_10px_rgba(168,85,247,0.4)]"></div>}
                      </button>
