              {mode === 'narration' && (
                <>
                  <div className="w-full h-px bg-zinc-800"></div>
                  <div className="space-y-4">
                    <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Emotional Blueprint</label>
                    <div className="grid grid-cols-1 gap-2">
                        {EMOTIONS.map(e => (
                          <button
