    const checkKey = async () => {
      setCheckingKey(true);
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
      setCheckingKey(false);
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && mode === 'generate') return;

    if (genMode === 'pro' && !hasApiKey) {
      await handleSelectKey();
      return;
    }

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(prompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
