          <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-[#09090b] to-transparent pointer-events-none"></div>
        </div>

        {/* Retention Analytics Footer */}
        {script && (
          <div className="bg-zinc-900 border border-zinc-800 rounded-[2rem] p-6 shadow-xl flex flex-wrap items-center gap-8 animate-scale-in">
