const THUMBNAIL_BLUEPRINTS = [
  {
    id: 'ranktica-cyber',
    label: 'Ranktica AI: Cyberpunk',
    prompt: 'A high-fidelity cinematic visualization of Ranktica AI neural core. A futuristic creator workstation glowing with holographic YouTube data, algorithmic waves in neon red and orange, 8k resolution, octane render, tech-noir aesthetic.',
