    style: 'Photorealistic'
  }
];

interface ThumbnailGeneratorProps {
  prefill?: { title?: string; context?: string; style?: string };
}

export const ThumbnailGenerator: React.FC<ThumbnailGeneratorProps> = ({ prefill }) => {
  const [mode, setMode] = useState<'generate' | 'edit'>('generate');
  const [genMode, setGenMode] = useState<'fast' | 'pro'>('fast');

  // Initialize with Ranktica Cyberpunk blueprint as the default state
  const [prompt, setPrompt] = useState(prefill?.context || prefill?.title || THUMBNAIL_BLUEPRINTS[0].prompt);
  const [style, setStyle] = useState(prefill?.style || THUMBNAIL_BLUEPRINTS[0].style);

  const [aspectRatio, setAspectRatio] = useState<any>('16:9');
  const [imageSize, setImageSize] = useState<any>('1K');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [hasApiKey, setHasApiKey] = useState(false);
  const [checkingKey, setCheckingKey] = useState(true);

  const { incrementStat } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (prefill) {
      if (prefill.context || prefill.title) setPrompt(prefill.context || prefill.title || '');
      if (prefill.style) setStyle(prefill.style);
    }
  }, [prefill]);

  useEffect(() => {
    const checkKey = async () => {
      setCheckingKey(true);
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
      setCheckingKey(false);
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const applyRankticaStyle = () => {
    setPrompt(THUMBNAIL_BLUEPRINTS[0].prompt);
    setStyle(THUMBNAIL_BLUEPRINTS[0].style);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && mode === 'generate') return;

    if (genMode === 'pro' && !hasApiKey) {
      await handleSelectKey();
      return;
    }

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(prompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
        }
        url = await editImage(uploadedImage, prompt);
      }
      setResultImage(url);
      incrementStat('thumbnailsCreated');
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        setHasApiKey(false);
        alert("API Key not found or project missing billing. Resetting key selection.");
      } else {
        alert("Generation failed. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleEnhance = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      const enhanced = await enhanceThumbnailPrompt(prompt);
      setPrompt(enhanced);
    } catch (e) {
      console.error(e);
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6 gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
             <ImageIcon className="text-orange-500" /> Thumbnail Studio
          </h2>
          <p className="text-zinc-400 text-sm font-medium">Professional High-CTR Visual Architecture</p>
        </div>

        <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800 self-start md:self-center">
          <button 
            onClick={() => setMode('generate')}
            className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === 'generate' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
          >
            Concept Studio
          </button>
          <button 
            onClick={() => setMode('edit')}
            className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === 'edit' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
          >
            Neural Edit
          </button>
        </div>
      </header>

      <div className="flex-1 flex flex-col md:flex-row gap-8 min-h-0">
        {/* LEFT PANEL: CONFIG */}
        <div className="w-full md:w-[400px] flex flex-col gap-6 overflow-y-auto pr-3 custom-scrollbar pb-10">

          <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 space-y-8 shadow-2xl relative overflow-hidden">

             {/* Neural Blueprints */}
             {mode === 'generate' && (
               <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] flex items-center gap-2">
                      <Star size={12} className="text-yellow-500" /> Neural Blueprints
                    </h3>
                    <button 
                      onClick={applyRankticaStyle}
                      className="text-[9px] font-black text-red-500 hover:text-red-400 flex items-center gap-1.5 transition-colors uppercase tracking-widest"
                    >
                      <ShieldCheck size={12} /> Apply Ranktica Core
                    </button>
                  </div>
                  <div className="grid grid-cols-1 gap-2">
                     {THUMBNAIL_BLUEPRINTS.map(bp => (
                       <button
                         key={bp.id}
                         onClick={() => { setPrompt(bp.prompt); setStyle(bp.style); }}
                         className={`w-full text-left p-3 bg-zinc-950 border rounded-xl transition-all group ${prompt === bp.prompt ? 'border-orange-500/50 bg-orange-500/5' : 'border-zinc-800 hover:border-orange-500/30'}`}
                       >
                          <div className="flex justify-between items-center mb-1">
                             <span className="text-[9px] font-black text-zinc-400 uppercase tracking-tighter">{bp.label}</span>
                             <ChevronRight size={10} className="text-zinc-700 group-hover:translate-x-1 transition-transform" />
                          </div>
                          <p className="text-[10px] text-zinc-600 line-clamp-1">{bp.prompt}</p>
                       </button>
                     ))}
                  </div>
               </div>
             )}

             <div className="w-full h-px bg-zinc-800"></div>

             {/* Engine Selection */}
             {mode === 'generate' && (
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Inference Engine</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button
                      type="button"
                      onClick={() => setGenMode('fast')}
                      className={`py-3 rounded-xl text-[10px] font-black uppercase border transition-all flex items-center justify-center gap-2 ${genMode === 'fast' ? 'bg-blue-500/10 border-blue-500 text-blue-500 shadow-lg' : 'bg-zinc-950 border-zinc-800 text-zinc-600 hover:border-zinc-700'}`}
                    >
                      <Zap size={14} /> Flash Core
                    </button>
                    <button
                      type="button"
                      onClick={() => setGenMode('pro')}
                      className={`py-3 rounded-xl text-[10px] font-black uppercase border transition-all flex items-center justify-center gap-2 ${genMode === 'pro' ? 'bg-orange-500/10 border-orange-500 text-orange-500 shadow-lg' : 'bg-zinc-950 border-zinc-800 text-zinc-600 hover:border-zinc-700'}`}
                    >
                      <Sparkles size={14} /> Pro Vision
                    </button>
                  </div>
               </div>
             )}

             {mode === 'edit' && (
               <div className="space-y-4">
                 <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Latent Reference</label>
                 <div 
                   onClick={() => fileInputRef.current?.click()}
                   className="w-full h-44 border-2 border-dashed border-zinc-800 hover:border-orange-500/50 rounded-3xl flex flex-col items-center justify-center cursor-pointer bg-zinc-950/50 transition-all relative group overflow-hidden"
                 >
                   {uploadedImage ? (
                     <img src={uploadedImage} alt="Upload" className="h-full w-full object-contain p-4 group-hover:scale-105 transition-transform" />
                   ) : (
                     <div className="text-zinc-500 flex flex-col items-center gap-3">
                       <Upload size={32} />
                       <span className="text-[10px] font-black uppercase tracking-widest">Select Reference</span>
                     </div>
                   )}
                 </div>
                 <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
               </div>
             )}

             {/* Prompt Area */}
             <div className="space-y-4">
               <div className="flex items-center justify-between">
                 <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Concept Manifest</label>
                 {mode === 'generate' && (
                   <button 
                     type="button"
                     onClick={handleEnhance}
                     disabled={enhancing || !prompt}
                     className="text-[9px] font-black uppercase text-purple-400 hover:text-purple-300 transition-colors flex items-center gap-1 disabled:opacity-30"
                   >
                     {enhancing ? <Loader2 size={10} className="animate-spin" /> : <Sparkles size={10} />}
                     Neural Expansion
                   </button>
                 )}
               </div>
               <textarea
                 value={prompt}
                 onChange={(e) => setPrompt(e.target.value)}
                 placeholder={mode === 'generate' ? "What is the primary subject? (e.g. A high-tech gaming setup)..." : "Describe modification (e.g. Add realistic rain drops)..."}
                 className="w-full h-32 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 focus:ring-2 focus:ring-orange-500/50 outline-none transition-all resize-none text-white text-sm leading-relaxed shadow-inner"
               />
             </div>

