                    download={`ranktica_thumb_${Date.now()}.png`}
                    className="bg-white hover:bg-zinc-200 text-black px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-[0.2em] flex items-center gap-2 shadow-2xl transition-all active-press"
                  >
                     <Download size={16} /> Export Master
                  </a>
               </div>

               {/* Engine Badge */}
               <div className="absolute top-8 right-8 bg-black/60 backdrop-blur-md px-4 py-2 rounded-full border border-zinc-800 text-[10px] font-black text-orange-500 uppercase tracking-[0.2em] flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-orange-500 animate-pulse"></div>
                  {genMode === 'fast' ? 'Low Latency' : `Ultra ${imageSize}`}
               </div>
             </div>
           ) : (
             <div className="text-zinc-800 flex flex-col items-center gap-8 opacity-30 animate-pulse">
                <div className="w-56 h-56 rounded-[3.5rem] border-4 border-dashed border-zinc-800 flex items-center justify-center relative">
                   <ImageIcon size={96} strokeWidth={1} />
                   <div className="absolute -bottom-4 -right-4 bg-zinc-900 p-4 rounded-3xl border border-zinc-800">
                      <Sparkles size={24} />
                   </div>
                </div>
                <div className="text-center space-y-3">
                   <p className="font-black uppercase text-lg tracking-[0.4em]">Visual Latency Dormant</p>
                   <p className="text-[10px] font-bold tracking-widest uppercase opacity-60 flex items-center justify-center gap-2">
                      Configure technical parameters <ArrowRight size={10} /> Execute generation
                   </p>
                </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
