interface ScriptWriterProps {
  prefill?: { title?: string; text?: string; context?: string };
  onNavigate?: (tool: ToolType, payload?: any) => void;
}

export const ScriptWriter: React.FC<ScriptWriterProps> = ({ prefill, onNavigate }) => {
  const [title, setTitle] = useState('The Future of AI in Marketing');
  const [instructions, setInstructions] = useState('');
  const [tone, setTone] = useState('Fast-paced & Hype');
  const [scriptType, setScriptType] = useState('storytelling');
  const [script, setScript] = useState(AI_MARKETING_FUTURE_SAMPLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [showPresets, setShowPresets] = useState(false);
  const [library, setLibrary] = useState<Array<{title: string, content: string, date: number}>>([
    { title: 'AI Marketing Future', date: Date.now(), content: AI_MARKETING_FUTURE_SAMPLE }
  ]);

  const scriptEndRef = useRef<HTMLDivElement>(null);
  const instructionsRef = useRef<HTMLTextAreaElement>(null);
  const { incrementStat } = useAuth();

  const analytics = useMemo(() => {
    if (!script) return { pacing: 0, density: 0, cues: 0, heatmap: [] };
    const segments = script.split('\n\n');
    const heatmap = segments.map((s, i) => {
       const cueCount = (s.match(/\[Visual:.*?\]/g) || []).length;
       const intensity = cueCount > 0 ? 90 + Math.random() * 10 : 40 + Math.random() * 20;
       return { name: `S${i+1}`, Heat: intensity };
    });

    const cueCount = (script.match(/\[Visual:.*?\]/g) || []).length;
    const words = script.replace(/\[.*?\]/g, '').split(/\s+/).filter(w => w.length > 0).length;
    const visualDensity = Math.min((cueCount / (words / 11)) * 100, 100); 
    const pacingVelocity = Math.min((words / 80) * 100, 100); // Higher velocity for shorter scripts

    return {
      pacing: Math.round(pacingVelocity),
      density: Math.round(visualDensity),
      cues: cueCount,
      heatmap
    };
  }, [script]);

  useEffect(() => {
    if (prefill) {
      if (prefill.title) setTitle(prefill.title);
      if (prefill.context) setInstructions(prefill.context);
    }
  }, [prefill]);

  const applyPreset = (p: typeof SCRIPT_PRESETS[0]) => {
    setTitle(p.title);
    setTone(p.tone);
    setScriptType(p.type);
    setInstructions(p.instructions);
    if (p.id === 'ai-marketing-2025-shift') {
      setScript(AI_MARKETING_FUTURE_SAMPLE);
    }
    setShowPresets(false);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;
    setIsGenerating(true);
    setScript('');
    try {
      let full = '';
      await generateScriptStream(title, tone, scriptType, instructions, (chunk) => {
        setScript(prev => prev + chunk);
        full += chunk;
      });
      setLibrary(prev => [{title, content: full, date: Date.now()}, ...prev].slice(0, 10));
      incrementStat('scriptsWritten');
    } catch (err) { console.error(err); } 
    finally { setIsGenerating(false); }
  };

  const handleOptimizePacing = async () => {
    if (!script) return;
    setIsOptimizing(true);
    const original = script;
    setScript('');
    try {
      await optimizeScriptPacing(original, (chunk) => {
        setScript(prev => prev + chunk);
      });
    } catch (err) { 
      console.error(err);
      setScript(original);
    } finally { setIsOptimizing(false); }
  };

  const handleNarrate = () => {
    if (!script) return;
    const spokenText = script.replace(/\[.*?\]/g, '').trim();
    onNavigate?.(ToolType.AUDIO, { text: spokenText });
  };

  const insertFormat = (startTag: string, endTag: string = '') => {
    const textarea = instructionsRef.current;
    if (!textarea) return;
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const newText = text.substring(0, start) + startTag + text.substring(start, end) + endTag + text.substring(end);
    setInstructions(newText);
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col md:flex-row gap-6 animate-fade-in pb-10">
      {/* Config Panel */}
      <div className="w-full md:w-[380px] space-y-6 flex flex-col shrink-0">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-black text-white mb-1">Script Architect</h2>
            <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest">Neural Pacing Engine</p>
          </div>
          <div className="relative">
            <button onClick={() => setShowPresets(!showPresets)} className="flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all border border-zinc-800 active-press">
              <BookOpen size={14} /> Blueprints <ChevronDown size={14} className={showPresets ? 'rotate-180' : ''} />
            </button>
            {showPresets && (
              <div className="absolute top-full right-0 mt-2 w-64 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-2xl z-50 overflow-hidden animate-scale-in glass-morphism">
                <div className="p-3 border-b border-zinc-800 text-[10px] font-black uppercase text-zinc-500 tracking-widest">Select Template</div>
                {SCRIPT_PRESETS.map(p => (
                  <button key={p.id} onClick={() => applyPreset(p)} className="w-full text-left px-4 py-3 hover:bg-red-500/10 hover:text-white text-zinc-400 text-sm font-medium border-b border-zinc-800 last:border-0 transition-colors">
                    {p.label}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        <form onSubmit={handleGenerate} className="space-y-4 p-6 bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex-1 flex flex-col shadow-2xl">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Headline</label>
            <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-red-500/50 outline-none text-white font-medium" />
          </div>

          <div className="space-y-2 flex-1 flex flex-col">
            <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Logic Layers</label>
            <div className="flex-1 flex flex-col bg-zinc-950 border border-zinc-800 rounded-2xl overflow-hidden focus-within:ring-2 focus-within:ring-red-500/50 transition-all">
              <div className="flex items-center gap-1 p-2 border-b border-zinc-800 bg-zinc-900/40">
                <button type="button" onClick={() => insertFormat('**', '**')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded"><Bold size={14} /></button>
                <button type="button" onClick={() => insertFormat('*', '*')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded"><Italic size={14} /></button>
                <div className="w-px h-4 bg-zinc-800 mx-1"></div>
                <button type="button" onClick={() => insertFormat('# ')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded"><Heading1 size={14} /></button>
                <button type="button" onClick={() => insertFormat('- ')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded"><List size={14} /></button>
              </div>
              <textarea ref={instructionsRef} value={instructions} onChange={(e) => setInstructions(e.target.value)} placeholder="Narrative flow constraints..." className="w-full h-full min-h-[120px] bg-transparent p-5 outline-none resize-none text-white text-sm leading-relaxed" />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <select value={scriptType} onChange={(e) => setScriptType(e.target.value)} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-white appearance-none">
              <option value="storytelling">Storytelling</option>
              <option value="tutorial">Tutorial</option>
              <option value="standard">Standard</option>
            </select>
            <select value={tone} onChange={(e) => setTone(e.target.value)} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-white appearance-none">
              <option>Fast-paced & Hype</option>
              <option>Engaging & Fun</option>
              <option>Professional</option>
            </select>
          </div>

          <button type="submit" disabled={isGenerating || !title} className={`w-full py-5 rounded-[1.5rem] font-black uppercase text-xs tracking-widest flex items-center justify-center gap-3 active-press ${isGenerating ? 'bg-zinc-800 text-zinc-600' : 'bg-red-600 hover:bg-red-500 text-white shadow-xl shadow-red-600/20'}`}>
            {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <><Sparkles size={18} fill="currentColor" /> Synthesize Script</>}
          </button>
        </form>

        {/* Pacing Heatmap */}
        {script && (
          <div className="bg-zinc-900 border border-zinc-800 p-6 rounded-[2.5rem] shadow-xl overflow-hidden animate-scale-in">
             <div className="flex items-center justify-between mb-4">
                <h3 className="text-[10px] font-black text-zinc-600 uppercase tracking-widest flex items-center gap-2">
                  <Activity size={14} className="text-red-500" /> Retention Curve Sim
                </h3>
                <span className="text-[9px] font-bold text-green-500 px-2 py-0.5 rounded-full border border-green-500/20">Optimal Bias</span>
             </div>
             <div className="h-24 w-full">
                <ResponsiveContainer width="100%" height="100%">
                   <AreaChart data={analytics.heatmap}>
                      <defs>
                        <linearGradient id="colorHeat" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3}/>
                          <stop offset="95%" stopColor="#ef4444" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <Area type="monotone" dataKey="Heat" stroke="#ef4444" fillOpacity={1} fill="url(#colorHeat)" strokeWidth={2} />
                   </AreaChart>
                </ResponsiveContainer>
             </div>
             <p className="text-[9px] text-zinc-600 font-bold uppercase mt-2 text-center tracking-tighter">Timeline Intensity Monitor</p>
          </div>
        )}
      </div>

      {/* Output Stage */}
      <div className="flex-1 flex flex-col gap-6">
        <div className="flex-1 flex flex-col bg-zinc-900 border border-zinc-800 rounded-[3rem] overflow-hidden shadow-2xl relative">
          <div className="p-6 border-b border-zinc-800 flex justify-between items-center bg-zinc-950/50 backdrop-blur-md">
            <div className="flex items-center gap-3">
               <div className="w-2 h-2 rounded-full bg-red-600 animate-pulse shadow-[0_0_10px_rgba(239,68,68,0.5)]"></div>
               <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Live Production manifest</span>
            </div>
            <div className="flex gap-2">
              {script && (
                 <button onClick={handleOptimizePacing} disabled={isOptimizing} className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-tighter bg-purple-600 hover:bg-purple-500 text-white px-4 py-2 rounded-xl transition-all shadow-lg shadow-purple-500/20 active-press ${isOptimizing ? 'opacity-50 animate-pulse' : ''}`}>
                   {isOptimizing ? <Loader2 size={12} className="animate-spin" /> : <Wind size={12} />} Optimize Pacing
                 </button>
              )}
              {script && (
                 <button onClick={handleNarrate} className="flex items-center gap-2 text-[10px] font-black uppercase tracking-tighter bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-xl transition-all shadow-lg shadow-indigo-600/20 active-press">
                   <Mic size={12} /> Speak Manifest
                 </button>
              )}
              {script && (
                 <button onClick={() => onNavigate?.(ToolType.SEO, { title, text: script })} className="flex items-center gap-2 text-[10px] font-black uppercase tracking-tighter bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-xl transition-all shadow-lg active-press">
                   <Search size={12} /> Get Tags
                 </button>
              )}
              {script && !isGenerating && (
                 <button onClick={() => { navigator.clipboard.writeText(script); alert("Script copied!"); }} className="flex items-center gap-2 text-[10px] font-black uppercase tracking-tighter bg-zinc-800 hover:bg-zinc-700 text-white px-4 py-2 rounded-xl transition-all border border-zinc-700">
                   <Copy size={12} /> Copy
                 </button>
              )}
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-12 bg-[#09090b] custom-scrollbar">
             {script ? (
               <div className="max-w-3xl mx-auto animate-fade-in">
                  <pre className="whitespace-pre-wrap font-sans text-xl md:text-2xl font-bold leading-relaxed text-zinc-100 tracking-tight">
                    {script}
                  </pre>
                  <div ref={scriptEndRef} />
               </div>
             ) : (
