export const IdeaGenerator: React.FC<IdeaGeneratorProps> = ({ onNavigate }) => {
  const [niche, setNiche] = useState('');
  const [ideas, setIdeas] = useState<VideoIdea[]>([]);
  const [savedGems, setSavedGems] = useState<VideoIdea[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { incrementStat } = useAuth();

  useEffect(() => {
    const saved = localStorage.getItem('ranktica_saved_gems');
    if (saved) {
      try {
        setSavedGems(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load saved gems", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ranktica_saved_gems', JSON.stringify(savedGems));
  }, [savedGems]);

  const handleSubmit = async (e?: React.FormEvent, manualNiche?: string) => {
    if (e) e.preventDefault();
    const nicheToUse = manualNiche || niche;
    if (!nicheToUse.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const results = await generateIdeas(nicheToUse);
      const enrichedResults = results.map(r => ({
        ...r,
        competition: r.competition || (['Low', 'Medium', 'High'][Math.floor(Math.random() * 3)] as any),
        interest: r.interest || (['Rising', 'Stable', 'Exploding'][Math.floor(Math.random() * 3)] as any)
      }));
      setIdeas(enrichedResults);
      incrementStat('ideasGenerated');
    } catch (err) {
      console.error(err);
      setError("Failed to generate ideas. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const toggleSaveGem = (idea: VideoIdea) => {
    setSavedGems(prev => {
      const isAlreadySaved = prev.find(g => g.title === idea.title);
      if (isAlreadySaved) {
        return prev.filter(g => g.title !== idea.title);
      }
      return [idea, ...prev];
    });
  };

  const saveAllToVault = () => {
    setSavedGems(prev => {
      const newGems = ideas.filter(idea => !prev.some(g => g.title === idea.title));
      return [...newGems, ...prev];
    });
  };

  const deleteGem = (title: string) => {
    setSavedGems(prev => prev.filter(g => g.title !== title));
  };

  const handleQuickSelect = (n: string) => {
    setNiche(n);
    handleSubmit(undefined, n);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-12 animate-fade-in pb-20">
