              {script && (
                 <button onClick={handleNarrate} className="flex items-center gap-2 text-[10px] font-black uppercase tracking-tighter bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-xl transition-all shadow-lg shadow-indigo-600/20 active-press">
