const LOADING_MESSAGES = [
  "Dreaming of latent structures...",
  "Consulting cinematic logic cores...",
  "Synthesizing temporal coherence...",
  "Finalizing visual manifest...",
  "Encoding neural frames..."
];

export const VideoGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('Cinematic');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('1080p');

  const [loading, setLoading] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState(LOADING_MESSAGES[0]);
  const [resultVideo, setResultVideo] = useState<string | null>(null);
  const [hasApiKey, setHasApiKey] = useState(false);
  const [checkingKey, setCheckingKey] = useState(true);

  const [history, setHistory] = useState<Array<{prompt: string, url: string, date: number}>>([]);

  const { incrementStat } = useAuth();

  useEffect(() => {
    const checkKey = async () => {
      setCheckingKey(true);
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
      setCheckingKey(false);
    };
    checkKey();

    const savedHistory = localStorage.getItem('rt_video_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  useEffect(() => {
    localStorage.setItem('rt_video_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    let interval: any;
    if (loading) {
      interval = setInterval(() => {
        setLoadingMsg(LOADING_MESSAGES[Math.floor(Math.random() * LOADING_MESSAGES.length)]);
      }, 5000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;

    if (!hasApiKey) {
      await handleSelectKey();
      return;
    }

    setLoading(true);
    setResultVideo(null);

    const technicalPrompt = `Cinematic masterwork: ${prompt}. Artistic Style: ${style}. Ultra high fidelity, temporal consistency, 1080p textures.`;

    try {
      const url = await generateVideo(technicalPrompt, aspectRatio, undefined, resolution);
      if (url) {
        setResultVideo(url);
        setHistory(prev => [{ prompt, url, date: Date.now() }, ...prev].slice(0, 10));
        // Note: Stat increment omitted as videoCreated isn't in default UserStats, 
        // but we could use a generic trigger if needed.
      }
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        setHasApiKey(false);
        alert("API Key not found or project missing billing. Resetting key selection.");
      } else {
        alert("Generation failed. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  if (checkingKey) {
    return (
      <div className="h-full flex items-center justify-center">
        <Loader2 className="animate-spin text-red-500" size={48} />
      </div>
    );
  }

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-10">
      <header className="flex flex-col md:flex-row md:items-center justify-between py-6 border-b border-zinc-800 shrink-0 mb-8 gap-4">
        <div>
          <h2 className="text-4xl font-black text-white tracking-tighter flex items-center gap-4">
             <Clapperboard className="text-red-500" size={36} /> Video Generator
          </h2>
          <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest mt-1">Autonomous Neural Cinema</p>
        </div>
      </header>

      <div className="flex-1 flex flex-col lg:flex-row gap-10 min-h-0">
        {/* Control Panel */}
        <div className="w-full lg:w-[420px] flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar">
           <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 space-y-8 shadow-2xl relative overflow-hidden">

              {!hasApiKey ? (
                 <div className="bg-red-500/10 border border-red-500/20 p-6 rounded-3xl space-y-4">
                    <div className="flex items-start gap-3 text-red-500">
                       <Lock size={20} className="shrink-0 mt-1" />
                       <p className="text-xs font-bold leading-relaxed uppercase tracking-tight">
                         Engine Locked: Veo requires a paid Google Cloud project key.
                       </p>
                    </div>
                    <button 
                      onClick={handleSelectKey}
                      className="w-full bg-red-600 hover:bg-red-500 text-white py-4 rounded-2xl font-black uppercase text-xs tracking-widest transition-all active-press shadow-lg shadow-red-600/20"
                    >
                      Authorize Synthesis
                    </button>
                 </div>
              ) : (
                <form onSubmit={handleGenerate} className="space-y-8">
                   <div className="space-y-4">
                      <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block ml-1">Visual Manifest</label>
                      <textarea
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="Describe the action sequence (e.g. A futuristic samurai walking through a rainy Tokyo market in slow motion)..."
                        className="w-full h-40 bg-zinc-950 border border-zinc-800 rounded-3xl p-6 focus:ring-2 focus:ring-red-500/50 outline-none text-white text-sm leading-relaxed transition-all resize-none shadow-inner"
                      />
                   </div>

                   <div className="space-y-4">
                      <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block ml-1">Artistic Identity</label>
                      <div className="grid grid-cols-2 gap-3">
                         {VIDEO_STYLES.map(s => (
                           <button 
                             key={s.id}
                             type="button"
                             onClick={() => setStyle(s.id)}
                             className={`p-4 rounded-2xl border text-left transition-all group ${style === s.id ? 'bg-red-600 border-red-500 text-white shadow-xl' : 'bg-zinc-950 border-zinc-800 hover:border-zinc-700 text-zinc-500'}`}
                           >
                              <span className="block font-black text-[10px] uppercase group-hover:text-white transition-colors">{s.label}</span>
                              <span className="block text-[8px] opacity-60 font-bold group-hover:opacity-100 transition-opacity mt-0.5">{s.desc}</span>
                           </button>
                         ))}
                      </div>
                   </div>

                   <div className="grid grid-cols-2 gap-6 pt-4 border-t border-zinc-800/50">
                      <div className="space-y-3">
                        <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Canvas</label>
                        <div className="flex gap-2">
                           {ASPECT_RATIOS.map(ar => (
                             <button 
                                key={ar.id}
                                type="button"
                                onClick={() => setAspectRatio(ar.id as any)}
                                className={`p-4 rounded-2xl border transition-all ${aspectRatio === ar.id ? 'bg-white text-black border-white shadow-lg' : 'bg-zinc-950 border-zinc-800 text-zinc-600 hover:bg-zinc-800 hover:text-white'}`}
                             >
                                {ar.icon}
                             </button>
                           ))}
                        </div>
                      </div>

                      <div className="space-y-3">
                        <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Precision</label>
                        <select 
                           value={resolution}
                           onChange={(e) => setResolution(e.target.value as any)}
                           className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-4 py-4 text-xs font-bold text-white appearance-none cursor-pointer focus:ring-2 focus:ring-red-500/50 outline-none"
                        >
                           <option value="720p">720p Mobile</option>
                           <option value="1080p">1080p Master</option>
                        </select>
                      </div>
                   </div>

                   <button
                     type="submit"
                     disabled={loading || !prompt}
                     className={`w-full py-6 rounded-[2rem] font-black uppercase text-xs tracking-[0.3em] transition-all shadow-2xl flex items-center justify-center gap-4 active-press border-2 ${loading ? 'bg-zinc-800 border-zinc-700 text-zinc-600' : 'bg-red-600 border-red-500 text-white shadow-red-600/30'}`}
                   >
                     {loading ? <Loader2 className="animate-spin" size={20} /> : <><Zap size={20} fill="currentColor" /> Synthesize Visuals</>}
                   </button>
                </form>
              )}
           </div>

           {/* History */}
           {history.length > 0 && (
             <div className="bg-zinc-900/50 border border-zinc-800 rounded-[2.5rem] p-6 space-y-4">
                <div className="flex items-center justify-between px-2">
                   <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                      <History size={14} /> Latent Archives
                   </h3>
                   <button onClick={() => setHistory([])} className="text-zinc-700 hover:text-red-500 transition-colors"><Trash2 size={14}/></button>
                </div>
                <div className="space-y-3">
                   {history.map((h, i) => (
                      <button 
                        key={i} 
                        onClick={() => setResultVideo(h.url)}
                        className="w-full flex items-center gap-4 p-3 bg-zinc-950 border border-zinc-800 rounded-2xl hover:border-red-500/30 transition-all text-left group"
                      >
                         <div className="w-12 h-12 bg-zinc-900 rounded-xl flex items-center justify-center shrink-0 border border-zinc-800 group-hover:border-red-500/20">
                            <Film size={20} className="text-zinc-700 group-hover:text-red-500" />
