export const generateVideo = async (prompt: string, aspectRatio: string, imageBase64?: string, resolution: string = '1080p') => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const videoParams: any = {
    model: MODEL_NAMES.VIDEO_FAST,
    prompt: prompt,
    config: { 
      numberOfVideos: 1, 
      resolution: resolution as any, 
      aspectRatio: aspectRatio as any 
    }
  };
  if (imageBase64) videoParams.image = { imageBytes: imageBase64.split(',')[1], mimeType: 'image/png' };
  let operation = await ai.models.generateVideos(videoParams);
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }
  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) return null;
  const res = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await res.blob();
  return URL.createObjectURL(blob);
};

export const transcribeAudio = async (audioBlob: Blob) => {
  const ai = getAiClient();
  const reader = new FileReader();
  const base64 = await new Promise<string>((resolve) => {
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(audioBlob);
  });
  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_FAST,
    contents: { parts: [{ inlineData: { mimeType: audioBlob.type, data: base64 } }, { text: "Transcribe" }] }
  });
  return response.text || "";
};

// Fixed researchChat to extract grounding sources and handle multi-modal inputs correctly as per guidelines
export const researchChat = async (history: any[], message: string, image?: string, useThinking: boolean = false, tools: any = {}) => {
  const ai = getAiClient();
  const configuredTools: any[] = [];
  if (tools.search) configuredTools.push({ googleSearch: {} });
  if (tools.maps) configuredTools.push({ googleMaps: {} });

  const contentsParts: any[] = [];
  if (image) {
    contentsParts.push({ 
      inlineData: { 
        mimeType: 'image/png', 
        data: image.split(',')[1] 
      } 
    });
  }
  contentsParts.push({ text: message });

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_SMART,
    contents: { parts: contentsParts },
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.RESEARCH,
      tools: configuredTools.length > 0 ? configuredTools : undefined,
      thinkingConfig: useThinking ? { thinkingBudget: 4096 } : undefined
    }
  });

  // Extract mandatory grounding sources from groundingChunks
  const sources: Array<{ title: string; uri: string }> = [];
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (groundingChunks) {
    for (const chunk of groundingChunks) {
      if (chunk.web) {
        sources.push({ title: chunk.web.title, uri: chunk.web.uri });
      }
      if (chunk.maps) {
        sources.push({ title: chunk.maps.title, uri: chunk.maps.uri });
      }
    }
  }

  return { text: response.text || "", sources };
};

