interface ScriptWriterProps {
  prefill?: { title?: string; text?: string; context?: string };
  onNavigate?: (tool: ToolType, payload?: any) => void;
}

export const ScriptWriter: React.FC<ScriptWriterProps> = ({ prefill, onNavigate }) => {
  const [title, setTitle] = useState('The Future of AI in Marketing');
  const [instructions, setInstructions] = useState('');
  const [tone, setTone] = useState('Fast-paced & Hype');
  const [scriptType, setScriptType] = useState('storytelling');
  const [script, setScript] = useState(AI_MARKETING_FUTURE_SAMPLE);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [showPresets, setShowPresets] = useState(false);
  const [library, setLibrary] = useState<Array<{title: string, content: string, date: number}>>([
    { title: 'AI Marketing Future', date: Date.now(), content: AI_MARKETING_FUTURE_SAMPLE }
  ]);

  const scriptEndRef = useRef<HTMLDivElement>(null);
  const instructionsRef = useRef<HTMLTextAreaElement>(null);
  const { incrementStat } = useAuth();

  const analytics = useMemo(() => {
    if (!script) return { pacing: 0, density: 0, cues: 0, heatmap: [] };
    const segments = script.split('\n\n');
    const heatmap = segments.map((s, i) => {
       const cueCount = (s.match(/\[Visual:.*?\]/g) || []).length;
       const intensity = cueCount > 0 ? 90 + Math.random() * 10 : 40 + Math.random() * 20;
       return { name: `S${i+1}`, Heat: intensity };
    });

    const cueCount = (script.match(/\[Visual:.*?\]/g) || []).length;
    const words = script.replace(/\[.*?\]/g, '').split(/\s+/).filter(w => w.length > 0).length;
    const visualDensity = Math.min((cueCount / (words / 11)) * 100, 100); 
    const pacingVelocity = Math.min((words / 80) * 100, 100); // Higher velocity for shorter scripts

    return {
      pacing: Math.round(pacingVelocity),
      density: Math.round(visualDensity),
      cues: cueCount,
      heatmap
    };
  }, [script]);

  useEffect(() => {
    if (prefill) {
      if (prefill.title) setTitle(prefill.title);
      if (prefill.context) setInstructions(prefill.context);
    }
  }, [prefill]);

  const applyPreset = (p: typeof SCRIPT_PRESETS[0]) => {
    setTitle(p.title);
    setTone(p.tone);
    setScriptType(p.type);
    setInstructions(p.instructions);
    if (p.id === 'ai-marketing-2025-shift') {
      setScript(AI_MARKETING_FUTURE_SAMPLE);
    }
    setShowPresets(false);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;
    setIsGenerating(true);
    setScript('');
    try {
      let full = '';
      await generateScriptStream(title, tone, scriptType, instructions, (chunk) => {
        setScript(prev => prev + chunk);
        full += chunk;
      });
      setLibrary(prev => [{title, content: full, date: Date.now()}, ...prev].slice(0, 10));
      incrementStat('scriptsWritten');
    } catch (err) { console.error(err); } 
    finally { setIsGenerating(false); }
  };

  const handleOptimizePacing = async () => {
    if (!script) return;
    setIsOptimizing(true);
    const original = script;
    setScript('');
    try {
      await optimizeScriptPacing(original, (chunk) => {
        setScript(prev => prev + chunk);
      });
    } catch (err) { 
      console.error(err);
      setScript(original);
    } finally { setIsOptimizing(false); }
  };

  const handleNarrate = () => {
    if (!script) return;
    const spokenText = script.replace(/\[.*?\]/g, '').trim();
    onNavigate?.(ToolType.AUDIO, { text: spokenText });
  };

  const insertFormat = (startTag: string, endTag: string = '') => {
    const textarea = instructionsRef.current;
    if (!textarea) return;
    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const newText = text.substring(0, start) + startTag + text.substring(start, end) + endTag + text.substring(end);
    setInstructions(newText);
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col md:flex-row gap-6 animate-fade-in pb-10">
      {/* Config Panel */}
      <div className="w-full md:w-[380px] space-y-6 flex flex-col shrink-0">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-black text-white mb-1">Script Architect</h2>
            <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest">Neural Pacing Engine</p>
          </div>
          <div className="relative">
