import { GoogleGenAI, Type, Modality } from "@google/genai";
import { MODEL_NAMES, SYSTEM_INSTRUCTIONS } from '../constants';
import { 
  VideoIdea, 
  SeoResult, 
  OutreachResult, 
  SocialPost, 
  RepurposedContent, 
  KeywordMetrics, 
  TrendResult, 
  TitlePrediction, 
  ThumbnailRating, 
