                      <div className="w-12 h-12 rounded-full border-2 border-dashed border-zinc-800 flex items-center justify-center group-hover/add:scale-110 transition-transform">
                         <Plus size={24} />
                      </div>
                      <span className="text-[10px] font-black uppercase tracking-widest">Add Custom Step</span>
                   </button>
                </div>

                {/* Strategy Summary */}
                <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 space-y-6">
                   <div className="flex items-center gap-3">
                      <Target size={20} className="text-red-500" />
                      <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">Neural Strategy Breakdown</h3>
                   </div>
                   <div className="bg-zinc-950 border border-zinc-800 rounded-3xl p-6">
                      <p className="text-sm text-zinc-300 leading-relaxed font-medium italic">"{campaign.strategy}"</p>
