interface IdeaGeneratorProps {
  onNavigate?: (tool: ToolType, payload?: any) => void;
}

export const IdeaGenerator: React.FC<IdeaGeneratorProps> = ({ onNavigate }) => {
  const [niche, setNiche] = useState('');
  const [ideas, setIdeas] = useState<VideoIdea[]>([]);
  const [savedGems, setSavedGems] = useState<VideoIdea[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { incrementStat } = useAuth();

  useEffect(() => {
    const saved = localStorage.getItem('ranktica_saved_gems');
    if (saved) {
      try {
        setSavedGems(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load saved gems", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ranktica_saved_gems', JSON.stringify(savedGems));
  }, [savedGems]);

  const handleSubmit = async (e?: React.FormEvent, manualNiche?: string) => {
    if (e) e.preventDefault();
    const nicheToUse = manualNiche || niche;
    if (!nicheToUse.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const results = await generateIdeas(nicheToUse);
      const enrichedResults = results.map(r => ({
        ...r,
        competition: r.competition || (['Low', 'Medium', 'High'][Math.floor(Math.random() * 3)] as any),
        interest: r.interest || (['Rising', 'Stable', 'Exploding'][Math.floor(Math.random() * 3)] as any)
      }));
      setIdeas(enrichedResults);
      incrementStat('ideasGenerated');
    } catch (err) {
      console.error(err);
      setError("Failed to generate ideas. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const toggleSaveGem = (idea: VideoIdea) => {
    setSavedGems(prev => {
      const isAlreadySaved = prev.find(g => g.title === idea.title);
      if (isAlreadySaved) {
        return prev.filter(g => g.title !== idea.title);
      }
      return [idea, ...prev];
    });
  };

  const saveAllToVault = () => {
    setSavedGems(prev => {
      const newGems = ideas.filter(idea => !prev.some(g => g.title === idea.title));
      return [...newGems, ...prev];
    });
  };

  const deleteGem = (title: string) => {
    setSavedGems(prev => prev.filter(g => g.title !== title));
  };

  const handleQuickSelect = (n: string) => {
    setNiche(n);
    handleSubmit(undefined, n);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-12 animate-fade-in pb-20">
      <div className="text-center space-y-4 py-8">
        <div className="inline-flex items-center justify-center p-4 rounded-[2rem] bg-red-500/10 text-red-500 mb-2 border border-red-500/20 shadow-2xl shadow-red-500/5">
           <TrendingUp size={40} strokeWidth={2.5} />
        </div>
        <h2 className="text-5xl font-black bg-gradient-to-br from-white to-zinc-600 bg-clip-text text-transparent tracking-tighter">
          Viral Idea Lab
        </h2>
        <p className="text-zinc-400 text-lg font-medium max-w-2xl mx-auto">
          Deploy Google Gemini to engineer breakout topics with a calculated viral potential score and market supply/demand mapping.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
        <div className="lg:col-span-2 space-y-8">
          <div className="space-y-6">
            <form onSubmit={handleSubmit} className="relative group">
              <div className="absolute inset-0 bg-red-600 blur-2xl opacity-0 group-focus-within:opacity-10 transition-opacity"></div>
              <div className="relative flex gap-3 p-2 bg-zinc-900 border border-zinc-800 rounded-[2.5rem] shadow-2xl focus-within:border-red-500/50 transition-all">
                <div className="flex items-center pl-4 text-zinc-600">
                   <Search size={20} />
                </div>
                <input
                  type="text"
                  value={niche}
                  onChange={(e) => setNiche(e.target.value)}
                  placeholder="Enter your niche or target topic..."
                  className="flex-1 bg-transparent border-none py-4 outline-none text-white font-medium placeholder:text-zinc-700"
                />
                <button
                  type="submit"
                  disabled={loading || !niche}
                  className="bg-red-600 hover:bg-red-500 disabled:opacity-50 disabled:cursor-not-allowed text-white px-10 py-3 rounded-[2rem] font-black uppercase text-xs tracking-widest transition-all shadow-lg shadow-red-600/20 flex items-center gap-2 active-press"
                >
                  {loading ? <Loader2 className="animate-spin" size={18} /> : <><Zap size={18} fill="currentColor" /> Generate</>}
                </button>
              </div>
            </form>

            <div className="flex flex-wrap items-center justify-center gap-2 px-4">
               <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mr-2">Featured:</span>
               {SUGGESTED_NICHES.map(n => (
                 <button
                   key={n}
                   onClick={() => handleQuickSelect(n)}
                   className="px-4 py-1.5 rounded-full text-xs font-bold bg-zinc-900 border border-zinc-800 text-zinc-500 hover:text-red-500 hover:border-red-500/30 transition-all"
                 >
                   {n}
                 </button>
               ))}
            </div>
          </div>

          {error && (
            <div className="max-w-md mx-auto p-4 bg-red-500/10 border border-red-500/20 text-red-400 rounded-2xl text-center text-sm font-bold animate-pulse">
              {error}
            </div>
          )}

          {loading && ideas.length === 0 && (
             <div className="flex flex-col items-center justify-center py-20 gap-6 text-zinc-700 animate-fade-in">
                <Loader2 className="animate-spin" size={48} strokeWidth={1} />
                <p className="text-sm font-black uppercase tracking-[0.4em] opacity-40">Calculating Viral Flux</p>
             </div>
          )}

          {ideas.length > 0 && (
            <div className="space-y-8 animate-scale-in">
              <div className="bg-zinc-900/50 border border-zinc-800 rounded-3xl p-6 flex flex-col md:flex-row items-center justify-between gap-6 shadow-xl">
                <div className="flex items-center gap-6">
                  <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Niche Authority</span>
                    <span className="text-xl font-black text-white flex items-center gap-2">
                       <Target size={20} className="text-red-500" /> {niche}
                    </span>
                  </div>
                  <div className="w-px h-10 bg-zinc-800 hidden md:block"></div>
                  <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Algorithmic Match</span>
                    <span className="text-xl font-black text-green-500 flex items-center gap-2">
                       <Activity size={20} /> 94% Optimal
                    </span>
                  </div>
                </div>
                <button 
                  onClick={saveAllToVault}
                  className="flex items-center gap-2 px-6 py-2.5 bg-zinc-800 hover:bg-zinc-700 text-white rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border border-zinc-700 active-press"
                >
                  <Save size={14} className="text-red-500" /> Save All to Vault
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                 {ideas.map((idea, index) => (
                   <IdeaCard 
                    key={index} 
                    idea={idea} 
                    onAction={onNavigate} 
                    onToggleSave={toggleSaveGem}
                    isSaved={!!savedGems.find(g => g.title === idea.title)}
                   />
                 ))}
              </div>
            </div>
