            <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest">Neural Pacing Engine</p>
          </div>
          <div className="relative">
            <button onClick={() => setShowPresets(!showPresets)} className="flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all border border-zinc-800 active-press">
              <BookOpen size={14} /> Blueprints <ChevronDown size={14} className={showPresets ? 'rotate-180' : ''} />
