        {/* Pacing Heatmap */}
        {script && (
          <div className="bg-zinc-900 border border-zinc-800 p-6 rounded-[2.5rem] shadow-xl overflow-hidden animate-scale-in">
             <div className="flex items-center justify-between mb-4">
                <h3 className="text-[10px] font-black text-zinc-600 uppercase tracking-widest flex items-center gap-2">
