export const ScriptWriter: React.FC<any> = ({ prefill, onNavigate }) => {
  const [title, setTitle] = useState('The 24-Hour AI Agency Challenge');
  const [instructions, setInstructions] = useState('');
  const [tone, setTone] = useState('Fast-paced & Hype');
  const [scriptType, setScriptType] = useState('storytelling');
  const [script, setScript] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [showPresets, setShowPresets] = useState(false);
  const [library, setLibrary] = useState<any[]>([]);

  const scriptEndRef = useRef<HTMLDivElement>(null);
  const instructionsRef = useRef<HTMLTextAreaElement>(null);
  const { incrementStat } = useAuth();

  const analytics = useMemo(() => {
    if (!script) return { pacing: 0, density: 0, cues: 0, heatmap: [] };
    const cueCount = (script.match(/\[Visual:.*?\]/g) || []).length;
    const words = script.replace(/\[.*?\]/g, '').split(/\s+/).filter(w => w.length > 0).length;
    const visualDensity = Math.min((cueCount / (words / 12)) * 100, 100); 
    const segments = script.split('\n\n').map((s, i) => ({ name: `S${i+1}`, Heat: (s.match(/\[Visual:.*?\]/g) || []).length > 0 ? 95 : 40 }));
    return { pacing: Math.round(Math.min((words / 100) * 100, 100)), density: Math.round(visualDensity), cues: cueCount, heatmap: segments };
  }, [script]);

  useEffect(() => {
    if (prefill) {
      if (prefill.title) setTitle(prefill.title);
      if (prefill.instructions) setInstructions(prefill.instructions);
    }
  }, [prefill]);

  const applyPreset = (p: typeof SCRIPT_PRESETS[0]) => {
    setTitle(p.title);
    setTone(p.tone);
    setScriptType(p.type);
    setInstructions(p.instructions);
    setShowPresets(false);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;
    setIsGenerating(true);
    setScript('');
    try {
      let full = '';
      await generateScriptStream(title, tone, scriptType, instructions, (chunk) => {
        setScript(prev => prev + chunk);
        full += chunk;
      });
      incrementStat('scriptsWritten');
    } catch (err) { console.error(err); } 
    finally { setIsGenerating(false); }
  };

  const handleOptimizePacing = async () => {
    if (!script) return;
    setIsOptimizing(true);
    const original = script;
    setScript('');
    try {
      await optimizeScriptPacing(original, (chunk) => {
        setScript(prev => prev + chunk);
      });
    } catch (err) { console.error(err); setScript(original); } 
    finally { setIsOptimizing(false); }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col md:flex-row gap-6 animate-fade-in pb-10">
      <div className="w-full md:w-[380px] space-y-6 flex flex-col shrink-0">
        <div className="flex items-center justify-between">
          <h2 className="text-2xl font-black text-white">Script Architect</h2>
          <div className="relative">
            <button onClick={() => setShowPresets(!showPresets)} className="flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-4 py-2 rounded-xl text-xs font-bold border border-zinc-800 transition-all">
              <BookOpen size={14} /> Blueprints <ChevronDown size={14} />
            </button>
            {showPresets && (
              <div className="absolute top-full right-0 mt-2 w-64 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-2xl z-50 overflow-hidden glass-morphism">
                {SCRIPT_PRESETS.map(p => (
                  <button key={p.id} onClick={() => applyPreset(p)} className="w-full text-left px-4 py-3 hover:bg-red-500/10 text-zinc-400 text-sm border-b border-zinc-800 last:border-0 transition-colors">
                    {p.label}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        <form onSubmit={handleGenerate} className="space-y-4 p-6 bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex-1 flex flex-col shadow-2xl">
          <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Headline" className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 text-white font-medium focus:ring-2 focus:ring-red-500/50 outline-none" />
          <textarea value={instructions} onChange={(e) => setInstructions(e.target.value)} placeholder="Narrative constraints..." className="flex-1 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 outline-none resize-none text-white text-sm leading-relaxed" />
          <div className="grid grid-cols-2 gap-4">
            <select value={tone} onChange={(e) => setTone(e.target.value)} className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-[10px] font-black uppercase text-white appearance-none">
              <option>Fast-paced & Hype</option>
              <option>Professional</option>
            </select>
            <button type="submit" disabled={isGenerating || !title} className="bg-red-600 hover:bg-red-500 text-white rounded-xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2">
              {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} />} Synthesize
            </button>
          </div>
        </form>

        {script && (
          <div className="bg-zinc-900 border border-zinc-800 p-6 rounded-[2.5rem] animate-scale-in">
             <div className="flex items-center justify-between mb-4">
                <h3 className="text-[10px] font-black text-zinc-600 uppercase tracking-widest flex items-center gap-2">
