                     <button onClick={() => setCurrentTime(0)} className="text-zinc-500 hover:text-white transition-colors"><SkipBack size={20}/></button>
                     <button onClick={togglePlay} className="w-14 h-14 bg-red-600 hover:bg-red-500 rounded-full flex items-center justify-center text-white shadow-lg transition-all active-press">
