                   {/* Playhead */}
                   <div className="absolute top-0 bottom-0 w-[2px] bg-red-600 z-30 pointer-events-none" style={{ left: `${currentTime * zoomLevel}px` }}>
                      <div className="w-4 h-4 bg-red-600 rounded-full -ml-[7px] -mt-2 shadow-[0_0_10px_rgba(239,68,68,0.5)]"></div>
                   </div>

                   <div className="p-8 min-h-full" style={{ width: `${Math.max(1000, totalDuration * zoomLevel + 200)}px` }}>
                      <div className="space-y-4">
                         {/* Video Track */}
                         <div className="h-28 bg-zinc-900/50 border border-zinc-800 rounded-3xl relative flex items-center group/track">
                            <div className="absolute left-4 top-1/2 -translate-y-1/2 flex items-center gap-2 opacity-10 pointer-events-none">
                               <GripVertical size={14} />
                               <span className="text-[8px] font-black uppercase tracking-widest">Visual Layer 01</span>
                            </div>

                            {timeline.map((clip) => (
                              <div 
                                 key={clip.id}
                                 onClick={(e) => { e.stopPropagation(); setSelectedClipId(clip.id); }}
                                 className={`absolute h-20 rounded-2xl border transition-all flex flex-col justify-center px-4 cursor-pointer overflow-hidden ${selectedClipId === clip.id ? 'bg-red-600/10 border-red-500 ring-2 ring-red-500/20' : 'bg-zinc-800/80 border-zinc-700 hover:border-zinc-500'}`}
                                 style={{ left: `${clip.timelineOffset * zoomLevel}px`, width: `${(clip.trimEnd - clip.trimStart) * zoomLevel}px` }}
                              >
                                 <span className="text-[10px] font-black text-white uppercase truncate">{clip.name}</span>
                                 <div className="flex items-center gap-2 mt-1">
                                    <Clock size={10} className="text-zinc-600" />
                                    <span className="text-[8px] font-bold text-zinc-500">{(clip.trimEnd - clip.trimStart).toFixed(1)}s</span>
                                 </div>
                              </div>
                            ))}
                         </div>

                         {/* Info Track */}
                         <div className="h-12 flex items-center gap-4 opacity-40 px-4">
                            <Layers size={14} className="text-zinc-600" />
                            <span className="text-[9px] font-black text-zinc-700 uppercase tracking-widest">{timeline.length} Elements Manifested</span>
                         </div>
                      </div>
                   </div>
                </div>
             </div>

             <div className="px-8 py-3 bg-zinc-950 border-t border-zinc-800 flex items-center justify-between shrink-0">
                <div className="flex items-center gap-4">
                   <span className="text-[9px] font-black text-zinc-700 uppercase">Magnification</span>
                   <input type="range" min="10" max="100" value={zoomLevel} onChange={e => setZoomLevel(parseInt(e.target.value))} className="w-32 accent-red-600" />
                </div>
                {timeline.length > 0 && (
                   <button className="bg-white hover:bg-zinc-200 text-black px-6 py-2 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 transition-all shadow-xl active-press">
                      <Download size={14} /> Export Sequence
                   </button>
                )}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

