import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, PlanType, UserStats } from '../types';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  login: (email: string) => void;
  signup: (email: string, name: string, referralCode?: string) => void;
  logout: () => void;
  upgradeToPro: (plan?: PlanType) => void;
  checkPlanStatus: () => { isValid: boolean; daysLeft: number; isFree: boolean; plan: PlanType };
  incrementStat: (key: keyof UserStats) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const DEFAULT_STATS: UserStats = {
  ideasGenerated: 0,
  scriptsWritten: 0,
  thumbnailsCreated: 0,
  seoOptimized: 0,
  marketingPlans: 0
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Simulate checking session from local storage
    const storedUser = localStorage.getItem('tf_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setIsLoading(false);
  }, []);

  const login = (email: string) => {
    // Mock login - in production this would hit an API
    const storedUser = localStorage.getItem('tf_user');
    if (storedUser) {
      const u = JSON.parse(storedUser);
      if (u.email === email) {
        setUser(u);
        return;
      }
    }
    alert('User not found. Please sign up.');
  };

  const signup = (email: string, name: string, referredBy?: string) => {
    // Generate a simple unique referral code
    const referralCode = name.substring(0, 3).toUpperCase() + Math.floor(1000 + Math.random() * 9000);

    const newUser: User = {
      email,
      name,
      plan: 'free',
      planStartDate: Date.now(),
      referralCode,
      referredBy,
      stats: DEFAULT_STATS
    };

    localStorage.setItem('tf_user', JSON.stringify(newUser));
    setUser(newUser);
  };

  const logout = () => {
    localStorage.removeItem('tf_user');
    setUser(null);
  };

  const upgradeToPro = (plan: PlanType = 'solopreneur') => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      plan: plan,
      planStartDate: Date.now() // Reset timer for new plan
    };
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
    setUser(updatedUser);
  };

  const checkPlanStatus = () => {
    if (!user) return { isValid: false, daysLeft: 0, isFree: true, plan: 'free' as PlanType };

    const now = Date.now();
    const msPerDay = 24 * 60 * 60 * 1000;
    const daysSinceStart = (now - user.planStartDate) / msPerDay;

    if (user.plan === 'free') {
      const limit = 3;
      return {
        isValid: daysSinceStart < limit,
        daysLeft: Math.max(0, Math.ceil(limit - daysSinceStart)),
        isFree: true,
        plan: user.plan
      };
    } else {
      const limit = 30;
      return {
        isValid: daysSinceStart < limit,
        daysLeft: Math.max(0, Math.ceil(limit - daysSinceStart)),
        isFree: false,
        plan: user.plan
      };
    }
  };

  const incrementStat = (key: keyof UserStats) => {
    if (!user) return;

    const currentStats = user.stats || DEFAULT_STATS;
    const newStats = {
      ...currentStats,
      [key]: (currentStats[key] || 0) + 1
    };

    const updatedUser = { ...user, stats: newStats };
    setUser(updatedUser);
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, login, signup, logout, upgradeToPro, checkPlanStatus, incrementStat }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

