import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../auth/AuthContext';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { Mic, MicOff, Radio, Volume2 } from 'lucide-react';
import { MODEL_NAMES } from '../constants';

export const LiveBrainstorm: React.FC = () => {
  const [connected, setConnected] = useState(false);
  const [active, setActive] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null); // For future video support
  const [status, setStatus] = useState("Ready to connect");

  // Refs for audio handling
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const inputContextRef = useRef<AudioContext | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);

  const connect = async () => {
    setStatus("Connecting...");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const inputCtx = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 16000});
      const outputCtx = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
      inputContextRef.current = inputCtx;
      audioContextRef.current = outputCtx;

      const outputNode = outputCtx.createGain();
      outputNode.connect(outputCtx.destination);
      nextStartTimeRef.current = 0;

      // Microphone Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        // Fix: Use the latest native audio model from MODEL_NAMES
        model: MODEL_NAMES.AUDIO_NATIVE,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: 'You are a creative partner helping brainstorm YouTube content ideas. Be energetic and concise.',
        },
        callbacks: {
          onopen: () => {
            setStatus("Connected! Speak now.");
            setConnected(true);
            setActive(true);

            // Setup Input Processing
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              // CRITICAL: Solely rely on sessionPromise resolves and then call session.sendRealtimeInput
              sessionPromise.then((session: any) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && audioContextRef.current) {
               const ctx = audioContextRef.current;
               // Simple time tracking to queue audio
               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

               try {
                 const buffer = await decodeAudioData(base64Audio, ctx);
                 const source = ctx.createBufferSource();
                 source.buffer = buffer;
                 source.connect(outputNode);
                 // Schedule next chunk at the exact end time for gapless playback
                 source.start(nextStartTimeRef.current);
                 nextStartTimeRef.current += buffer.duration;

                 sourcesRef.current.add(source);
                 source.onended = () => sourcesRef.current.delete(source);
               } catch (e) { console.error("Decode error", e); }
            }
          },
          onclose: () => {
            setStatus("Disconnected");
            setConnected(false);
            setActive(false);
          },
          onerror: (e) => {
            console.error(e);
            setStatus("Error occurred");
            setConnected(false);
          }
        }
      });
      sessionPromiseRef.current = sessionPromise;

    } catch (e) {
      console.error(e);
      setStatus("Failed to connect");
    }
  };

  const disconnect = () => {
    // Stop audio contexts and clean up
    inputContextRef.current?.close();
    audioContextRef.current?.close();
    setConnected(false);
    setActive(false);
    setStatus("Disconnected");
  };

  // Helpers
  function createPcmBlob(data: Float32Array) {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      int16[i] = data[i] * 32768;
    }
    // Manual base64 encode helper
    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);

    return {
      data: btoa(binary),
      mimeType: 'audio/pcm;rate=16000'
    };
  }

  async function decodeAudioData(base64: string, ctx: AudioContext) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

    // Manual decoding for raw PCM 24k
    const dataInt16 = new Int16Array(bytes.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
    }
    return buffer;
  }

  return (
    <div className="max-w-2xl mx-auto flex flex-col items-center justify-center h-[calc(100vh-6rem)] animate-fade-in">
       <div className={`relative w-64 h-64 rounded-full flex items-center justify-center transition-all duration-500 ${active ? 'bg-red-500/20 shadow-[0_0_100px_rgba(239,68,68,0.4)]' : 'bg-zinc-900'}`}>
          {active && (
            <div className="absolute inset-0 rounded-full border border-red-500/50 animate-ping opacity-20"></div>
          )}
          <Volume2 size={80} className={active ? 'text-red-500 animate-pulse' : 'text-zinc-600'} />
       </div>

       <h2 className="text-3xl font-bold text-white mt-12 mb-2">Live Brainstorm</h2>
       <p className="text-zinc-400 mb-8 font-mono">{status}</p>

       <button
         onClick={connected ? disconnect : connect}
         className={`px-8 py-4 rounded-full font-bold text-lg flex items-center gap-3 transition-all ${
           connected 
            ? 'bg-zinc-800 hover:bg-zinc-700 text-white' 
            : 'bg-red-600 hover:bg-red-500 text-white shadow-lg shadow-red-600/30'
         }`}
       >
         {connected ? <><MicOff /> End Session</> : <><Mic /> Start Conversation</>}
       </button>
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, PlanType, UserStats } from '../types';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  login: (email: string) => void;
  signup: (email: string, name: string, referralCode?: string) => void;
  logout: () => void;
  upgradeToPro: (plan: PlanType) => void;
  renewPlan: () => void;
  checkPlanStatus: () => { 
    isValid: boolean; 
    daysLeft: number; 
    isFree: boolean; 
    plan: PlanType;
    isExpiringSoon: boolean;
  };
  incrementStat: (key: keyof UserStats) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const DEFAULT_STATS: UserStats = {
  ideasGenerated: 0,
  scriptsWritten: 0,
  thumbnailsCreated: 0,
  seoOptimized: 0,
  marketingPlans: 0
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const storedUser = localStorage.getItem('tf_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setIsLoading(false);
  }, []);

  const login = (email: string) => {
    const storedUser = localStorage.getItem('tf_user');
    if (storedUser) {
      const u = JSON.parse(storedUser);
      if (u.email === email) {
        setUser(u);
        return;
      }
    }
    alert('User not found. Please sign up.');
  };

  const signup = (email: string, name: string, referredBy?: string) => {
    const referralCode = name.substring(0, 3).toUpperCase() + Math.floor(1000 + Math.random() * 9000);
    const newUser: User = {
      email,
      name,
      plan: 'free',
      planStartDate: Date.now(),
      referralCode,
      referredBy,
      stats: DEFAULT_STATS
    };
    localStorage.setItem('tf_user', JSON.stringify(newUser));
    setUser(newUser);
  };

  const logout = () => {
    localStorage.removeItem('tf_user');
    setUser(null);
  };

  const upgradeToPro = (plan: PlanType) => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      plan: plan,
      planStartDate: Date.now()
    };
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
    setUser(updatedUser);
  };

  const renewPlan = () => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      planStartDate: Date.now() // Reset cycle
    };
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
    setUser(updatedUser);
  };

  const checkPlanStatus = () => {
    if (!user) return { isValid: false, daysLeft: 0, isFree: true, plan: 'free' as PlanType, isExpiringSoon: false };

    const now = Date.now();
    const msPerDay = 24 * 60 * 60 * 1000;
    const daysSinceStart = (now - user.planStartDate) / msPerDay;
    const planDuration = user.plan === 'free' ? 3 : 30;

    const daysLeft = Math.max(0, Math.ceil(planDuration - daysSinceStart));
    const isExpiringSoon = daysLeft <= 5 && daysLeft > 0;

    return {
      isValid: daysSinceStart < planDuration,
      daysLeft,
      isFree: user.plan === 'free',
      plan: user.plan,
      isExpiringSoon
    };
  };

  const incrementStat = (key: keyof UserStats) => {
    if (!user) return;
    const currentStats = user.stats || DEFAULT_STATS;
    const newStats = { ...currentStats, [key]: (currentStats[key] || 0) + 1 };
    const updatedUser = { ...user, stats: newStats };
    setUser(updatedUser);
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, login, signup, logout, upgradeToPro, renewPlan, checkPlanStatus, incrementStat }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

