/**
 * Initialize and return GoogleGenAI client with the key from process.env.API_KEY.
 */
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateOutreachCampaign = async (
  platform: string, 
  intent: string, 
  duration: string, 
  goal: string, 
  customer: string, 
  city: string,
  dataCollection?: string[]
): Promise<OutreachResult> => {
  const ai = getAiClient();
  const prompt = `Generate a 7-8 step outreach funnel for ${platform}. 
  INTENT: ${intent}
  DURATION: ${duration}
  GOAL: ${goal}
  TARGET CUSTOMER: ${customer}
  CITY: ${city}
  DATA COLLECTION: ${dataCollection?.join(', ') || 'none'}`;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_SMART,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.OUTREACH,
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || "{}");
};

