const AppContent = () => {
  const { user, isLoading, checkPlanStatus } = useAuth();
  const [currentTool, setCurrentTool] = useState<ToolType>(ToolType.DASHBOARD);
  const [showIntro, setShowIntro] = useState(true);
  const [prefillData, setPrefillData] = useState<any>(null);

  const handleNavigate = (tool: ToolType, payload?: any) => {
    setPrefillData(payload || null);
    setCurrentTool(tool);
  };

  if (showIntro) {
    return <Intro onFinish={() => setShowIntro(false)} />;
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-[#09090b] flex items-center justify-center">
        <Loader2 className="animate-spin text-red-500" size={32} />
      </div>
    );
  }

  if (!user) {
    return <Auth />;
  }

  const { isValid } = checkPlanStatus();

  if (!isValid && currentTool !== ToolType.UPGRADE) {
    return <Upgrade />;
  }

  const renderTool = () => {
    if (currentTool === ToolType.UPGRADE) {
      return <Upgrade />;
    }

    if (!isValid) return <Upgrade />;

    switch (currentTool) {
      case ToolType.DASHBOARD:
        return <CreatorDashboard onNavigate={handleNavigate} />;
      case ToolType.DEV_DASHBOARD:
        return <DeveloperDashboard />;
      case ToolType.ABOUT:
        return <About />;
      case ToolType.PROJECTS:
        return <Projects />;
      case ToolType.IDEAS:
        return <IdeaGenerator onNavigate={handleNavigate} />;
      case ToolType.SCRIPT:
        return <ScriptWriter prefill={prefillData} />;
      case ToolType.SHORTS_GENERATOR:
        return <ShortsGenerator prefill={prefillData} />;
      case ToolType.SEO:
        return <SeoOptimizer prefill={prefillData} />;
      case ToolType.METADATA_ENGINEER:
        return <MetadataEngineer />;
      case ToolType.THUMBNAIL:
        return <ThumbnailGenerator prefill={prefillData} />;
      case ToolType.THUMBNAIL_RATER:
        return <ThumbnailRater />;
      case ToolType.COMPETITOR_SPY:
        return <CompetitorSpy />;
      case ToolType.CHANNEL_AUDIT:
        return <ChannelAudit />;
      case ToolType.VIDEO:
        return <VideoStudio />;
      case ToolType.VIDEO_GENERATOR:
        return <VideoGenerator />;
      case ToolType.AUDIO:
        return <AudioStudio />;
      case ToolType.RESEARCH:
        return <ResearchAssistant />;
      case ToolType.LIVE:
        return <LiveBrainstorm />;
      case ToolType.MARKETING:
        return <MarketingScheduler />;
      case ToolType.REPURPOSE:
        return <RepurposeEngine onNavigate={handleNavigate} />;
      case ToolType.KEYWORD_INSPECTOR:
        return <KeywordInspector />;
      case ToolType.TREND_WATCHER:
        return <TrendWatcher />;
      case ToolType.TITLE_GENERATOR:
        return <TitleGenerator />;
      case ToolType.OUTREACH:
        return <OutreachHub />;
      case ToolType.EMAIL_MARKETING:
        return <EmailMarketing />;
      case ToolType.MARKET_STRATEGIST:
        return <MarketStrategist />;
      default:
        return <CreatorDashboard onNavigate={handleNavigate} />;
    }
  };

  return (
    <Layout currentTool={currentTool} onNavigate={handleNavigate}>
      {renderTool()}
    </Layout>
  );
};

function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

export default App;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, PlanType, UserStats } from '../types';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  login: (email: string) => void;
  signup: (email: string, name: string, referralCode?: string) => void;
  logout: () => void;
  upgradeToPro: (plan: PlanType) => void;
  renewPlan: () => void;
  checkPlanStatus: () => { 
    isValid: boolean; 
    daysLeft: number; 
    isFree: boolean; 
    plan: PlanType;
    isExpiringSoon: boolean;
  };
  incrementStat: (key: keyof UserStats) => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const DEFAULT_STATS: UserStats = {
  ideasGenerated: 0,
  scriptsWritten: 0,
  thumbnailsCreated: 0,
  seoOptimized: 0,
  marketingPlans: 0
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const storedUser = localStorage.getItem('tf_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setIsLoading(false);
  }, []);

  const login = (email: string) => {
    const storedUser = localStorage.getItem('tf_user');
    if (storedUser) {
      const u = JSON.parse(storedUser);
      if (u.email === email) {
        setUser(u);
        return;
      }
    }
    alert('User not found. Please sign up.');
  };

  const signup = (email: string, name: string, referredBy?: string) => {
    const referralCode = name.substring(0, 3).toUpperCase() + Math.floor(1000 + Math.random() * 9000);
    const newUser: User = {
      email,
      name,
      plan: 'free',
      planStartDate: Date.now(),
      referralCode,
      referredBy,
      stats: DEFAULT_STATS
    };
    localStorage.setItem('tf_user', JSON.stringify(newUser));
    setUser(newUser);
  };

  const logout = () => {
    localStorage.removeItem('tf_user');
    setUser(null);
  };

  const upgradeToPro = (plan: PlanType) => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      plan: plan,
      planStartDate: Date.now()
    };
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
    setUser(updatedUser);
  };

  const renewPlan = () => {
    if (!user) return;
    const updatedUser: User = {
      ...user,
      planStartDate: Date.now() // Reset cycle
    };
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
    setUser(updatedUser);
  };

  const checkPlanStatus = () => {
    if (!user) return { isValid: false, daysLeft: 0, isFree: true, plan: 'free' as PlanType, isExpiringSoon: false };

    const now = Date.now();
    const msPerDay = 24 * 60 * 60 * 1000;
    const daysSinceStart = (now - user.planStartDate) / msPerDay;
    // Changed trial duration from 3 to 1
    const planDuration = user.plan === 'free' ? 1 : 30;

    const daysLeft = Math.max(0, Math.ceil(planDuration - daysSinceStart));
    const isExpiringSoon = daysLeft <= 5 && daysLeft > 0;

    return {
      isValid: daysSinceStart < planDuration,
      daysLeft,
      isFree: user.plan === 'free',
      plan: user.plan,
      isExpiringSoon
    };
  };

  const incrementStat = (key: keyof UserStats) => {
    if (!user) return;
    const currentStats = user.stats || DEFAULT_STATS;
    const newStats = { ...currentStats, [key]: (currentStats[key] || 0) + 1 };
    const updatedUser = { ...user, stats: newStats };
    setUser(updatedUser);
    localStorage.setItem('tf_user', JSON.stringify(updatedUser));
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, login, signup, logout, upgradeToPro, renewPlan, checkPlanStatus, incrementStat }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

