             </div>

             {/* Pacing Auditor Alert */}
             <div className={`p-4 rounded-2xl border flex items-start gap-3 transition-all ${auditData.violationsCount > 0 ? 'bg-orange-500/10 border-orange-500/30 text-orange-400' : 'bg-green-500/10 border-green-500/30 text-green-400'}`}>
                {auditData.violationsCount > 0 ? <ShieldAlert size={18} className="shrink-0 mt-0.5" /> : <CheckCircle2 size={18} className="shrink-0 mt-0.5" />}
                <div>
                   <p className="text-[10px] font-black uppercase tracking-widest">
                      {auditData.violationsCount > 0 ? 'Retention Risk Detected' : 'Optimal Pacing Verified'}
                   </p>
                   <p className="text-[11px] font-medium opacity-80 mt-1">
                      {auditData.violationsCount > 0 
                        ? `${auditData.violationsCount} segments deviate from the 10-15 word visual cue rule.` 
                        : 'Linguistic velocity matches visual density perfectly.'}
                   </p>
                </div>
             </div>
