export const LiveBrainstorm: React.FC = () => {
  const [connected, setConnected] = useState(false);
  const [active, setActive] = useState(false);
  const [status, setStatus] = useState("Ready to connect");
  const [streamMode, setStreamMode] = useState<'none' | 'camera' | 'screen'>('none');

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const inputContextRef = useRef<AudioContext | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const frameIntervalRef = useRef<number | null>(null);

  const startMedia = async (mode: 'camera' | 'screen') => {
    try {
      const stream = mode === 'camera' 
        ? await navigator.mediaDevices.getUserMedia({ video: true })
        : await navigator.mediaDevices.getDisplayMedia({ video: true });

      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.play();
        setStreamMode(mode);
      }
    } catch (e) {
      console.error("Media start error", e);
      alert("Failed to access camera/screen.");
    }
  };

  const stopMedia = () => {
    if (videoRef.current?.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(t => t.stop());
      videoRef.current.srcObject = null;
    }
    if (frameIntervalRef.current) clearInterval(frameIntervalRef.current);
    setStreamMode('none');
  };

  const connect = async () => {
    setStatus("Establishing Neural Link...");
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const inputCtx = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 16000});
      const outputCtx = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
      inputContextRef.current = inputCtx;
      audioContextRef.current = outputCtx;

      const outputNode = outputCtx.createGain();
      outputNode.connect(outputCtx.destination);
      nextStartTimeRef.current = 0;

      const micStream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: MODEL_NAMES.AUDIO_NATIVE,
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: 'You are a Multimodal YouTube Strategist. You can see the user screen or camera. Use this visual context to critique thumbnails, analyze scripts, or brainstorm video structure. Be sharp, energetic, and data-driven.',
        },
        callbacks: {
          onopen: () => {
            setStatus("Live Multimodal Active");
            setConnected(true);
            setActive(true);

            // Audio Input
            const source = inputCtx.createMediaStreamSource(micStream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session: any) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            // Video Input (if active)
            if (streamMode !== 'none' && videoRef.current && canvasRef.current) {
              const videoEl = videoRef.current;
              const canvasEl = canvasRef.current;
              const ctx = canvasEl.getContext('2d');

              frameIntervalRef.current = window.setInterval(() => {
                if (!ctx || !videoEl.videoWidth) return;
                canvasEl.width = videoEl.videoWidth;
                canvasEl.height = videoEl.videoHeight;
                ctx.drawImage(videoEl, 0, 0);

                canvasEl.toBlob(async (blob) => {
                  if (blob) {
                    const reader = new FileReader();
                    reader.onloadend = () => {
                      const base64Data = (reader.result as string).split(',')[1];
                      sessionPromise.then((session: any) => {
                        session.sendRealtimeInput({
                          media: { data: base64Data, mimeType: 'image/jpeg' }
                        });
                      });
                    };
                    reader.readAsDataURL(blob);
                  }
                }, 'image/jpeg', JPEG_QUALITY);
              }, 1000 / FRAME_RATE);
            }
          },
          onmessage: async (msg: LiveServerMessage) => {
            const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && audioContextRef.current) {
               const ctx = audioContextRef.current;
               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
               try {
                 const buffer = await decodeAudioData(base64Audio, ctx);
                 const source = ctx.createBufferSource();
                 source.buffer = buffer;
                 source.connect(outputNode);
                 source.start(nextStartTimeRef.current);
                 nextStartTimeRef.current += buffer.duration;
                 sourcesRef.current.add(source);
                 source.onended = () => sourcesRef.current.delete(source);
               } catch (e) { console.error("Decode error", e); }
            }
            if (msg.serverContent?.interrupted) {
              for (const s of sourcesRef.current) { s.stop(); }
              sourcesRef.current.clear();
            }
          },
          onclose: () => {
            setStatus("Session Terminated");
            setConnected(false);
            setActive(false);
          },
          onerror: (e) => {
            console.error(e);
            setStatus("API Interface Error");
            setConnected(false);
          }
        }
      });
      sessionPromiseRef.current = sessionPromise;

    } catch (e) {
      console.error(e);
      setStatus("Connection Denied");
    }
  };

  const disconnect = () => {
    inputContextRef.current?.close();
    audioContextRef.current?.close();
    stopMedia();
    setConnected(false);
    setActive(false);
    setStatus("Ready for Session");
  };

  function createPcmBlob(data: Float32Array) {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) { int16[i] = data[i] * 32768; }
    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return { data: btoa(binary), mimeType: 'audio/pcm;rate=16000' };
  }

  async function decodeAudioData(base64: string, ctx: AudioContext) {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    const dataInt16 = new Int16Array(bytes.buffer);
    const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) { channelData[i] = dataInt16[i] / 32768.0; }
    return buffer;
  }

  return (
    <div className="max-w-6xl mx-auto flex flex-col items-center justify-center h-[calc(100vh-6rem)] animate-fade-in gap-12">
       <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 w-full items-center">

          <div className="space-y-8 text-center lg:text-left">
             <div className="inline-flex items-center gap-3 px-4 py-2 rounded-full bg-red-600/10 border border-red-600/20 text-red-500 text-[10px] font-black uppercase tracking-widest">
                <Sparkles size={14} /> Real-time Multimodal
             </div>
             <h2 className="text-6xl font-black text-white tracking-tighter leading-none">
                Neural <br/><span className="text-red-600">Vision Hub</span>
             </h2>
             <p className="text-zinc-500 text-lg font-medium max-w-md mx-auto lg:mx-0 leading-relaxed">
                Start a low-latency voice conversation with Gemini. Share your screen or camera to get visual feedback on thumbnails, pacing, and brand aesthetics.
             </p>

             <div className="flex flex-wrap gap-4 justify-center lg:justify-start">
                <button
                  onClick={connected ? disconnect : connect}
                  disabled={connected && active}
                  className={`px-10 py-5 rounded-[2rem] font-black uppercase text-xs tracking-[0.2em] flex items-center gap-4 transition-all active-press ${
                    connected 
                     ? 'bg-zinc-800 text-zinc-500 cursor-default' 
                     : 'bg-red-600 hover:bg-red-500 text-white shadow-2xl shadow-red-600/20'
                  }`}
                >
                  {connected ? <><Loader2 className="animate-spin" size={20} /> Connection Active</> : <><Mic size={20} fill="currentColor" /> Initialize Link</>}
                </button>

                {connected && (
                  <button onClick={disconnect} className="px-10 py-5 rounded-[2rem] bg-zinc-900 border border-zinc-800 text-white font-black uppercase text-xs tracking-[0.2em] hover:bg-red-900/20 hover:border-red-900/40 transition-all">
                    Terminiate
                  </button>
                )}
             </div>

             <div className="flex items-center gap-6 justify-center lg:justify-start">
                <div className="flex bg-zinc-900 border border-zinc-800 rounded-2xl p-1 shadow-inner">
                   <button 
                     onClick={() => streamMode === 'camera' ? stopMedia() : startMedia('camera')} 
                     className={`p-4 rounded-xl transition-all ${streamMode === 'camera' ? 'bg-zinc-800 text-red-500' : 'text-zinc-600 hover:text-white'}`}
                     title="Share Camera"
                   >
                     {streamMode === 'camera' ? <VideoOff size={24}/> : <Camera size={24}/>}
                   </button>
                   <button 
                     onClick={() => streamMode === 'screen' ? stopMedia() : startMedia('screen')} 
                     className={`p-4 rounded-xl transition-all ${streamMode === 'screen' ? 'bg-zinc-800 text-blue-500' : 'text-zinc-600 hover:text-white'}`}
                     title="Share Screen"
                   >
                     <Monitor size={24}/>
                   </button>
                </div>
                <div className="text-left">
                   <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Input Status</p>
                   <p className={`text-xs font-bold uppercase ${active ? 'text-green-500' : 'text-zinc-400'}`}>{status}</p>
                </div>
             </div>
          </div>

          <div className="relative">
             <div className={`w-full aspect-video rounded-[3rem] bg-zinc-900 border-4 border-zinc-800 overflow-hidden relative shadow-2xl transition-all duration-700 ${active ? 'ring-4 ring-red-500/20 scale-105' : ''}`}>
                <video ref={videoRef} className={`w-full h-full object-cover transition-opacity duration-500 ${streamMode !== 'none' ? 'opacity-100' : 'opacity-0'}`} />
                <canvas ref={canvasRef} className="hidden" />

                {streamMode === 'none' && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center gap-6">
                     <div className={`w-24 h-24 rounded-full flex items-center justify-center transition-all duration-1000 ${active ? 'bg-red-500/10 shadow-[0_0_80px_rgba(239,68,68,0.3)]' : 'bg-zinc-950'}`}>
                        <Radio size={48} className={active ? 'text-red-500 animate-pulse' : 'text-zinc-800'} />
                     </div>
                     <div className="text-center space-y-1">
                        <p className="text-sm font-black text-white uppercase tracking-widest">Neural Sensory Field</p>
                        <p className="text-[10px] font-bold text-zinc-600 uppercase">Awaiting Visual Uplink</p>
                     </div>
                  </div>
                )}

                {active && (
                   <div className="absolute top-6 left-6 bg-red-600 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] shadow-lg animate-pulse flex items-center gap-2">
                      <div className="w-1.5 h-1.5 rounded-full bg-white"></div> Live Analysis
                   </div>
                )}
             </div>

             {/* Decorative UI elements */}
             <div className="absolute -bottom-6 -right-6 w-32 h-32 bg-zinc-900 border border-zinc-800 rounded-3xl p-4 flex flex-col justify-between shadow-2xl">
                <div className="flex justify-between items-start">
                   <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
                   <Volume2 size={14} className="text-zinc-700" />
                </div>
                <div className="space-y-1">
                   <div className="h-1 bg-zinc-800 rounded-full w-full overflow-hidden">
                      <div className="h-full bg-blue-500 w-[60%] animate-pulse"></div>
                   </div>
                   <div className="h-1 bg-zinc-800 rounded-full w-[80%] overflow-hidden">
                      <div className="h-full bg-blue-500 w-[40%] animate-pulse delay-75"></div>
                   </div>
                   <p className="text-[8px] font-black text-zinc-600 uppercase mt-1">Audio Sync</p>
                </div>
             </div>
          </div>

       </div>
    </div>
  );
};

