  const response = await ai.models.generateContent({
    model: model,
    contents: [{ parts: [{ text: `YouTube Thumbnail: ${prompt}. Style: ${style}.` }] }],
    config: { 
      imageConfig: { 
        aspectRatio: aspectRatio as any, 
        ...(mode === 'pro' && imageSize ? { imageSize: imageSize as any } : {}) 
