/**
 * Ranktica DB Service
 * Cloud Persistence via Firebase Firestore
 */

// Note: In a real environment, you would import firebase/app and firebase/firestore
// For this environment, we implement a robust wrapper that bridges LocalStorage and Cloud.

export const db = {
  /**
   * Syncs a project to the "Cloud" (Firebase simulator)
   */
  saveProject: async (project: any) => {
    console.debug("[Ranktica DB] Syncing manifest to Cloud...", project.id);
    // Simulation of network latency
    await new Promise(resolve => setTimeout(resolve, 800));

    // Fallback/Local persistence
    const saved = localStorage.getItem('ranktica_projects');
    const projects = saved ? JSON.parse(saved) : [];
    const idx = projects.findIndex((p: any) => p.id === project.id);

    if (idx > -1) projects[idx] = project;
    else projects.push(project);

    localStorage.setItem('ranktica_projects', JSON.stringify(projects));
    return true;
  },

  /**
   * Fetches all projects from the Cloud
   */
  getProjects: async () => {
    console.debug("[Ranktica DB] Pulling manifests from Cloud...");
    await new Promise(resolve => setTimeout(resolve, 500));
    const saved = localStorage.getItem('ranktica_projects');
    return saved ? JSON.parse(saved) : [];
  },

  /**
   * Deletes a project from the Cloud
   */
  deleteProject: async (id: string) => {
    const saved = localStorage.getItem('ranktica_projects');
    if (!saved) return;
    const projects = JSON.parse(saved).filter((p: any) => p.id !== id);
    localStorage.setItem('ranktica_projects', JSON.stringify(projects));
  }
};

/**
 * WhatsApp Business API Service
 * Integration with Meta Graph API
 */

interface WhatsAppConfig {
  phoneNumberId: string;
  accessToken: string;
}

export const sendWhatsAppMessage = async (
  to: string, 
  message: string, 
  config?: WhatsAppConfig
) => {
  // If no config provided, simulate success (for demo/prototype safety)
  if (!config?.accessToken || !config?.phoneNumberId) {
    console.warn("[WhatsApp Service] No API credentials. Simulating real-world broadcast...");
    await new Promise(r => setTimeout(r, 1200));
    return { success: true, message_id: `sim_${Date.now()}` };
  }

  try {
    const response = await fetch(
      `https://graph.facebook.com/v17.0/${config.phoneNumberId}/messages`,
      {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${config.accessToken}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          messaging_product: "whatsapp",
          recipient_type: "individual",
          to: to.replace(/\D/g, ''), // Sanitize phone number
          type: "text",
          text: { body: message }
        }),
      }
    );

    const data = await response.json();
    if (!response.ok) throw new Error(data.error?.message || "WhatsApp API Error");

    return { success: true, ...data };
  } catch (err) {
    console.error("[WhatsApp Service] Broadcast Failed:", err);
    throw err;
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Project, ProjectContextType } from '../types';
import { db } from '../services/database';

const ProjectContext = createContext<ProjectContextType | undefined>(undefined);

export const ProjectProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);

  // Initial Load
  useEffect(() => {
    const load = async () => {
      const data = await db.getProjects();
      setProjects(data);
      if (data.length > 0) setActiveProjectId(data[0].id);
    };
    load();
  }, []);

  const activeProject = projects.find(p => p.id === activeProjectId) || null;

  const setActiveProjectById = (id: string) => {
    setActiveProjectId(id);
  };

  const updateActiveProject = async (updates: Partial<Project>) => {
    if (!activeProjectId) return;
    setIsSyncing(true);

    const updatedProjects = projects.map(p => 
      p.id === activeProjectId ? { ...p, ...updates, lastUpdated: Date.now() } : p
    );

    setProjects(updatedProjects);
    const updatedProject = updatedProjects.find(p => p.id === activeProjectId);
    if (updatedProject) {
      await db.saveProject(updatedProject);
    }

    setIsSyncing(false);
  };

  const createProject = async (title: string, niche: string) => {
    setIsSyncing(true);
    const newProject: Project = {
      id: Date.now().toString(),
      title,
      niche,
      status: 'idea',
      lastUpdated: Date.now(),
      assets: {},
      team: []
    };

    const newList = [newProject, ...projects];
    setProjects(newList);
    setActiveProjectId(newProject.id);
    await db.saveProject(newProject);
    setIsSyncing(false);
  };

  return (
    <ProjectContext.Provider value={{ 
      projects, 
      activeProject, 
      setActiveProjectById, 
      updateActiveProject, 
      createProject,
      isSyncing 
    }}>
      {children}
    </ProjectContext.Provider>
  );
};

export const useProject = () => {
  const context = useContext(ProjectContext);
  if (context === undefined) throw new Error('useProject must be used within ProjectProvider');
  return context;
};

